-- Schema for Domain: safety | Business: Clinical Trials | Version: v1_mvm
-- Generated on: 2026-05-07 02:33:32

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `clinical_trials_ecm`.`safety` COMMENT 'Manages adverse events (AE), serious adverse events (SAE), suspected unexpected serious adverse reactions (SUSAR), and safety signal detection. Owns MedDRA coding (SOC/PT/LLT), CTCAE severity grading, causality assessments, expedited regulatory reporting timelines, and DSMB/DMC safety reviews processed through Oracle Argus Safety.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`adverse_event` (
    `adverse_event_id` BIGINT COMMENT 'Unique surrogate identifier for each adverse event record in the lakehouse Silver layer. Serves as the primary key for the adverse_event data product and is the SSOT reference for all AE occurrences across studies and subjects.',
    `arm_id` BIGINT COMMENT 'Foreign key linking to study.arm. Business justification: AEs must be attributed to the treatment arm for SDTM ADAE dataset generation, blinded/unblinded safety reporting, and dose-response analysis. A clinical-research expert expects every AE record to iden',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: EU trials require AEs to be reported under the CTA. The CTA governs safety reporting obligations in EU member states. A clinical research expert expects every AE to reference the governing CTA for EU ',
    `ctcae_grade_id` BIGINT COMMENT 'Foreign key linking to safety.ctcae_grade. Business justification: adverse_event stores ctcae_grade as an INT (the grade number). Adding ctcae_grade_id FK to the ctcae_grade reference table establishes referential integrity and enables navigation to the full CTCAE gr',
    `dosing_regimen_id` BIGINT COMMENT 'Foreign key linking to study.dosing_regimen. Business justification: The dosing regimen active at AE onset is essential for dose-response analysis and causality assessment. Pharmacovigilance teams and DSMB require AE-to-regimen linkage to evaluate whether dose level, f',
    `ecrf_form_id` BIGINT COMMENT 'Foreign key linking to data.ecrf_form. Business justification: Source data verification (SDV) and ALCOA audit trail require tracing each adverse event back to the specific eCRF AE form it was collected on. Regulatory inspectors expect this traceability link betwe',
    `epoch_id` BIGINT COMMENT 'Foreign key linking to study.epoch. Business justification: AEs are classified by study epoch (treatment vs. follow-up) for SDTM mapping and safety analysis. Regulatory submissions require epoch-level AE breakdowns; epoch context determines whether an AE is tr',
    `imp_master_id` BIGINT COMMENT 'Foreign key linking to supply.imp_master. Business justification: Pharmacovigilance causality assessment and DSUR/PBRER generation require direct linkage from AE to the IMP product master. Regulatory submissions (ICSRs, expedited reports) must identify the exact IMP',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: AEs must be reported to the FDA under the IND. The IND number is required on expedited safety reports (7-day/15-day). A clinical research expert expects every AE to reference the governing IND for US ',
    `investigational_site_id` BIGINT COMMENT 'Reference to the investigational site where the adverse event was reported. Used for site-level safety monitoring and CRA oversight.',
    `manufacture_batch_id` BIGINT COMMENT 'Foreign key linking to supply.manufacture_batch. Business justification: GxP regulations (21 CFR 312, EMA GMP) require batch-level traceability from adverse events for product quality investigations and potential recalls. Direct FK enables immediate batch identification du',
    `meddra_term_id` BIGINT COMMENT 'Foreign key linking to safety.meddra_term. Business justification: adverse_event stores MedDRA codes (meddra_llt_code, meddra_pt_code, meddra_soc_code) as denormalized strings. Adding meddra_term_id FK to the meddra_term reference master establishes referential integ',
    `study_id` BIGINT COMMENT 'FK to study.study.study_id — Critical for study-level safety analysis — AEs must join to study for DSUR preparation, aggregate safety tables, and cross-study signal detection.',
    `subject_randomization_id` BIGINT COMMENT 'Foreign key linking to randomization.subject_randomization. Business justification: AE records require the subjects authoritative randomization record for causality assessment, ICSR narrative population, and expedited reporting obligation determination. treatment_arm on adverse_even',
    `subject_visit_data_id` BIGINT COMMENT 'Foreign key linking to data.subject_visit_data. Business justification: AEs are reported at specific subject visits. Linking adverse_event to subject_visit_data enables visit-level data completeness review, SDV tracking, and lock/freeze status checks before safety databas',
    `subject_visit_id` BIGINT COMMENT 'Foreign key linking to subject.subject_visit. Business justification: AEs are collected at specific study visits; SDTM AE domain requires AEVISIT mapping. Safety reviewers and data managers trace AE onset to the reporting visit for source data verification and visit-win',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: AE source documents (CRF pages, follow-up reports) must be filed in the eTMF per ICH E6 GCP requirements. Safety monitors and data managers need direct traceability from each AE record to its filed TM',
    `trial_subject_id` BIGINT COMMENT 'Reference to the trial subject (patient) who experienced the adverse event. Core party reference linking the AE to the enrolled participant.',
    `action_taken` STRING COMMENT 'Action taken with the investigational product in response to the adverse event, as recorded by the investigator. Drives dose modification tracking and safety signal analysis.. Valid values are `none|dose_reduced|dose_interrupted|drug_withdrawn|not_applicable|unknown`',
    `ae_status` STRING COMMENT 'Current lifecycle status of the adverse event record, reflecting whether the event is still active, has resolved, or resulted in death. Drives workflow routing in Oracle Argus Safety and expedited reporting decisions.. Valid values are `ongoing|resolved|resolved_with_sequelae|fatal|unknown`',
    `ae_term_verbatim` STRING COMMENT 'The exact verbatim text of the adverse event as reported by the investigator or subject on the eCRF, prior to MedDRA coding. Preserved for ALCOA+ compliance and audit trail integrity.',
    `argus_case_number` STRING COMMENT 'Externally-known case identifier assigned by Oracle Argus Safety upon initial AE entry. This is the business-facing identifier used in regulatory submissions, safety narratives, and cross-system reconciliation with the source system of record.',
    `awareness_date` DATE COMMENT 'The date on which the sponsor (or CRO acting on behalf of the sponsor) first became aware of the adverse event. This is the clock-start date for regulatory expedited reporting timelines per ICH E2A.',
    `causality_assessment` STRING COMMENT 'Investigators assessment of the causal relationship between the investigational product and the adverse event. Determines whether the event qualifies as a suspected adverse reaction and drives SUSAR classification and expedited reporting.. Valid values are `unrelated|unlikely|possible|probable|definite|not_assessable`',
    `concomitant_medication_related` BOOLEAN COMMENT 'Indicates whether the adverse event may be related to concomitant medications taken by the subject, as assessed by the investigator. Supports differential causality analysis and confounding factor assessment.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this adverse event record was first created in the source system (Oracle Argus Safety). Supports audit trail requirements under 21 CFR Part 11 and ICH E6(R2) ALCOA+ principles.',
    `ctcae_grade` STRING COMMENT 'Severity grade assigned per the National Cancer Institute Common Terminology Criteria for Adverse Events (CTCAE), ranging from 1 (mild) to 5 (death). The primary severity measure used in oncology and other therapeutic areas for safety reporting and DSMB/DMC reviews.',
    `dsmb_reported` BOOLEAN COMMENT 'Indicates whether this adverse event has been reported to the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) for independent safety review. Supports DSMB/DMC meeting preparation and safety oversight documentation.',
    `edc_subject_sequence_number` STRING COMMENT 'The AE sequence number assigned within the EDC system (Medidata Rave eCRF) for the subject, used to reconcile the safety database record with the source eCRF entry during SDV and data review.',
    `is_current_version` BOOLEAN COMMENT 'Indicates whether this record is the most current version of the adverse event. Used to filter the latest state of each AE without requiring a MAX(version_number) query, supporting efficient reporting and analytics.',
    `is_expected` BOOLEAN COMMENT 'Indicates whether the adverse event is listed in the current Investigators Brochure (IB) or product labeling as an expected/anticipated reaction. Unexpected serious adverse reactions trigger SUSAR reporting obligations.',
    `is_serious` BOOLEAN COMMENT 'Indicates whether the adverse event meets the regulatory definition of a Serious Adverse Event (SAE) per ICH E2A criteria (death, life-threatening, hospitalization, disability, congenital anomaly, or other medically important condition). Triggers expedited regulatory reporting obligations.',
    `is_susar` BOOLEAN COMMENT 'Indicates whether this adverse event has been classified as a Suspected Unexpected Serious Adverse Reaction (SUSAR), requiring expedited regulatory reporting to health authorities (FDA, EMA, MHRA, etc.) within defined timelines (7 or 15 calendar days).',
    `is_teae` BOOLEAN COMMENT 'Indicates whether the adverse event is treatment-emergent, defined as an event that first occurred or worsened in severity after the first dose of investigational product. Used in TEAE incidence tables in the CSR and SAP-defined safety analyses.',
    `meddra_llt_code` STRING COMMENT 'MedDRA Lowest Level Term (LLT) numeric code assigned during medical coding, representing the most granular level of the MedDRA hierarchy closest to the verbatim term.',
    `meddra_llt_name` STRING COMMENT 'MedDRA Lowest Level Term (LLT) text description corresponding to the LLT code. Used in safety listings, narratives, and regulatory submissions.',
    `meddra_pt_code` STRING COMMENT 'MedDRA Preferred Term (PT) numeric code, the primary level used for regulatory reporting, signal detection, and aggregate safety analysis.',
    `meddra_pt_name` STRING COMMENT 'MedDRA Preferred Term (PT) text description. The standardized medical term used in all regulatory submissions, DSMB/DMC reports, and safety narratives.',
    `meddra_soc_code` STRING COMMENT 'MedDRA System Organ Class (SOC) numeric code representing the highest level of the MedDRA hierarchy. Used for aggregate safety tabulations by body system in CSRs and regulatory submissions.',
    `meddra_soc_name` STRING COMMENT 'MedDRA System Organ Class (SOC) text description. Used in safety tabulations, listings, and figures in the Clinical Study Report (CSR).',
    `meddra_version` STRING COMMENT 'Version of the MedDRA dictionary used for coding this adverse event (e.g., 26.0). Required for regulatory submissions to ensure reproducibility of coded terms across dictionary versions.',
    `medical_history_related` BOOLEAN COMMENT 'Indicates whether the adverse event is considered related to or a continuation of a pre-existing medical history condition, as assessed by the investigator. Supports pre-existing condition confounding analysis.',
    `narrative` STRING COMMENT 'Free-text medical narrative describing the clinical course of the adverse event, including relevant medical history, treatment, and outcome. Required for SAE/SUSAR regulatory submissions and DSMB/DMC safety reviews.',
    `onset_date` DATE COMMENT 'The date on which the adverse event first began, as reported by the investigator. This is the principal real-world event date used for duration calculations, expedited reporting timelines, and TEAE determination.',
    `outcome` STRING COMMENT 'Final or current outcome of the adverse event as assessed by the investigator. Used in safety listings, aggregate safety tables, and regulatory submissions.. Valid values are `recovered|recovering|not_recovered|recovered_with_sequelae|fatal|unknown`',
    `regulatory_report_due_date` DATE COMMENT 'The deadline by which an expedited safety report (e.g., SUSAR, IND Safety Report) must be submitted to the relevant health authority. Calculated from the date of first awareness per ICH E2A timelines (7-day for fatal/life-threatening, 15-day for other SUSARs).',
    `regulatory_report_submitted_date` DATE COMMENT 'The actual date on which the expedited safety report was submitted to the health authority. Used to calculate compliance with regulatory reporting timelines and track submission performance KPIs.',
    `report_type` STRING COMMENT 'Indicates whether this record represents the initial AE report, a follow-up update with new clinical information, or the final report upon event resolution. Supports version history tracking as the clinical picture evolves.. Valid values are `initial|follow_up|final`',
    `resolution_date` DATE COMMENT 'The date on which the adverse event resolved or returned to baseline. Null if the event is ongoing. Used to calculate AE duration and determine outcome status.',
    `seriousness_criteria` STRING COMMENT 'Specific ICH E2A seriousness criterion or criteria met by this SAE (e.g., death, life-threatening, hospitalization required, persistent disability, congenital anomaly, medically significant). Multiple criteria may apply. [ENUM-REF-CANDIDATE: death|life_threatening|hospitalization|prolonged_hospitalization|disability|congenital_anomaly|medically_significant — promote to reference product]',
    `severity` STRING COMMENT 'Descriptive severity classification of the adverse event as assessed by the investigator (mild, moderate, severe, life-threatening, fatal). Distinct from CTCAE grade; used in non-oncology studies and as a complementary severity descriptor per ICH E2A.. Valid values are `mild|moderate|severe|life_threatening|fatal`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this adverse event record was sourced (Oracle Argus Safety, Medidata Rave EDC, Oracle Clinical One, or manual entry). Supports data lineage, reconciliation, and audit trail requirements.. Valid values are `argus_safety|medidata_rave|oracle_clinical_one|manual`',
    `study_day_onset` STRING COMMENT 'The study day (relative to first dose date) on which the adverse event began. Calculated per CDISC convention (Day 1 = first dose date). Used in time-to-event analyses and safety exposure-adjusted incidence calculations.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this adverse event record was most recently modified in the source system. Supports change tracking, audit trail compliance, and incremental data loading in the Databricks Silver layer.',
    `version_number` STRING COMMENT 'Sequential version number of this AE record, incremented with each follow-up update. Version 1 is the initial report; subsequent versions capture evolving clinical information. Enables temporal evolution tracking across the AE lifecycle.',
    CONSTRAINT pk_adverse_event PRIMARY KEY(`adverse_event_id`)
) COMMENT 'Core master record for every adverse event (AE) reported during a clinical trial, capturing onset date, resolution date, severity grade per CTCAE, seriousness flag, expectedness, relationship to investigational product, action taken, outcome, and follow-up version history. Each AE may progress through multiple follow-up updates as clinical picture evolves, with version tracking for each update. Sourced from Oracle Argus Safety and EDC (Medidata Rave). This is the SSOT for all AE occurrences and their temporal evolution across studies and subjects.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`serious_adverse_event` (
    `serious_adverse_event_id` BIGINT COMMENT 'Unique surrogate identifier for the Serious Adverse Event record in the Databricks Silver Layer. Primary key for this transactional entity. Role: TRANSACTION_HEADER.',
    `adverse_event_id` BIGINT COMMENT 'Reference to the parent Adverse Event (AE) record from which this SAE was escalated. Every SAE must be linked to a parent AE record in the safety domain.',
    `arm_id` BIGINT COMMENT 'Foreign key linking to study.arm. Business justification: SAE regulatory submissions (IND safety reports, EudraVigilance) require arm-level SAE breakdowns. Unblinded SAE analysis for DSMB and sponsor safety reviews depends on identifying the treatment arm fo',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: EU SAEs are reported under the CTA framework. The CTA defines the reporting clock and authority for SAE notifications in EU member states. A clinical research expert expects SAEs to reference the gove',
    `ctcae_grade_id` BIGINT COMMENT 'Foreign key linking to safety.ctcae_grade. Business justification: serious_adverse_event stores ctcae_grade as an INT. Adding ctcae_grade_id FK to the ctcae_grade reference table establishes referential integrity and enables navigation to the full CTCAE grade definit',
    `discrepancy_query_id` BIGINT COMMENT 'Foreign key linking to data.discrepancy_query. Business justification: SAE eCRF fields frequently generate data queries (missing onset date, conflicting causality). Data management teams raise and track discrepancy queries directly against SAE records; this link supports',
    `dispensing_record_id` BIGINT COMMENT 'Foreign key linking to supply.dispensing_record. Business justification: SAE case processing requires documenting the specific dispensing event (dose, date, kit number, compliance) as part of the case file for regulatory submissions and medical review. serious_adverse_even',
    `ecrf_form_id` BIGINT COMMENT 'Foreign key linking to data.ecrf_form. Business justification: SAE reconciliation between the safety database and EDC requires identifying the specific eCRF SAE form. Regulatory inspections (FDA 21 CFR Part 312, ICH E6 GCP) require traceability from SAE reports b',
    `enrollment_id` BIGINT COMMENT 'Foreign key linking to subject.enrollment. Business justification: SAE regulatory reporting and causality assessment require the subjects enrollment record to confirm study arm, protocol version, and IMP exposure at SAE onset. Standard pharmacovigilance and SDTM BDS',
    `epoch_id` BIGINT COMMENT 'Foreign key linking to study.epoch. Business justification: SAEs occurring during treatment vs. follow-up epochs have different regulatory implications and reporting timelines. Epoch-level SAE classification is required for DSUR periodic safety reports and DSM',
    `imp_master_id` BIGINT COMMENT 'Foreign key linking to supply.imp_master. Business justification: SAE expedited reporting to health authorities (FDA, EMA) requires precise IMP identification including formulation and strength. Direct FK to imp_master supports automated ICSR generation and regulato',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: SAEs are reported to the FDA under the IND via expedited safety reports. The IND number is mandatory on all SAE submissions. A clinical research expert expects SAEs to directly reference the governing',
    `investigational_site_id` BIGINT COMMENT 'Reference to the investigational site where the SAE was reported. Used for site-level safety monitoring and CRA follow-up.',
    `irb_iec_approval_id` BIGINT COMMENT 'Foreign key linking to site.irb_iec_approval. Business justification: SAEs require IRB/IEC notification per ICH E6(R2) 4.11.1. The SAE record must reference the specific irb_iec_approval active at time of event to document which approval was notified and to drive notifi',
    `lab_result_id` BIGINT COMMENT 'Foreign key linking to laboratory.lab_result. Business justification: SAE causality assessment and ICH E2A narrative authoring requires the specific precipitating lab result (e.g., ALT >10x ULN confirming hepatotoxicity). Regulatory SAE narratives must reference the con',
    `manufacture_batch_id` BIGINT COMMENT 'Foreign key linking to supply.manufacture_batch. Business justification: SAE regulatory submissions (EudraVigilance, MedWatch) require batch/lot number of the suspect product. GVP Module VI mandates batch traceability for SAE case processing. serious_adverse_event has imp_',
    `meddra_term_id` BIGINT COMMENT 'Foreign key linking to safety.meddra_term. Business justification: serious_adverse_event stores MedDRA codes (meddra_soc_code, meddra_pt_code, meddra_llt_code) as strings. Adding meddra_term_id FK normalizes the reference to the authoritative MedDRA dictionary. Exist',
    `principal_investigator_id` BIGINT COMMENT 'Foreign key linking to site.principal_investigator. Business justification: SAE reports require PI causality assessment and PI signature per ICH E6 and 21 CFR 312.32. The PI is the reporting investigator of record for each SAE. serious_adverse_event has no direct PI FK; PI-le',
    `protocol_id` BIGINT COMMENT 'Foreign key linking to study.protocol. Business justification: SAE reporting obligations are protocol-version-specific — the protocol in effect at SAE onset determines expectedness assessments and reporting timelines per ICH E2A. Regulatory binders require SAE re',
    `study_id` BIGINT COMMENT 'Reference to the clinical study (protocol) under which the SAE occurred. Used for regulatory reporting and safety signal aggregation across the study.',
    `study_site_id` BIGINT COMMENT 'Foreign key linking to site.study_site. Business justification: SAE aggregate reporting and site risk tiering require linking SAEs to the study_site record, which holds per-protocol SAE counts, monitoring visit data, and risk tier. CRAs use this join during monito',
    `subject_randomization_id` BIGINT COMMENT 'Foreign key linking to randomization.subject_randomization. Business justification: SAE regulatory submissions (CIOMS I, MedWatch) require the subjects treatment arm from the authoritative randomization record. treatment_arm on serious_adverse_event is denormalized from subject_rand',
    `subject_visit_data_id` BIGINT COMMENT 'Foreign key linking to data.subject_visit_data. Business justification: SAEs are captured during subject visits; safety reviewers and data managers must trace each SAE back to the exact eCRF visit data record for source data verification and regulatory inspection. No exis',
    `subject_visit_id` BIGINT COMMENT 'Foreign key linking to subject.subject_visit. Business justification: SAEs must be traceable to the visit at which they were identified or reported for source data verification, SDTM AE domain mapping (VISITNUM), and regulatory inspection readiness. adverse_event alread',
    `susar_id` BIGINT COMMENT 'Foreign key linking to safety.susar. Business justification: When an SAE meets the criteria for unexpectedness and causality, it is escalated to a SUSAR. The serious_adverse_event record needs a direct FK to the resulting susar record to track this escalation. ',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: SAE source documents are essential TMF artifacts per ICH E6 and FDA 21 CFR 312. The existing source_document_reference is a denormalized text field; a proper FK to tmf_document enables inspection-read',
    `trial_subject_id` BIGINT COMMENT 'Reference to the study subject (patient/participant) who experienced the SAE. Serves as the PARTY_REFERENCE for this transaction header per canonical attribute rules.',
    `action_taken` STRING COMMENT 'The action taken with the investigational product in response to the SAE (e.g., dose reduced, drug withdrawn, dose interrupted). This is a key regulatory field in ICSR submissions and clinical study reports.. Valid values are `dose_reduced|drug_withdrawn|dose_interrupted|not_applicable|unknown`',
    `argus_case_number` STRING COMMENT 'Externally-known unique case identifier assigned by Oracle Argus Safety upon SAE intake. This is the BUSINESS_IDENTIFIER used for cross-system traceability, regulatory submissions, and sponsor communications.',
    `blinding_status` STRING COMMENT 'Indicates whether the SAE case is currently blinded (treatment assignment unknown) or unblinded (treatment assignment revealed for safety reporting purposes). Unblinding may be required for SUSAR reporting to regulatory authorities.. Valid values are `blinded|unblinded|not_applicable`',
    `causality_assessment` STRING COMMENT 'The investigators assessment of the causal relationship between the investigational product and the SAE. This is a critical regulatory field used to determine whether the event qualifies as a Suspected Unexpected Serious Adverse Reaction (SUSAR).. Valid values are `related|not_related|possibly_related|probably_related|unknown`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when the SAE record was first created in Oracle Argus Safety. Serves as the RECORD_AUDIT_CREATED field per canonical transaction header requirements. Conforms to 21 CFR Part 11 audit trail requirements.',
    `ctcae_grade` STRING COMMENT 'The CTCAE severity grade assigned to the SAE, ranging from 1 (mild) to 5 (death). Grade 3 = severe, Grade 4 = life-threatening, Grade 5 = death. Used for oncology and other therapeutic area safety assessments.',
    `dsmb_reported` BOOLEAN COMMENT 'Indicates whether this SAE was reported to the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) for independent safety review. Required for studies with an active DSMB/DMC charter.',
    `expectedness` STRING COMMENT 'Indicates whether the SAE is expected (listed in the Investigators Brochure or product labeling) or unexpected (not listed or differing in nature/severity). Unexpected + serious + related = SUSAR, triggering expedited regulatory reporting.. Valid values are `expected|unexpected|unknown`',
    `follow_up_number` STRING COMMENT 'Sequential number indicating which follow-up report this record represents (0 = initial report, 1 = first follow-up, 2 = second follow-up, etc.). Used to track the evolution of the SAE case over time as new information becomes available.',
    `initial_report_date` DATE COMMENT 'The date on which the SAE was first reported to the sponsor or CRO by the investigational site. This is Day 0 for calculating regulatory reporting timelines (e.g., 7-day or 15-day expedited reporting clock).',
    `irb_iec_notification_date` DATE COMMENT 'The date on which the Institutional Review Board (IRB) or Independent Ethics Committee (IEC) was notified of the SAE. Required under GCP and local regulations to ensure ongoing ethical oversight of the study.',
    `is_susar` BOOLEAN COMMENT 'Indicates whether this SAE has been classified as a Suspected Unexpected Serious Adverse Reaction (SUSAR), requiring expedited regulatory reporting to health authorities (e.g., FDA 7/15-day reporting, EMA reporting). Derived from causality, expectedness, and seriousness criteria but stored as a business flag.',
    `meddra_llt_code` STRING COMMENT 'The MedDRA Lowest Level Term (LLT) code that most closely matches the verbatim SAE term. The LLT is the most granular level of MedDRA coding and is used to preserve the original reported term in a coded format.',
    `meddra_pt_code` STRING COMMENT 'The MedDRA Preferred Term (PT) code assigned to the SAE. The PT is the primary level of MedDRA used for regulatory reporting and is the standard coded term submitted in ICSRs and clinical study reports.',
    `meddra_soc_code` STRING COMMENT 'The MedDRA System Organ Class (SOC) code assigned to the SAE during medical coding. Represents the highest level of the MedDRA hierarchy, used for regulatory submissions and safety signal detection.',
    `meddra_version` STRING COMMENT 'The version of the MedDRA dictionary used to code this SAE (e.g., 26.0, 26.1). Required for regulatory submissions to ensure reproducibility of coding and compliance with current dictionary standards.. Valid values are `^d{2}.d{1}$`',
    `narrative` STRING COMMENT 'The full medical narrative describing the SAE, including clinical course, relevant medical history, concomitant medications, investigational product details, and the investigators assessment. This is the primary free-text field in the Argus Safety case and is included in regulatory submissions.',
    `onset_date` DATE COMMENT 'The date on which the serious adverse event first began or was first observed by the subject or investigator. This is the principal BUSINESS_EVENT_TIMESTAMP (date precision) for the SAE transaction.',
    `outcome` STRING COMMENT 'The clinical outcome of the serious adverse event at the time of the most recent report. recovered_with_sequelae indicates the subject recovered but with lasting effects. fatal must align with seriousness_death = true.. Valid values are `recovered|recovering|not_recovered|recovered_with_sequelae|fatal|unknown`',
    `regulatory_report_due_date` DATE COMMENT 'The calculated deadline by which the expedited regulatory report (e.g., IND Safety Report, SUSAR notification) must be submitted to the relevant health authority. Typically 7 calendar days for fatal/life-threatening SUSARs and 15 calendar days for other SUSARs.',
    `report_type` STRING COMMENT 'Classifies the type of safety report generated for this SAE. expedited = 7/15-day SUSAR or IND safety report; periodic = included in DSUR/PSUR; spontaneous = post-marketing spontaneous report; literature = identified from published literature.. Valid values are `expedited|periodic|spontaneous|literature`',
    `reporting_authority` STRING COMMENT 'The health authority or regulatory body to which the SAE/SUSAR report was submitted (e.g., FDA, EMA, MHRA, PMDA, TGA, Health Canada). May contain multiple authorities if reported to more than one. [ENUM-REF-CANDIDATE: FDA|EMA|MHRA|PMDA|TGA|Health Canada|ANVISA|CDSCO — promote to reference product]',
    `resolution_date` DATE COMMENT 'The date on which the serious adverse event resolved, stabilized, or the subject died. Null if the event is ongoing at the time of reporting.',
    `sae_status` STRING COMMENT 'Current lifecycle status of the SAE case in Oracle Argus Safety. initial = first report received; follow_up = additional information received; closed = case fully resolved and closed; nullified = case determined not to meet SAE criteria and voided.. Valid values are `initial|follow_up|closed|nullified`',
    `sae_term` STRING COMMENT 'The verbatim (as-reported) description of the serious adverse event as recorded by the investigator or site staff in the source document or eCRF. This is the raw, uncoded term prior to MedDRA coding.',
    `seriousness_congenital_anomaly` BOOLEAN COMMENT 'Indicates whether the SAE meets the regulatory seriousness criterion of resulting in a congenital anomaly or birth defect in the offspring of the subject.',
    `seriousness_death` BOOLEAN COMMENT 'Indicates whether the SAE meets the regulatory seriousness criterion of resulting in death of the subject. One of the six ICH E2A seriousness criteria that must be captured individually.',
    `seriousness_disability` BOOLEAN COMMENT 'Indicates whether the SAE meets the regulatory seriousness criterion of resulting in persistent or significant disability or incapacity.',
    `seriousness_hospitalization` BOOLEAN COMMENT 'Indicates whether the SAE meets the regulatory seriousness criterion of requiring inpatient hospitalization or prolongation of existing hospitalization.',
    `seriousness_life_threatening` BOOLEAN COMMENT 'Indicates whether the SAE meets the regulatory seriousness criterion of being immediately life-threatening (i.e., the subject was at immediate risk of death at the time of the event).',
    `seriousness_medically_important` BOOLEAN COMMENT 'Indicates whether the SAE meets the regulatory seriousness criterion of being an other medically important condition — events that may not be immediately life-threatening but may jeopardize the subject or require intervention to prevent one of the other serious outcomes.',
    `sponsor_receipt_date` DATE COMMENT 'The date on which the sponsor (or CRO acting on behalf of the sponsor) received the complete minimum information required to process the SAE. This date starts the regulatory reporting clock per ICH E2A.',
    `subject_number` STRING COMMENT 'The protocol-assigned subject identifier (e.g., site-subject number) for the patient who experienced the SAE. Restricted as it can be used to identify an individual participant in combination with study data.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when the SAE record was most recently modified in Oracle Argus Safety. Serves as the RECORD_AUDIT_UPDATED field per canonical transaction header requirements. Required for 21 CFR Part 11 audit trail compliance.',
    CONSTRAINT pk_serious_adverse_event PRIMARY KEY(`serious_adverse_event_id`)
) COMMENT 'Transactional record for Serious Adverse Events (SAEs) that meet regulatory seriousness criteria (death, life-threatening, hospitalization, disability, congenital anomaly, or other medically important condition). Captures SAE narrative, seriousness criteria met, initial and follow-up report dates, blinded/unblinded status, and regulatory reporting obligations. Linked to the parent adverse_event record. Sourced from Oracle Argus Safety.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`susar` (
    `susar_id` BIGINT COMMENT 'Unique surrogate identifier for the SUSAR record in the Databricks Silver Layer. Primary key for this transactional entity. Entity role: TRANSACTION_HEADER — a discrete regulatory safety event with a defined lifecycle, expedited reporting obligations, and submission tracking.',
    `adverse_event_id` BIGINT COMMENT 'Foreign key linking to safety.adverse_event. Business justification: A SUSAR is a specific type of adverse event that is both serious and unexpected. Every SUSAR originates from an underlying adverse event record. Adding adverse_event_id to susar establishes the direct',
    `arm_id` BIGINT COMMENT 'Foreign key linking to study.arm. Business justification: SUSARs require treatment arm identification for unblinding procedures and regulatory reporting. Health authority submissions (EudraVigilance, FDA) for SUSARs must specify the implicated treatment arm ',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: SUSARs in EU trials are reported under specific CTAs to EMA/national competent authorities per EU Clinical Trials Regulation. Linking susar to clinical_trial_authorization replaces the denormalized eu',
    `ctcae_grade_id` BIGINT COMMENT 'Foreign key linking to safety.ctcae_grade. Business justification: susar stores ctcae_grade as an INT. Adding ctcae_grade_id FK to the ctcae_grade reference table establishes referential integrity and enables navigation to the full CTCAE grade definition. The ctcae_g',
    `dispensing_record_id` BIGINT COMMENT 'Foreign key linking to supply.dispensing_record. Business justification: SUSAR case narratives and E2B(R3) submissions require complete product exposure documentation including dispensing date, dose, and kit number. susar links to imp_master and subject_randomization but n',
    `ecrf_form_id` BIGINT COMMENT 'Foreign key linking to data.ecrf_form. Business justification: SUSARs are sourced from eCRF form data. EMA and FDA regulations require traceability from the SUSAR back to the source eCRF form; pharmacovigilance teams use this link during 7/15-day expedited report',
    `enrollment_id` BIGINT COMMENT 'Foreign key linking to subject.enrollment. Business justification: SUSAR regulatory submissions to health authorities require enrollment context to confirm IMP identity, arm assignment, and protocol version. EudraVigilance and FDA expedited reporting workflows depend',
    `imp_master_id` BIGINT COMMENT 'Foreign key linking to supply.imp_master. Business justification: SUSAR regulatory reporting (7/15-day clock) to health authorities requires authoritative IMP identification. susar.investigational_product_name is a denormalized plain column; FK to imp_master enables',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: SUSARs in US trials are reported to the FDA under the IND within 7 or 15 days. The IND governs the SUSAR reporting obligation. A clinical research expert expects SUSARs to reference the governing IND.',
    `investigational_site_id` BIGINT COMMENT 'Reference to the investigational site where the SUSAR occurred. Used for site-level safety monitoring, regulatory notifications, and investigator communications.',
    `irb_iec_approval_id` BIGINT COMMENT 'Foreign key linking to site.irb_iec_approval. Business justification: When a SUSAR is identified, the sponsor must notify the specific IRB/IEC approval under which subjects are enrolled per ICH E6(R2) 4.11 and 21 CFR 312.32. susar has irb_iec_notified and irb_iec_notifi',
    `lab_result_id` BIGINT COMMENT 'Foreign key linking to laboratory.lab_result. Business justification: SUSAR 7/15-day expedited reporting clock requires documentation of the precipitating lab finding that confirmed unexpectedness and seriousness. EudraVigilance and FDA submissions must reference the sp',
    `manufacture_batch_id` BIGINT COMMENT 'Foreign key linking to supply.manufacture_batch. Business justification: SUSARs require 7/15-day expedited reporting to health authorities with mandatory batch/lot identification per ICH E2B(R3) and EudraVigilance requirements. Batch traceability determines whether a SUSAR',
    `meddra_term_id` BIGINT COMMENT 'Foreign key linking to safety.meddra_term. Business justification: susar stores MedDRA codes (meddra_soc_code, meddra_pt_code, meddra_llt_code) as strings. Adding meddra_term_id FK normalizes the reference to the authoritative MedDRA dictionary. Existing code columns',
    `protocol_id` BIGINT COMMENT 'Foreign key linking to study.protocol. Business justification: SUSAR expectedness is assessed against the Reference Safety Information in the protocol/IB. The protocol version at time of SUSAR determines whether the event was listed/expected, directly affecting t',
    `regulatory_binder_id` BIGINT COMMENT 'Foreign key linking to document.regulatory_binder. Business justification: SUSARs are expedited regulatory submissions filed in regulatory binders per EU CT Directive 2001/20/EC and ICH E2A. The susar product has tmf_document_id but no regulatory_binder_id. Direct binder tra',
    `study_id` BIGINT COMMENT 'Reference to the clinical study (protocol) under which this SUSAR occurred. Links the SUSAR to the sponsoring study for regulatory reporting and safety surveillance.',
    `study_site_id` BIGINT COMMENT 'Foreign key linking to site.study_site. Business justification: SUSARs require investigator and IRB/IEC notification at the study-site level. Linking susar to study_site drives per-site SUSAR notification workflows and enables study-site-level SUSAR aggregate repo',
    `subject_randomization_id` BIGINT COMMENT 'Foreign key linking to randomization.subject_randomization. Business justification: SUSAR causality and expectedness determination requires the subjects authoritative treatment assignment from the randomization system. treatment_assignment on susar is denormalized from subject_rando',
    `subject_visit_data_id` BIGINT COMMENT 'Foreign key linking to data.subject_visit_data. Business justification: SUSARs are compiled from subject visit eCRF data. Regulatory traceability for 7/15-day expedited reports requires linking the SUSAR to the specific visit data record from which the case was identified',
    `subject_visit_id` BIGINT COMMENT 'Foreign key linking to subject.subject_visit. Business justification: The visit at which a SUSAR-triggering event was identified is required for SDTM AE domain traceability and source document verification during regulatory inspections. Pharmacovigilance teams need visi',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: SUSARs result in expedited regulatory submissions (IND safety reports, EudraVigilance submissions). The submission record tracks the regulatory filing. A clinical research expert expects SUSARs to ref',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: SUSAR expedited reports are essential TMF documents (DIA TMF Reference Model Zone 1, Section 11). Regulatory inspectors verify that each SUSAR submission is filed in the TMF; this FK enables that trac',
    `trial_subject_id` BIGINT COMMENT 'Reference to the study subject (patient) who experienced the SUSAR. Links to the subject master record for patient-level safety surveillance and regulatory reporting.',
    `ae_term` STRING COMMENT 'Verbatim description of the adverse event as reported by the investigator or subject, prior to MedDRA coding. Preserved for source data verification (SDV) and coding audit trail per ALCOA+ principles.',
    `argus_case_reference` BIGINT COMMENT 'System-generated case identifier from Oracle Argus Safety, the operational system of record for adverse event and SUSAR management. Used to trace the SUSAR back to its source case in Argus.',
    `awareness_date` DATE COMMENT 'Date on which the sponsor (or CRO acting on behalf of the sponsor) first became aware of the SUSAR. This date starts the regulatory reporting clock for 7-day and 15-day expedited reporting obligations under ICH E2A.',
    `blind_break_date` DATE COMMENT 'Date on which the treatment blind was broken for this subject. Populated only when blind_broken is True. Required for audit trail and regulatory documentation of unblinding events.',
    `blind_broken` BOOLEAN COMMENT 'Indicates whether the treatment blind was broken for this subject in order to perform the causality assessment for this SUSAR. A blind break is a significant event requiring documentation and regulatory notification.',
    `blind_status` STRING COMMENT 'Blinding status of the study at the time of SUSAR reporting. Indicates whether the study was blinded, and if so, whether the blind was broken for this subject to determine treatment assignment for causality assessment.. Valid values are `blinded|unblinded|open_label`',
    `case_number` STRING COMMENT 'Externally-known alphanumeric case number assigned by the sponsor or CRO for this SUSAR, used in all regulatory submissions and correspondence. Serves as the BUSINESS_IDENTIFIER for this transaction.. Valid values are `^[A-Z0-9-]{5,30}$`',
    `causality_assessment` STRING COMMENT 'Investigators or sponsors assessment of the causal relationship between the investigational product and the serious adverse reaction. A SUSAR requires a positive causality assessment (related or probably/possibly related) to the investigational product.. Valid values are `related|not_related|possibly_related|probably_related|unassessable`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the SUSAR record was first created in Oracle Argus Safety. Serves as the RECORD_AUDIT_CREATED field for this transaction header, supporting ALCOA+ data integrity requirements.',
    `ctcae_grade` STRING COMMENT 'CTCAE severity grade assigned to the adverse reaction (1=Mild, 2=Moderate, 3=Severe, 4=Life-threatening, 5=Death). Used for safety signal detection, DSMB/DMC reviews, and regulatory reporting.',
    `deadline_15day` DATE COMMENT 'Calculated deadline for 15-day expedited reporting to regulatory authorities for non-fatal/non-life-threatening SUSARs. Derived from the reporting clock start date plus 15 calendar days per ICH E2A and FDA 21 CFR 312.32.',
    `deadline_7day` DATE COMMENT 'Calculated deadline for 7-day expedited reporting to regulatory authorities for fatal or life-threatening SUSARs. Derived from the reporting clock start date plus 7 calendar days per ICH E2A and FDA 21 CFR 312.32.',
    `dose_at_onset` STRING COMMENT 'Dose of the investigational product administered to the subject at the time of the adverse reaction onset, including amount and unit (e.g., 100 mg). Required for causality assessment and regulatory case narratives.',
    `dsmb_notification_date` DATE COMMENT 'Date on which the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) was notified of this SUSAR. Populated only when dsmb_notified is True.',
    `dsmb_notified` BOOLEAN COMMENT 'Indicates whether the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) was notified of this SUSAR. Required for studies with an active DSMB/DMC per ICH E6(R2) and study protocol.',
    `eudravigilance_number` STRING COMMENT 'Unique case identifier assigned by the EudraVigilance system upon submission of the SUSAR to the EMA. Used for tracking and referencing the case in EU regulatory correspondence and EudraVigilance database.',
    `expectedness_assessment` STRING COMMENT 'Assessment of whether the serious adverse reaction is unexpected — i.e., not listed or not consistent with the nature, severity, or frequency described in the current Investigators Brochure (IB). A SUSAR must be assessed as unexpected to qualify for expedited reporting.. Valid values are `unexpected|expected`',
    `fatal_date` DATE COMMENT 'Date of subject death if the outcome of the SUSAR is fatal. Triggers the 7-day expedited reporting clock and is required for death narratives in regulatory submissions.',
    `follow_up_number` STRING COMMENT 'Sequential number of the follow-up report for this SUSAR case (e.g., 1 for first follow-up, 2 for second). Zero or null for initial reports. Tracks the version history of regulatory submissions for this case.',
    `irb_iec_notification_date` DATE COMMENT 'Date on which the Institutional Review Board (IRB) or Independent Ethics Committee (IEC) was notified of this SUSAR. Populated only when irb_iec_notified is True.',
    `irb_iec_notified` BOOLEAN COMMENT 'Indicates whether the Institutional Review Board (IRB) or Independent Ethics Committee (IEC) was notified of this SUSAR as required by GCP and local regulations.',
    `meddra_llt_code` STRING COMMENT 'MedDRA Lowest Level Term (LLT) code that most closely matches the verbatim adverse event term. Used for granular coding traceability and verbatim-to-PT mapping audit.. Valid values are `^[0-9]{8}$`',
    `meddra_pt_code` STRING COMMENT 'MedDRA Preferred Term (PT) code assigned to this SUSAR. The PT is the primary level of MedDRA used for regulatory reporting, signal detection, and aggregate safety analysis in IND/NDA/BLA submissions.. Valid values are `^[0-9]{8}$`',
    `meddra_soc_code` STRING COMMENT 'MedDRA System Organ Class (SOC) code assigned to this SUSAR during medical coding. Represents the highest level of the MedDRA hierarchy and is required for regulatory submissions and aggregate safety reporting.. Valid values are `^[0-9]{8}$`',
    `meddra_version` STRING COMMENT 'Version of the MedDRA dictionary used for coding this SUSAR (e.g., 26.0, 26.1). Required for regulatory submissions to ensure reproducibility of coding and compliance with current MedDRA release requirements.. Valid values are `^[0-9]{1,2}.[0-9]{1}$`',
    `narrative` STRING COMMENT 'Medical narrative summarizing the SUSAR case, including patient demographics, event description, clinical course, causality assessment, and outcome. Required component of all expedited regulatory reports per ICH E2A.',
    `onset_date` DATE COMMENT 'Date on which the subject first experienced the serious adverse reaction. This is the principal real-world event time (BUSINESS_EVENT_TIMESTAMP) for the SUSAR and is the anchor for all regulatory reporting clocks per ICH E2A.',
    `outcome` STRING COMMENT 'Clinical outcome of the serious adverse reaction at the time of reporting. Required for regulatory submissions and DSMB/DMC safety reviews. Tracks resolution status of the event.. Valid values are `recovered|recovering|not_recovered|fatal|unknown|sequelae`',
    `reporting_clock_start_date` DATE COMMENT 'The date from which the regulatory reporting clock begins for this SUSAR. Typically the sponsor awareness date, but may be adjusted based on the date of unblinding or receipt of minimum reportable information per ICH E2A.',
    `reporting_status` STRING COMMENT 'Current lifecycle state of the SUSAR regulatory reporting workflow. Tracks progression from initial draft through submission to regulatory authority acknowledgement and case closure. Serves as the LIFECYCLE_STATUS for this transaction.. Valid values are `draft|submitted|acknowledged|closed|withdrawn`',
    `route_of_administration` STRING COMMENT 'Route by which the investigational product was administered (e.g., oral, intravenous, subcutaneous). Required for regulatory case narratives and pharmacovigilance signal assessment. [ENUM-REF-CANDIDATE: oral|intravenous|subcutaneous|intramuscular|topical|inhalation — promote to reference product]',
    `seriousness_criteria` STRING COMMENT 'ICH E2A seriousness criterion met by this adverse reaction that qualifies it as a Serious Adverse Event (SAE). [ENUM-REF-CANDIDATE: death|life_threatening|hospitalization|disability|congenital_anomaly|medically_significant — promote to reference product]',
    `submission_report_type` STRING COMMENT 'Indicates whether this SUSAR submission is an initial report, a follow-up report with additional information, or a final report closing the case. Regulatory authorities require tracking of report versions per ICH E2A.. Valid values are `initial|follow_up|final`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the SUSAR record in Oracle Argus Safety. Serves as the RECORD_AUDIT_UPDATED field for this transaction header, supporting audit trail and data integrity requirements.',
    CONSTRAINT pk_susar PRIMARY KEY(`susar_id`)
) COMMENT 'Transactional record for Suspected Unexpected Serious Adverse Reactions (SUSARs) — SAEs that are both unexpected (not in the Investigator Brochure) and causally related to the investigational product. Captures expectedness assessment, causality determination, expedited reporting clock start date, 7-day and 15-day reporting deadlines, submission status to FDA/EMA/PMDA, and blind-break details. Sourced from Oracle Argus Safety.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`ae_meddra_coding` (
    `ae_meddra_coding_id` BIGINT COMMENT 'Unique surrogate identifier for each MedDRA coding record assigned to an adverse event. Primary key for the ae_meddra_coding data product in the safety domain.',
    `adverse_event_id` BIGINT COMMENT 'Reference to the parent adverse event record for which this MedDRA coding assignment was made. Links the coding record back to the originating AE in Oracle Argus Safety.',
    `coding_assignment_id` BIGINT COMMENT 'Foreign key linking to data.coding_assignment. Business justification: MedDRA coding reconciliation process requires matching safety-side ae_meddra_coding records with EDC-side coding_assignment records. Regulatory submissions (SDTM AE domain) depend on reconciled coding',
    `ctcae_grade_id` BIGINT COMMENT 'Foreign key linking to safety.ctcae_grade. Business justification: ae_meddra_coding stores ctcae_grade (INT) and ctcae_version (STRING). Adding ctcae_grade_id FK to the ctcae_grade reference table normalizes the grade reference and enables navigation to the full CTCA',
    `discrepancy_query_id` BIGINT COMMENT 'Foreign key linking to data.discrepancy_query. Business justification: MedDRA coding discrepancies generate EDC queries that must be resolved before database lock. Linking ae_meddra_coding to discrepancy_query enables data managers to track open coding queries against sa',
    `ecrf_field_id` BIGINT COMMENT 'Foreign key linking to data.ecrf_field. Business justification: MedDRA coding traceability requires identifying which specific eCRF field contained the verbatim AE term that was coded. This supports SDTM AE domain mapping and regulatory submission audit trails whe',
    `meddra_term_id` BIGINT COMMENT 'Foreign key linking to safety.meddra_term. Business justification: ae_meddra_coding is the MedDRA coding assignment table and should reference the authoritative meddra_term reference master. Adding meddra_term_id (pointing to the PT-level term) establishes referentia',
    `study_id` BIGINT COMMENT 'Reference to the clinical study (protocol) under which the adverse event and its MedDRA coding were recorded. Supports study-level aggregate safety reporting.',
    `subject_visit_data_id` BIGINT COMMENT 'Foreign key linking to data.subject_visit_data. Business justification: AE MedDRA coding is performed on verbatim terms captured in subject visit data records. Medical coders need to trace each coding assignment back to the source visit data for coding quality review, rec',
    `subject_visit_id` BIGINT COMMENT 'Foreign key linking to subject.subject_visit. Business justification: MedDRA coding of AEs requires visit context for SDTM AE domain mapping (VISITNUM, VISIT) and for reconciliation with EDC source data at the visit level. Data managers performing coding reconciliation ',
    `trial_subject_id` BIGINT COMMENT 'Reference to the clinical trial subject (patient) who experienced the adverse event being coded. Enables subject-level safety queries and MedDRA-coded AE listings.',
    `argus_case_reference` STRING COMMENT 'The case identifier from Oracle Argus Safety that corresponds to this MedDRA coding record. Serves as the source system business key for traceability back to the originating safety case in the system of record.',
    `argus_event_reference` STRING COMMENT 'The event-level identifier from Oracle Argus Safety for the specific adverse event record within a case that this MedDRA coding applies to. Enables precise traceability to the source system event record.',
    `coded_date` DATE COMMENT 'Calendar date on which the MedDRA code was assigned to the verbatim adverse event term. Used for coding timeliness metrics and regulatory submission audit trails.',
    `coded_timestamp` TIMESTAMP COMMENT 'Precise date and time (with timezone) at which the MedDRA code was assigned. Provides granular audit trail for 21 CFR Part 11 electronic records compliance. Sourced from Oracle Argus Safety system timestamp.',
    `coding_comment` STRING COMMENT 'Free-text comment entered by the coder to document coding rationale, ambiguities, or special considerations for this MedDRA assignment. Supports coding consistency reviews and regulatory inspection readiness.',
    `coding_method` STRING COMMENT 'Indicates how the MedDRA code was assigned: auto for system-generated auto-coding by Oracle Argus Safety, manual for coder-assigned coding, auto_confirmed for auto-coded and confirmed by a coder, recoded for a previously coded term that was revised. Drives QC workflows and audit requirements.. Valid values are `auto|manual|auto_confirmed|recoded`',
    `coding_status` STRING COMMENT 'Current workflow status of the MedDRA coding assignment. pending indicates awaiting coding, coded indicates a code has been assigned, confirmed indicates QC-approved, rejected indicates coding was rejected and requires rework, under_review indicates currently in QC review. Drives coding workflow in Oracle Argus Safety.. Valid values are `pending|coded|confirmed|rejected|under_review`',
    `confirmed_date` DATE COMMENT 'Date on which the MedDRA coding assignment was confirmed (QC-approved) by a second reviewer or coding supervisor. Null if coding has not yet been confirmed. Supports dual-coder QC workflows.',
    `ctcae_grade` STRING COMMENT 'Severity grade assigned to the adverse event using the NCI Common Terminology Criteria for Adverse Events (CTCAE) scale (1=Mild, 2=Moderate, 3=Severe, 4=Life-threatening, 5=Death). Used in oncology and other therapeutic areas for standardized severity grading alongside MedDRA coding.',
    `ctcae_version` STRING COMMENT 'Version of the NCI CTCAE grading scale used for severity assessment (e.g., 5.0, 4.03). Required for regulatory submissions to ensure consistent severity grading interpretation across study sites and time periods.. Valid values are `^[0-9]+.[0-9]+$`',
    `dictionary_language` STRING COMMENT 'Three-letter ISO 639-2 language code of the MedDRA dictionary used for coding (e.g., ENG for English, JPN for Japanese). Relevant for multi-regional studies where local language MedDRA versions may be used (e.g., PMDA submissions in Japan).. Valid values are `^[A-Z]{3}$`',
    `effective_from_date` DATE COMMENT 'Date from which this MedDRA coding record version is considered effective. Used in conjunction with is_current_version and effective_to_date to implement SCD Type 2 versioning for coding history tracking.',
    `effective_to_date` DATE COMMENT 'Date until which this MedDRA coding record version is considered effective. Null for the current active record. Used with effective_from_date and is_current_version for SCD Type 2 coding history. Populated when a recoding event supersedes this record.',
    `hlgt_code` STRING COMMENT 'Eight-digit MedDRA numeric code for the High Level Group Term (HLGT), which sits between the HLT and SOC in the MedDRA hierarchy. Used for broad safety grouping in regulatory submissions.. Valid values are `^[0-9]{8}$`',
    `hlgt_name` STRING COMMENT 'Descriptive text of the MedDRA High Level Group Term (HLGT) corresponding to hlgt_code. Supports broad-level safety grouping in aggregate analyses and CSR appendices.',
    `hlt_code` STRING COMMENT 'Eight-digit MedDRA numeric code for the High Level Term (HLT) in the MedDRA hierarchy above the PT. Used for grouping related PTs in aggregate safety analyses and signal detection.. Valid values are `^[0-9]{8}$`',
    `hlt_name` STRING COMMENT 'Descriptive text of the MedDRA High Level Term (HLT) corresponding to hlt_code. Supports mid-level grouping in safety tabulations and DSMB/DMC review packages.',
    `is_current_version` BOOLEAN COMMENT 'Indicates whether this record represents the current (active) MedDRA coding assignment for the associated adverse event. Set to false for superseded coding records retained for historical audit trail. Supports slowly changing dimension (SCD Type 2) versioning in the Silver layer.',
    `is_sae` BOOLEAN COMMENT 'Indicates whether the adverse event associated with this MedDRA coding record meets the regulatory definition of a Serious Adverse Event (SAE) per ICH E2A criteria (death, life-threatening, hospitalization, disability, congenital anomaly, or other medically important condition). Drives expedited reporting timelines.',
    `is_susar` BOOLEAN COMMENT 'Indicates whether this adverse event has been classified as a Suspected Unexpected Serious Adverse Reaction (SUSAR), requiring expedited regulatory reporting (7-day or 15-day) to health authorities. Sourced from Oracle Argus Safety case classification.',
    `llt_code` STRING COMMENT 'Eight-digit MedDRA numeric code for the Lowest Level Term (LLT) assigned to the verbatim adverse event term. The LLT is the most granular level of the MedDRA hierarchy and is the primary coding target. Sourced from Oracle Argus Safety MedDRA dictionary.. Valid values are `^[0-9]{8}$`',
    `llt_name` STRING COMMENT 'Descriptive text of the MedDRA Lowest Level Term (LLT) corresponding to llt_code. Provides the human-readable label for the most granular MedDRA coding level. Sourced from Oracle Argus Safety MedDRA dictionary.',
    `meddra_version` STRING COMMENT 'Version of the MedDRA dictionary used for this coding assignment (e.g., 26.0, 26.1). Critical for regulatory submissions as coding must reference the specific MedDRA version in use at the time of the submission. Sourced from Oracle Argus Safety dictionary configuration.. Valid values are `^[0-9]{1,2}.[0-9]{1}$`',
    `previous_pt_code` STRING COMMENT 'The MedDRA PT code that was previously assigned before a recoding event. Populated only when coding_method = recoded. Enables before/after comparison for coding change impact analysis and regulatory audit.. Valid values are `^[0-9]{8}$`',
    `previous_soc_code` STRING COMMENT 'The MedDRA SOC code that was previously assigned before a recoding event. Populated only when coding_method = recoded. Enables assessment of whether a recoding changed the SOC-level classification, which may affect regulatory safety tables.. Valid values are `^[0-9]{8}$`',
    `primary_soc_flag` BOOLEAN COMMENT 'Indicates whether this SOC assignment is the primary (true) or secondary (false) SOC for the PT. MedDRA PTs may be linked to multiple SOCs; the primary SOC is used for standard regulatory safety tables. Sourced from Oracle Argus Safety.',
    `pt_code` STRING COMMENT 'Eight-digit MedDRA numeric code for the Preferred Term (PT) to which the LLT maps. The PT is the primary level used for regulatory reporting, safety queries, and signal detection. Sourced from Oracle Argus Safety.. Valid values are `^[0-9]{8}$`',
    `pt_name` STRING COMMENT 'Descriptive text of the MedDRA Preferred Term (PT) corresponding to pt_code. Used as the standard term in regulatory submissions, CIOMS forms, and safety narratives.',
    `recoding_reason` STRING COMMENT 'Free-text justification provided by the coder when a previously assigned MedDRA code is revised (coding_method = recoded). Required for audit trail integrity and regulatory inspection readiness. Null when coding_method is not recoded.',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp at which this MedDRA coding record was first created in the data lakehouse Silver layer. Supports audit trail and data lineage requirements per 21 CFR Part 11 and ALCOA+ principles.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp at which this MedDRA coding record was last modified in the data lakehouse Silver layer. Tracks the most recent update for change detection, incremental processing, and audit trail compliance.',
    `soc_code` STRING COMMENT 'Eight-digit MedDRA numeric code for the System Organ Class (SOC), the highest level of the MedDRA hierarchy. SOC is the primary axis for organizing adverse events in regulatory safety tables (e.g., Table 14.3.1 in ICH E3 CSR).. Valid values are `^[0-9]{8}$`',
    `soc_name` STRING COMMENT 'Descriptive text of the MedDRA System Organ Class (SOC) corresponding to soc_code. Used as the primary grouping header in all regulatory safety tabulations, PSUR/PBRER narratives, and DSMB reports.',
    `source_system` STRING COMMENT 'Identifies the operational system from which this MedDRA coding record was sourced. Supports data lineage tracking in the Databricks Silver layer. Typically argus_safety for records originating from Oracle Argus Safety.. Valid values are `argus_safety|medidata_rave|manual_entry`',
    `verbatim_term` STRING COMMENT 'The exact, unmodified adverse event term as reported by the investigator or subject in the source document or eCRF prior to MedDRA coding. Preserved for ALCOA+ compliance and audit trail. Sourced from Oracle Argus Safety verbatim field.',
    CONSTRAINT pk_ae_meddra_coding PRIMARY KEY(`ae_meddra_coding_id`)
) COMMENT 'Stores the MedDRA coding assignment for each adverse event, capturing the verbatim term reported, the coded Lowest Level Term (LLT), Preferred Term (PT), High Level Term (HLT), High Level Group Term (HLGT), and System Organ Class (SOC). Tracks coding version, coder identity, coding date, and auto-code vs. manual-code flag. Enables standardized MedDRA-based safety queries and regulatory submissions. Sourced from Oracle Argus Safety.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`causality_assessment` (
    `causality_assessment_id` BIGINT COMMENT 'Unique surrogate identifier for each causality assessment record in the Silver layer lakehouse. Primary key for this entity.',
    `adverse_event_id` BIGINT COMMENT 'Reference to the adverse event record for which this causality assessment is being performed. Links the assessment to the parent AE in Oracle Argus Safety.',
    `arm_id` BIGINT COMMENT 'Foreign key linking to study.arm. Business justification: Causality assessment requires knowing the treatment arm to evaluate whether the investigational product caused the AE. Unblinded causality reviews by medical monitors and DSMB are conducted at the arm',
    `dispensing_record_id` BIGINT COMMENT 'Foreign key linking to supply.dispensing_record. Business justification: Causality assessment requires authoritative dispensing data (exact dose, formulation, timing) per ICH E2A guidelines. causality_assessment.dose_at_onset and dose_unit are denormalized; FK to dispensin',
    `dosing_regimen_id` BIGINT COMMENT 'Foreign key linking to study.dosing_regimen. Business justification: Causality assessment explicitly evaluates the dosing regimen (dose level, frequency, route) as a causal factor. The dechallenge/rechallenge results and temporal relationship fields on causality_assess',
    `ecrf_form_id` BIGINT COMMENT 'Foreign key linking to data.ecrf_form. Business justification: Causality assessments are documented on specific eCRF forms (e.g., SAE causality form). Linking to the source eCRF form supports SDV, data lineage, and regulatory inspection readiness — a standard cli',
    `enrollment_id` BIGINT COMMENT 'Foreign key linking to subject.enrollment. Business justification: Causality assessments require enrollment context (arm, dosing regimen, protocol version) to evaluate drug-event temporal relationship and assess IMP relatedness. Medical monitors and pharmacovigilance',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: Causality assessments determine whether an AE requires expedited IND safety reporting. The IND governs the reporting obligation triggered by causality. A clinical research expert expects causality ass',
    `investigational_product_id` BIGINT COMMENT 'Reference to the investigational product (drug, biologic, or device) being assessed for causal relationship to the adverse event.',
    `lab_result_id` BIGINT COMMENT 'Foreign key linking to laboratory.lab_result. Business justification: Causality assessments evaluate AE-drug relationships using lab evidence (e.g., liver function tests, renal markers). Linking causality_assessment to the supporting lab_result formalizes the evidence c',
    `manufacture_batch_id` BIGINT COMMENT 'Foreign key linking to supply.manufacture_batch. Business justification: GVP Module VI causality assessment requires evaluating batch-level quality data (release status, stability, retest date) to determine if a manufacturing defect contributed to the AE. causality_assessm',
    `prior_assessment_causality_assessment_id` BIGINT COMMENT 'Self-referencing identifier pointing to the immediately preceding causality assessment record that this revision supersedes. Null for original (first) assessments. Enables full revision chain reconstruction.',
    `study_id` BIGINT COMMENT 'Reference to the clinical study protocol under which the adverse event occurred and this causality assessment was conducted.',
    `study_site_id` BIGINT COMMENT 'Reference to the investigational site where the subject was enrolled and the adverse event was reported.',
    `subject_randomization_id` BIGINT COMMENT 'Foreign key linking to randomization.subject_randomization. Business justification: Causality assessment explicitly evaluates temporal relationship between treatment and AE onset, requiring the authoritative randomization record. treatment_arm and blinding_status are denormalized fro',
    `subject_visit_data_id` BIGINT COMMENT 'Foreign key linking to data.subject_visit_data. Business justification: Causality assessments are performed in the context of a specific subject visit data record. This link enables traceability from the clinical causality judgment back to the source eCRF visit data, requ',
    `subject_visit_id` BIGINT COMMENT 'Foreign key linking to subject.subject_visit. Business justification: Causality assessments are performed at specific visits (e.g., end-of-treatment, unscheduled safety visit). DSMB data packages and medical monitor reviews require visit-level causality tracking. No exi',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: Causality assessment records are formal safety documents filed in the TMF. Regulatory inspectors (FDA, EMA) require traceability from causality determinations to their filed source documents. The exis',
    `trial_subject_id` BIGINT COMMENT 'Reference to the clinical trial subject (patient) for whom the adverse event and causality assessment applies.',
    `alternative_explanation` STRING COMMENT 'Free-text description of alternative causes considered by the assessor (e.g., concomitant medications, underlying disease, concurrent procedures). Documents the differential diagnosis reasoning supporting the causality determination.',
    `argus_case_number` STRING COMMENT 'The case number assigned by Oracle Argus Safety to the parent safety case containing this causality assessment. Enables direct traceability back to the source system for audit and regulatory purposes.',
    `argus_workflow_state` STRING COMMENT 'The workflow routing state of the causality assessment within Oracle Argus Safety at the time of data extraction (e.g., Open, Closed, Submitted, Archived). Supports reconciliation between the lakehouse Silver layer and the source system. [ENUM-REF-CANDIDATE: open|closed|submitted|archived|pending_review|locked — promote to reference product]',
    `assessment_date` DATE COMMENT 'The calendar date on which the causality assessment was performed or last confirmed by the assessor. Used to track compliance with expedited reporting timelines (e.g., 7-day/15-day clock).',
    `assessment_number` STRING COMMENT 'Externally-known business identifier for this causality assessment record, typically generated by Oracle Argus Safety (e.g., CA-2024-00123). Used for cross-system traceability and regulatory correspondence.',
    `assessment_status` STRING COMMENT 'Current workflow state of the causality assessment record within Oracle Argus Safety. Tracks progression from initial draft through regulatory submission. Superseded indicates a newer revision exists.. Valid values are `draft|submitted|confirmed|revised|superseded|withdrawn`',
    `assessor_role` STRING COMMENT 'The professional role of the individual performing the causality assessment. Distinguishes between the Principal Investigator (PI) site-level assessment and the Sponsor Medical Monitors independent assessment, as required by ICH E2A and GCP guidelines.. Valid values are `investigator|sponsor_medical_monitor|independent_reviewer|dsmb_member|regulatory_authority`',
    `causality_category` STRING COMMENT 'The assessors determination of the causal relationship between the investigational product and the adverse event. Standard WHO/ICH causality categories used in Oracle Argus Safety and regulatory submissions. Not assessable applies when insufficient information is available.. Valid values are `unrelated|unlikely|possible|probable|definite|not_assessable`',
    `causality_category_code` STRING COMMENT 'Standardized short code for the causality category used in CDISC SDTM AE domain submissions and Oracle Argus Safety exports (UN=Unrelated, UL=Unlikely, PO=Possible, PR=Probable, DE=Definite, NA=Not Assessable).. Valid values are `UN|UL|PO|PR|DE|NA`',
    `concomitant_medication_flag` BOOLEAN COMMENT 'Indicates whether this causality assessment pertains to a concomitant medication (True) rather than the primary investigational product (False). Enables differentiation of IP-related versus concomitant drug-related assessments within the same AE case.',
    `concomitant_medication_name` STRING COMMENT 'Name of the concomitant medication being assessed for causal relationship when concomitant_medication_flag is True. Populated from WHO Drug Dictionary (WHO-DD) preferred drug name.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this causality assessment record was first created in the source system (Oracle Argus Safety). Supports ALCOA+ audit trail requirements and regulatory inspection readiness.',
    `dechallenge_result` STRING COMMENT 'Outcome observed when the investigational product was withdrawn (dechallenged) following the adverse event. A positive dechallenge (AE resolved or improved upon withdrawal) supports a causal relationship. Captured per ICH E2A causality criteria.. Valid values are `positive|negative|not_applicable|unknown`',
    `dsmb_review_date` DATE COMMENT 'The date on which the DSMB/DMC formally reviewed this causality assessment during a scheduled or ad hoc safety review meeting.',
    `dsmb_reviewed` BOOLEAN COMMENT 'Indicates whether this causality assessment was reviewed by the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) as part of a formal safety review. Supports DSMB/DMC meeting documentation and regulatory oversight.',
    `expectedness` STRING COMMENT 'Determination of whether the adverse event is listed in the current Investigators Brochure (IB) or Reference Safety Information (RSI) as a known effect of the investigational product. Drives SUSAR classification and expedited reporting obligations.. Valid values are `expected|unexpected|unknown`',
    `expedited_report_required` BOOLEAN COMMENT 'Indicates whether this causality assessment triggers an obligation for expedited regulatory reporting (7-day or 15-day report) to health authorities such as FDA, EMA, or PMDA based on SUSAR classification.',
    `is_revised` BOOLEAN COMMENT 'Indicates whether this causality assessment is a revision of a previously submitted assessment. True when the assessor has changed their causality determination after initial submission, triggering regulatory follow-up reporting obligations.',
    `rationale_narrative` STRING COMMENT 'Free-text clinical narrative provided by the assessor explaining the reasoning behind the causality determination. Includes consideration of temporal relationship, biological plausibility, dechallenge/rechallenge results, and alternative explanations. Required for regulatory submissions.',
    `rechallenge_result` STRING COMMENT 'Outcome observed when the investigational product was re-administered (rechallenged) after the adverse event resolved. A positive rechallenge (AE recurred) provides strong evidence of causal relationship. Captured per ICH E2A causality criteria.. Valid values are `positive|negative|not_applicable|unknown`',
    `report_due_date` DATE COMMENT 'Calculated deadline date by which the expedited regulatory report (SUSAR/IND safety report) must be submitted to health authorities. Derived from the date of first awareness plus the applicable reporting timeline.',
    `reporting_timeline_days` STRING COMMENT 'The applicable expedited reporting timeline in calendar days from the date of first awareness of the SUSAR (typically 7 days for fatal/life-threatening or 15 days for other serious unexpected reactions). Drives compliance monitoring.',
    `revision_number` STRING COMMENT 'Sequential revision version number for this causality assessment. Starts at 1 for the original assessment and increments with each revision. Enables audit trail tracking of assessment changes over the case lifecycle.',
    `signal_detection_flag` BOOLEAN COMMENT 'Indicates whether this causality assessment has been flagged for inclusion in pharmacovigilance signal detection analysis within Oracle Argus Safety. Supports aggregate safety review and cumulative causality trend monitoring.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this causality assessment record was extracted. Primarily Oracle Argus Safety; may include Medidata Rave for EDC-sourced assessments or manual for paper-based entries.. Valid values are `oracle_argus_safety|medidata_rave|manual`',
    `sponsor_causality_category` STRING COMMENT 'The Sponsor Medical Monitors independent causality determination, captured separately from the investigators assessment. When sponsor_causality_override is True, this field holds the sponsors differing conclusion used for regulatory reporting.. Valid values are `unrelated|unlikely|possible|probable|definite|not_assessable`',
    `sponsor_causality_override` BOOLEAN COMMENT 'Indicates whether the Sponsor Medical Monitors causality determination differs from (overrides) the Investigators assessment. When True, both assessments are retained and the sponsors determination governs regulatory reporting obligations per ICH E2A.',
    `susar_flag` BOOLEAN COMMENT 'Indicates whether this adverse event has been classified as a Suspected Unexpected Serious Adverse Reaction (SUSAR) based on the combination of seriousness, causality (at least possible), and unexpectedness criteria. Triggers mandatory expedited regulatory reporting.',
    `temporal_relationship` STRING COMMENT 'Assessment of whether the timing between investigational product administration and adverse event onset is consistent with a causal relationship. A key criterion in WHO and ICH causality assessment frameworks.. Valid values are `compatible|incompatible|unknown`',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this causality assessment record was most recently modified in the source system. Tracks the latest change for audit trail compliance and Silver layer incremental load processing.',
    `who_dd_drug_code` STRING COMMENT 'WHO Drug Dictionary standardized drug code for the product (investigational or concomitant) being assessed. Enables cross-study signal detection and regulatory pharmacovigilance reporting.',
    CONSTRAINT pk_causality_assessment PRIMARY KEY(`causality_assessment_id`)
) COMMENT 'Records the investigator and sponsor medical monitor causality assessments for each adverse event relative to the investigational product and concomitant medications. Captures assessor role, assessment date, causality category (unrelated, unlikely, possible, probable, definite), rationale narrative, and whether the assessment was revised. Supports regulatory reporting and signal detection workflows in Oracle Argus Safety.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`narrative` (
    `narrative_id` BIGINT COMMENT 'Unique surrogate identifier for the safety narrative record in the Databricks Silver Layer. Primary key for this data product.',
    `adverse_event_id` BIGINT COMMENT 'Foreign key linking to safety.adverse_event. Business justification: Safety narratives are written for SAEs and SUSARs, which are adverse events. While safety_narrative already has icsr_id → icsr → adverse_event, a direct adverse_event_id FK is essential for narratives',
    `ae_meddra_coding_id` BIGINT COMMENT 'Foreign key linking to safety.ae_meddra_coding. Business justification: Narratives include MedDRA coding information (PT, SOC, LLT codes) that is authoritatively stored in ae_meddra_coding. Adding ae_meddra_coding_id normalizes the narrative by removing the denormalized M',
    `arm_id` BIGINT COMMENT 'Foreign key linking to study.arm. Business justification: Safety narratives for regulatory submissions (ICSRs, SAE reports) must include the treatment arm the subject was enrolled in. Medical writers and pharmacovigilance teams require arm context when autho',
    `causality_assessment_id` BIGINT COMMENT 'Foreign key linking to safety.causality_assessment. Business justification: Clinical narratives document the causality assessment as a core component of the case summary. The narrative.causality_assessment field is a denormalized string; adding a FK to causality_assessment pr',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: Narratives for EU trial safety reports are submitted under the CTA framework. The CTA governs the reporting obligation for narrative submissions in EU member states. A clinical research expert expects',
    `ctcae_grade_id` BIGINT COMMENT 'Foreign key linking to safety.ctcae_grade. Business justification: safety_narrative stores ctcae_grade (INT) and ctcae_version (STRING). Adding ctcae_grade_id FK to the ctcae_grade reference table normalizes the grade reference. The ctcae_grade INT and ctcae_version ',
    `dispensing_record_id` BIGINT COMMENT 'Foreign key linking to supply.dispensing_record. Business justification: Safety case narratives (ICH E2B, CIOMS I) must describe product exposure including dose, dispensing date, kit number, and compliance. The dispensing_record is the source of truth for these narrative e',
    `ecrf_form_id` BIGINT COMMENT 'Foreign key linking to data.ecrf_form. Business justification: Safety narratives reference specific eCRF forms as primary source documents. Medical writers use eCRF form data to construct case narratives; this link supports source document traceability required f',
    `enrollment_id` BIGINT COMMENT 'Foreign key linking to subject.enrollment. Business justification: Safety narratives for regulatory submissions must document the subjects treatment assignment, protocol version, and dosing history — all sourced from the enrollment record. Medical writers and pharma',
    `icsr_id` BIGINT COMMENT 'Reference to the parent safety case (SAE or SUSAR) for which this narrative is authored. Links to the safety case master record in Oracle Argus Safety.',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: Narratives for expedited safety reports are submitted under the IND. The IND number is required on all narrative submissions to the FDA. A clinical research expert expects narratives to reference the ',
    `investigational_site_id` BIGINT COMMENT 'Foreign key linking to site.investigational_site. Business justification: Regulatory case narratives per ICH E2B(R3) and FDA guidance must identify the site where the event occurred. safety_narrative has no site FK despite describing site-specific events. New site_id column',
    `lab_result_id` BIGINT COMMENT 'Foreign key linking to laboratory.lab_result. Business justification: Medical monitor narrative authoring (ICH E2A/E2B) requires direct reference to specific lab result values to populate the clinical description section. Narrative generation systems pull lab data (valu',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: Safety narratives are formal ICSR components filed as TMF documents. Medical writers and pharmacovigilance teams need to link the narrative record to its TMF-filed version for audit trail, version con',
    `safety_report_submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.safety_report_submission. Business justification: Narratives are the core content of safety report submissions (ICSRs, DSURs). The narrative is filed as part of the safety_report_submission to health authorities. A clinical research expert expects na',
    `serious_adverse_event_id` BIGINT COMMENT 'Foreign key linking to safety.serious_adverse_event. Business justification: Narratives are explicitly authored for SAEs and SUSARs. While narrative.adverse_event_id links to the base AE record, a direct FK to serious_adverse_event is needed to associate the narrative with the',
    `study_id` BIGINT COMMENT 'Reference to the clinical study (protocol) under which this safety narrative was generated.',
    `subject_visit_data_id` BIGINT COMMENT 'Foreign key linking to data.subject_visit_data. Business justification: Safety narratives are authored using source data from subject visit eCRF records. Medical writers and safety reviewers must trace narrative content back to the specific visit data record for source do',
    `subject_visit_id` BIGINT COMMENT 'Foreign key linking to subject.subject_visit. Business justification: ICH E2A-compliant safety narratives must include the visit at which the AE was observed/reported. Linking narrative to subject_visit enables automated population of visit date, visit number, and study',
    `susar_id` BIGINT COMMENT 'Foreign key linking to safety.susar. Business justification: Narratives are explicitly authored for SUSARs as part of the expedited regulatory reporting process. While narrative.adverse_event_id provides an indirect link, a direct FK to susar enables retrieval ',
    `trial_subject_id` BIGINT COMMENT 'Reference to the clinical trial subject (patient) associated with this safety narrative. Links to the subject master record.',
    `ae_onset_date` DATE COMMENT 'Date on which the adverse event first began, as reported by the investigator or subject. Critical for calculating reporting timelines and for CDISC SDTM AE domain mapping.',
    `ae_outcome` STRING COMMENT 'Coded outcome of the adverse event at the time of narrative authoring or case closure. Aligns with ICH E2B(R3) outcome codes and CDISC SDTM AE.AEOUT controlled terminology.. Valid values are `recovered|recovering|not_recovered|recovered_with_sequelae|fatal|unknown`',
    `ae_resolution_date` DATE COMMENT 'Date on which the adverse event resolved or stabilized. Null if the event is ongoing at the time of narrative authoring. Used to determine event duration and outcome status.',
    `approval_date` DATE COMMENT 'Date on which the medical monitor formally approved the final version of the safety narrative for regulatory submission. Represents the final lifecycle milestone before submission.',
    `argus_case_number` STRING COMMENT 'The externally-known case number assigned by Oracle Argus Safety to the adverse event case. Used as the primary business identifier for cross-system traceability and regulatory submissions.',
    `authoring_date` DATE COMMENT 'Date on which the safety narrative was initially authored or drafted. Supports ALCOA+ audit trail requirements and version history tracking.',
    `case_summary` STRING COMMENT 'High-level executive summary of the safety case, synthesizing the patient description, event, treatment, and outcome into a concise paragraph suitable for inclusion in the ICSR narrative field of E2B(R3) submissions.',
    `case_type` STRING COMMENT 'Classification of the safety case for which this narrative is written. SAE = Serious Adverse Event; SUSAR = Suspected Unexpected Serious Adverse Reaction; AE = Adverse Event; AESI = Adverse Event of Special Interest.. Valid values are `SAE|SUSAR|AE|AESI`',
    `causality_assessment` STRING COMMENT 'Medical monitors or investigators assessment of the causal relationship between the investigational product and the adverse event. Used in regulatory reporting and signal detection.. Valid values are `related|not_related|possibly_related|probably_related|unassessable`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this safety narrative record was first created in the system. Supports ALCOA+ audit trail and 21 CFR Part 11 electronic record requirements.',
    `ctcae_grade` STRING COMMENT 'Common Terminology Criteria for Adverse Events (CTCAE) severity grade assigned to the adverse event (1=Mild, 2=Moderate, 3=Severe, 4=Life-threatening, 5=Death). Used for safety signal detection and regulatory reporting.',
    `ctcae_version` STRING COMMENT 'Version of the NCI Common Terminology Criteria for Adverse Events used for severity grading in this narrative (e.g., 5.0). Ensures consistency in grading across study sites and regulatory submissions.. Valid values are `^[0-9]+.[0-9]+$`',
    `dsmb_review_date` DATE COMMENT 'Date on which the DSMB or DMC reviewed this safety case. Populated only when dsmb_reviewed is True. Used to track safety oversight compliance.',
    `dsmb_reviewed` BOOLEAN COMMENT 'Indicates whether this safety case and its narrative have been reviewed by the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC). True if reviewed; False if not yet presented to the DSMB/DMC.',
    `e2b_message_reference` STRING COMMENT 'Unique message identifier assigned to the ICSR transmission in E2B(R3) XML format as submitted via eCTD to health authorities. Enables traceability between the narrative record and the regulatory submission artifact.',
    `event_description` STRING COMMENT 'Detailed narrative describing the onset, nature, severity, and clinical course of the adverse event or serious adverse event, including signs, symptoms, and diagnostic findings. Core narrative section for ICSR submissions.',
    `expedited_report_due_date` DATE COMMENT 'Regulatory deadline by which the expedited safety report (ICSR) must be submitted to health authorities. Calculated from the date of first awareness per ICH E2A (7-day for fatal/life-threatening; 15-day for other serious unexpected).',
    `expedited_report_submitted_date` DATE COMMENT 'Actual date on which the expedited safety report (ICSR) was submitted to the relevant health authority via eCTD/E2B(R3) format. Used to verify compliance with regulatory reporting timelines.',
    `is_blinded` BOOLEAN COMMENT 'Indicates whether the narrative was authored under blinded conditions (True) or after unblinding of treatment assignment (False). Critical for maintaining study integrity in double-blind trials; blinded narratives must not reveal treatment allocation.',
    `medical_monitor_commentary` STRING COMMENT 'Clinical commentary and causality assessment provided by the medical monitor, including their opinion on the relationship between the investigational product and the adverse event, and any recommendations for protocol amendments or safety actions.',
    `medical_monitor_name` STRING COMMENT 'Full name of the medical monitor or safety physician who reviewed and approved the safety narrative. Required for regulatory audit trail and ICSR submission accountability.',
    `narrative_status` STRING COMMENT 'Current workflow status of the safety narrative document. Tracks progression from initial authoring through medical monitor review and approval to regulatory submission. superseded indicates a newer version has replaced this record.. Valid values are `draft|under_review|approved|submitted|superseded`',
    `outcome_description` STRING COMMENT 'Narrative section describing the resolution or current status of the adverse event, including recovery details, sequelae, or death information. Corresponds to the outcome field in E2B(R3) regulatory submissions.',
    `regulatory_authority_notified` STRING COMMENT 'Pipe-delimited list of regulatory authorities to which this safety report was submitted (e.g., FDA|EMA|PMDA|MHRA). Supports multi-jurisdictional compliance tracking. [ENUM-REF-CANDIDATE: FDA|EMA|PMDA|MHRA|TGA|Health_Canada|other — promote to reference product]',
    `report_type` STRING COMMENT 'Indicates whether this narrative supports an initial expedited report, a follow-up report with updated information, or a final report closing the case. Drives regulatory submission timelines under ICH E2A.. Valid values are `initial|follow_up|final`',
    `review_date` DATE COMMENT 'Date on which the medical monitor or safety physician completed their clinical review of the narrative. Distinct from the authoring date; marks the transition from draft to reviewed status.',
    `seriousness_criteria` STRING COMMENT 'Pipe-delimited list of ICH E2A seriousness criteria met by the adverse event (e.g., death|life_threatening|hospitalization|disability|congenital_anomaly|medically_significant). Determines expedited reporting obligations. [ENUM-REF-CANDIDATE: death|life_threatening|hospitalization|disability|congenital_anomaly|medically_significant|other — promote to reference product]',
    `source_document_reference` STRING COMMENT 'Reference identifier or path to the source documents (e.g., hospital records, lab reports, investigator notes) used to author this narrative, as stored in Veeva Vault eTMF. Supports SDV and audit trail requirements.',
    `subject_description` STRING COMMENT 'Structured narrative section describing the patients relevant medical history, demographics (age, sex, weight), concomitant medications, and pre-existing conditions relevant to the adverse event. Contains protected health information (PHI).',
    `treatment_description` STRING COMMENT 'Narrative section describing the investigational product(s) and concomitant medications administered, including dose, route, frequency, start and stop dates, and any dose modifications or interruptions relevant to the adverse event.',
    `unblinding_date` DATE COMMENT 'Date on which the treatment assignment was unblinded for this subject in the context of this safety case. Populated only when is_blinded transitions to False. Relevant for causality re-assessment post-unblinding.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this safety narrative record was most recently modified. Supports ALCOA+ audit trail, version control, and 21 CFR Part 11 electronic record requirements.',
    `version` STRING COMMENT 'Sequential version number of the safety narrative document, incremented each time the narrative is revised. Version 1 is the initial draft; subsequent versions reflect amendments or follow-up updates.',
    CONSTRAINT pk_narrative PRIMARY KEY(`narrative_id`)
) COMMENT 'Stores the structured clinical narrative for SAEs and SUSARs, including case summary, patient description, event description, treatment details, outcome, and medical monitor commentary. Tracks narrative version, authoring date, review status, and approval by the medical monitor. Used in expedited regulatory reports (ICSRs) submitted via Oracle Argus Safety in eCTD/E2B(R3) format.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`icsr` (
    `icsr_id` BIGINT COMMENT 'Unique surrogate identifier for the Individual Case Safety Report (ICSR) record in the Databricks Silver Layer. Primary key for this entity.',
    `adverse_event_id` BIGINT COMMENT 'Reference to the source adverse event or serious adverse event record in the safety.adverse_event product from which this ICSR was generated.',
    `ae_meddra_coding_id` BIGINT COMMENT 'Foreign key linking to safety.ae_meddra_coding. Business justification: ICSRs require the specific MedDRA coding record used for the regulatory submission. The icsr table has denormalized meddra_pt_code, meddra_soc_code, meddra_version fields that duplicate data in ae_med',
    `arm_id` BIGINT COMMENT 'Foreign key linking to study.arm. Business justification: ICSRs submitted to health authorities per ICH E2B(R3) must identify the treatment arm (study arm section of E2B message). Regulatory submissions require arm-level attribution for causality assessment ',
    `causality_assessment_id` BIGINT COMMENT 'Foreign key linking to safety.causality_assessment. Business justification: ICSRs must include the causality assessment as a mandatory regulatory field (ICH E2B standard). The icsr table has a narrative field for causality but no FK to the structured causality_assessment reco',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: ICSRs in EU trials are submitted under the CTA framework. The CTA defines the reporting obligation and authority for ICSR submissions in EU member states. A clinical research expert expects ICSRs to r',
    `dispensing_record_id` BIGINT COMMENT 'Foreign key linking to supply.dispensing_record. Business justification: E2B(R3) ICSR submissions to health authorities require product exposure details: dose, dispensing date, kit number, and subject compliance. The dispensing_record is the authoritative source for these ',
    `document_sop_id` BIGINT COMMENT 'Foreign key linking to document.document_sop. Business justification: ICSRs are prepared and submitted under a governing expedited reporting SOP (per ICH E2B and FDA/EMA requirements). Linking each ICSR to its governing SOP enables compliance verification, SOP deviation',
    `ecrf_form_id` BIGINT COMMENT 'Foreign key linking to data.ecrf_form. Business justification: ICSRs (E2B reports) are compiled from eCRF form data. ICH E2B regulatory requirement mandates traceability from the ICSR back to the source eCRF form; pharmacovigilance teams use this link during ICSR',
    `enrollment_id` BIGINT COMMENT 'Foreign key linking to subject.enrollment. Business justification: E2B(R3) ICSR submissions require enrollment context to document IMP identity, study arm, and protocol version in the case report. Regulatory agencies (FDA, EMA) require this linkage to validate IMP ex',
    `health_authority_id` BIGINT COMMENT 'Foreign key linking to regulatory.health_authority. Business justification: ICSRs are submitted to specific health authorities. Linking icsr to health_authority normalizes the regulatory_agency field and enables ICSR submission tracking by authority, supporting pharmacovigila',
    `imp_master_id` BIGINT COMMENT 'Foreign key linking to supply.imp_master. Business justification: ICSR (E2B) regulatory submissions require precise IMP identification including formulation, strength, and route. icsr.investigational_product_name is denormalized; FK to imp_master enables automated E',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: ICSRs are filed under specific IND applications per FDA 21 CFR 312.32 requirements. Linking icsr to ind_application enables IND-level ICSR tracking, supports IND annual report preparation, and is fund',
    `investigational_product_id` BIGINT COMMENT 'Foreign key linking to study.investigational_product. Business justification: ICSRs are filed per study investigational product — the E2B(R3) message requires study-specific IP details (IND number, formulation, dose form) from study.investigational_product, which is distinct fr',
    `investigational_site_id` BIGINT COMMENT 'Foreign key linking to site.investigational_site. Business justification: ICSRs submitted to FDA (MedWatch), EMA (EudraVigilance), and other authorities must identify the reporting site per ICH E2B(R3). icsr currently has no site FK despite containing site-level regulatory ',
    `irb_iec_approval_id` BIGINT COMMENT 'Foreign key linking to site.irb_iec_approval. Business justification: ICSRs trigger IRB/IEC notification obligations (ICH E6, 21 CFR 312.32). The active irb_iec_approval governs notification deadlines and approval status at the site. Linking icsr directly to irb_iec_app',
    `lab_result_id` BIGINT COMMENT 'Foreign key linking to laboratory.lab_result. Business justification: ICH E2B(R3) ICSR submissions require inclusion of relevant laboratory test results (Section C.3.1 lab data fields). Pharmacovigilance systems (Argus, Veeva Vault Safety) must link the specific lab res',
    `manufacture_batch_id` BIGINT COMMENT 'Foreign key linking to supply.manufacture_batch. Business justification: ICH E2B(R3) and FDA MedWatch ICSR formats require batch/lot number of the suspect medicinal product as a mandatory field. icsr has imp_master_id for product identity but lacks direct batch linkage, wh',
    `meddra_term_id` BIGINT COMMENT 'Foreign key linking to safety.meddra_term. Business justification: icsr stores meddra_pt_code, meddra_pt_name, meddra_soc_code as strings. Adding meddra_term_id FK normalizes the reference to the authoritative MedDRA dictionary. meddra_pt_name is removed as derivable',
    `regulatory_binder_id` BIGINT COMMENT 'Foreign key linking to document.regulatory_binder. Business justification: ICSRs submitted to regulatory agencies (FDA, EMA) are included in IND/CTA regulatory binders. Regulatory affairs teams need to link each ICSR to its submission binder for eCTD compilation, agency corr',
    `reporting_obligation_id` BIGINT COMMENT 'Foreign key linking to safety.safety_reporting_obligation. Business justification: Each ICSR is filed to fulfill a specific regulatory reporting obligation. icsr.reporting_obligation_type is a STRING that should be normalized to a FK. Adding safety_reporting_obligation_id links the ',
    `serious_adverse_event_id` BIGINT COMMENT 'Foreign key linking to safety.serious_adverse_event. Business justification: ICSRs are the formal regulatory submission records for expedited safety reporting, primarily triggered by SAEs and SUSARs. While icsr.adverse_event_id links to the base AE, a direct FK to serious_adve',
    `study_id` BIGINT COMMENT 'Reference to the clinical study associated with this ICSR, linking the safety report to the sponsoring trial.',
    `study_site_id` BIGINT COMMENT 'Foreign key linking to site.study_site. Business justification: ICSRs must be tracked against the study_site for site-level regulatory reporting metrics, IRB/IEC notification tracking, and CRO monitoring dashboards. icsr already has investigational_site_id but lac',
    `subject_randomization_id` BIGINT COMMENT 'Foreign key linking to randomization.subject_randomization. Business justification: ICSR (E2B/MedWatch) preparation requires the subjects randomization assignment — treatment arm and blinding status — to complete causality and drug exposure sections. Pharmacovigilance systems like A',
    `subject_visit_data_id` BIGINT COMMENT 'Foreign key linking to data.subject_visit_data. Business justification: ICSRs are compiled from subject visit eCRF data. E2B traceability requirements and health authority inspections require linking each ICSR to the specific visit data record from which the case informat',
    `subject_visit_id` BIGINT COMMENT 'Foreign key linking to subject.subject_visit. Business justification: ICSRs require visit-level traceability for complete case narrative construction and SDTM AE domain mapping. The visit at which the reportable event was observed is a standard data element in E2B(R3) c',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: ICSRs are expedited regulatory submissions (7/15-day reports) that must be filed as essential documents in the TMF per ICH E6(R2) and GVP Module VI. TMF managers and regulatory affairs teams track the',
    `trial_subject_id` BIGINT COMMENT 'Reference to the clinical trial subject (patient) who experienced the adverse event triggering this ICSR.',
    `acknowledgement_date` DATE COMMENT 'The date on which the regulatory agency formally acknowledged receipt of the ICSR submission. For electronic submissions via EudraVigilance or FDA gateway, this is the date of the automated acknowledgement message (ACK).',
    `acknowledgement_number` STRING COMMENT 'The unique reference number or message ID returned by the regulatory agency in the acknowledgement (ACK) message confirming receipt of the ICSR. Used for reconciliation and proof of submission.',
    `applicable_deadline_date` DATE COMMENT 'The operative regulatory deadline date for this specific ICSR, reflecting the applicable reporting window (7-day or 15-day) based on the seriousness criteria and expectedness of the adverse event. Used for compliance monitoring.',
    `argus_case_number` STRING COMMENT 'The unique case identifier assigned by Oracle Argus Safety to the source safety case from which this ICSR was generated. Used for traceability back to the system of record.',
    `awareness_date` DATE COMMENT 'The date on which the sponsor or CRO first became aware of the adverse event that triggered this ICSR. This is the regulatory clock start date (Day 0) from which all expedited reporting deadlines (7-day and 15-day) are calculated per ICH E2A.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this ICSR record was first created in Oracle Argus Safety and ingested into the Databricks Silver Layer. Supports audit trail and ALCOA+ data integrity requirements.',
    `days_to_submission` STRING COMMENT 'The number of calendar days elapsed between the awareness_date (clock start) and the actual submission_date. Used to assess compliance with 7-day and 15-day expedited reporting requirements. Negative values indicate early submission.',
    `deadline_15day_date` DATE COMMENT 'The calculated calendar date by which a serious unexpected adverse reaction (non-fatal/non-life-threatening SUSAR) must be submitted to the regulatory agency, computed as awareness_date + 15 calendar days per ICH E2A.',
    `deadline_7day_date` DATE COMMENT 'The calculated calendar date by which a fatal or life-threatening unexpected SUSAR must be submitted to the regulatory agency, computed as awareness_date + 7 calendar days per ICH E2A.',
    `delay_reason` STRING COMMENT 'Free-text explanation documenting the reason why the ICSR was not submitted within the applicable regulatory deadline. Required for late submissions to support CAPA processes and regulatory inspection readiness.',
    `dsmb_notified` BOOLEAN COMMENT 'Indicates whether the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) was notified of this ICSR. Required for studies with an active DSMB charter.',
    `irb_iec_notification_date` DATE COMMENT 'The date on which the Institutional Review Board (IRB) or Independent Ethics Committee (IEC) was formally notified of this ICSR. Used for compliance tracking against GCP notification requirements.',
    `irb_iec_notified` BOOLEAN COMMENT 'Indicates whether the Institutional Review Board (IRB) or Independent Ethics Committee (IEC) overseeing the study was notified of this ICSR, as required by GCP and applicable regulations.',
    `is_current_version` BOOLEAN COMMENT 'Indicates whether this record represents the most current version of the ICSR. True for the latest version; False for superseded versions retained for audit history.',
    `is_fatal` BOOLEAN COMMENT 'Indicates whether the adverse event associated with this ICSR resulted in the death of the subject. Fatal cases trigger the 7-day expedited reporting clock per ICH E2A.',
    `is_life_threatening` BOOLEAN COMMENT 'Indicates whether the adverse event associated with this ICSR was life-threatening (i.e., the subject was at immediate risk of death). Life-threatening cases trigger the 7-day expedited reporting clock per ICH E2A.',
    `is_on_time` BOOLEAN COMMENT 'Indicates whether the ICSR was submitted to the regulatory agency on or before the applicable regulatory deadline date. True = compliant submission; False = late submission. Key KPI for regulatory compliance monitoring.',
    `is_susar` BOOLEAN COMMENT 'Indicates whether this ICSR relates to a Suspected Unexpected Serious Adverse Reaction (SUSAR). SUSARs require expedited reporting to regulatory authorities and ethics committees under ICH E2A and EU CTR 536/2014.',
    `narrative` STRING COMMENT 'The structured free-text clinical narrative summarizing the adverse event, patient information, treatment details, and outcome as included in the ICSR submission. Corresponds to ICH E2B(R3) H.1 narrative section.',
    `rejection_reason` STRING COMMENT 'The reason provided by the regulatory agency when an ICSR submission is rejected (e.g., data validation failure, duplicate case, missing mandatory fields). Populated only when submission_status = rejected.',
    `report_number` STRING COMMENT 'The externally-known, unique regulatory report identifier assigned to this ICSR submission (e.g., the E2B message identifier or MedWatch report number). Used by health authorities to track and acknowledge the submission.',
    `report_type` STRING COMMENT 'Indicates whether this ICSR is an initial submission, a follow-up update with new information, or a nullification (withdrawal) of a previously submitted report. Aligns with ICH E2B(R3) A.1.6.. Valid values are `initial|follow-up|nullification`',
    `report_version` STRING COMMENT 'Sequential version number of this ICSR record. Version 1 is the initial report; subsequent versions represent follow-up or amended submissions for the same case.',
    `sender_identifier` STRING COMMENT 'The unique identifier of the organization or individual sending the ICSR to the regulatory agency, as defined in ICH E2B(R3) A.3.1. Typically the sponsor or CRO EudraVigilance/FDA sender ID.',
    `source_system` STRING COMMENT 'The operational system of record from which this ICSR record was sourced. Primarily Oracle Argus Safety case submission module; Manual for records entered outside the system.. Valid values are `Oracle Argus Safety|Manual`',
    `submission_date` DATE COMMENT 'The actual calendar date on which the ICSR was transmitted to the regulatory agency. Used to calculate days-to-submission and determine on-time compliance against the applicable deadline.',
    `submission_method` STRING COMMENT 'The technical format or channel used to transmit the ICSR to the regulatory agency. E2B XML is the standard electronic format per ICH E2B(R3); MedWatch and CIOMS I are paper/PDF formats used for specific agencies or fallback scenarios.. Valid values are `E2B(R3) XML|E2B(R2) XML|MedWatch|CIOMS I|Gateway|Manual`',
    `submission_status` STRING COMMENT 'Current workflow state of the ICSR submission lifecycle. Tracks progression from internal drafting through regulatory acknowledgement or rejection.. Valid values are `draft|pending|submitted|acknowledged|rejected|nullified`',
    `submission_timestamp` TIMESTAMP COMMENT 'The precise date and time (with timezone) at which the ICSR was electronically transmitted to the regulatory agency gateway. Provides audit-grade precision beyond the submission date for 21 CFR Part 11 compliance.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this ICSR record was most recently modified in Oracle Argus Safety or the Databricks Silver Layer. Supports change tracking and ALCOA+ data integrity requirements.',
    CONSTRAINT pk_icsr PRIMARY KEY(`icsr_id`)
) COMMENT 'Individual Case Safety Report (ICSR) — the formal regulatory submission record for expedited safety reporting to health authorities (FDA, EMA, PMDA, MHRA). Captures report type (initial, follow-up, nullification), submission date, acknowledgement receipt, regulatory agency, submission method (E2B XML, MedWatch, CIOMS), report version, submission status, clock start date (date of first awareness), calculated 7-day and 15-day deadline dates, actual submission date, days-to-submission, on-time compliance flag, and reason for delay if late. Enables compliance monitoring against ICH E2A and regional reporting requirements. Sourced from Oracle Argus Safety case submission module.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`signal` (
    `signal_id` BIGINT COMMENT 'Unique surrogate identifier for the safety signal record in the Databricks Silver Layer. Primary key for this entity.',
    `adverse_event_id` BIGINT COMMENT 'Foreign key linking to the adverse event case included in this signals case series',
    `analysis_population_id` BIGINT COMMENT 'Foreign key linking to biostatistics.analysis_population. Business justification: Safety signals are detected within a defined analysis population (e.g., safety population, ITT). DSMB and regulatory signal evaluation reports must specify which population the signal was observed in;',
    `arm_id` BIGINT COMMENT 'Foreign key linking to study.arm. Business justification: Safety signals are detected and evaluated at the treatment arm level — a signal in the high-dose arm vs. placebo arm drives different regulatory actions. DSMB signal reports and pharmacovigilance anal',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: Safety signals in EU trials may require CTA amendments or urgent safety measures under the CTA framework. A clinical research expert expects signals to reference the governing CTA for EU regulatory ac',
    `epoch_id` BIGINT COMMENT 'Foreign key linking to study.epoch. Business justification: Safety signals are detected within specific study epochs — a signal emerging during the treatment epoch vs. follow-up has different causality implications. DSMB data packages and signal evaluation rep',
    `health_authority_id` BIGINT COMMENT 'Foreign key linking to regulatory.health_authority. Business justification: Safety signals are reported to specific health authorities (FDA, EMA). The health authority determines the reporting format and timeline. A clinical research expert expects signals to reference the he',
    `imp_master_id` BIGINT COMMENT 'Foreign key linking to supply.imp_master. Business justification: Signal detection and management is product-centric; pharmacovigilance teams aggregate signals by IMP for DSUR Section 16 and PBRER. safety_signal.investigational_product_name is denormalized; FK to im',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: Safety signals identified during a trial must be reported to the FDA under the IND. Signal management and expedited reporting are governed by the IND safety reporting framework. A clinical research ex',
    `investigational_product_id` BIGINT COMMENT 'Foreign key linking to study.investigational_product. Business justification: Safety signals are tracked per study-level investigational product record. study.investigational_product contains study-specific IP details (dose form, strength, IND reference) needed for signal evalu',
    `manufacture_batch_id` BIGINT COMMENT 'Foreign key linking to supply.manufacture_batch. Business justification: Safety signal detection and evaluation must determine whether a signal is batch-specific (manufacturing defect) or product-wide. Pharmacovigilance signal management systems link signals to specific ba',
    `meddra_term_id` BIGINT COMMENT 'Foreign key linking to safety.meddra_term. Business justification: safety_signal stores MedDRA PT and SOC codes and names as strings. Adding meddra_term_id FK to the meddra_term reference master normalizes the terminology reference. meddra_pt_name and meddra_soc_name',
    `sdtm_dataset_id` BIGINT COMMENT 'Foreign key linking to data.sdtm_dataset. Business justification: Safety signals are detected from SDTM AE/SAE datasets. Signal detection workflows (e.g., disproportionality analysis) reference specific SDTM dataset versions; this link is required for signal documen',
    `statistical_endpoint_id` BIGINT COMMENT 'Foreign key linking to biostatistics.statistical_endpoint. Business justification: Safety signal detection and benefit-risk evaluation reference the specific SAP-defined statistical endpoint being monitored. Regulatory signal evaluation reports and DSMB packages must cite which endp',
    `study_id` BIGINT COMMENT 'Reference to the clinical study associated with this safety signal. Links the signal to the study protocol under which the signal was detected.',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: Safety signal detection and management reports are required TMF artifacts per ICH E2E and EMA pharmacovigilance guidelines. Each signal record must link to its filed TMF document for inspection readin',
    `treatment_arm_id` BIGINT COMMENT 'Foreign key linking to randomization.treatment_arm. Business justification: Safety signals are detected and evaluated at treatment-arm level (active vs. placebo disproportionality). Signal evaluation reports and DSMB referrals require arm-level attribution. safety_signal has ',
    `argus_signal_reference` STRING COMMENT 'Native signal identifier assigned by Oracle Argus Safety signal detection and evaluation module. Used for traceability back to the source system of record.',
    `benefit_risk_summary` STRING COMMENT 'Narrative summary of the benefit-risk assessment conducted as part of signal evaluation. Captures the medical monitors or safety committees conclusion on whether the signal alters the overall benefit-risk profile of the investigational product.',
    `case_count` STRING COMMENT 'Total number of adverse event cases contributing to the safety signal at the time of detection or most recent evaluation. Represents the volume of evidence supporting the signal.',
    `case_weight` DECIMAL(18,2) COMMENT 'Numeric weight assigned to this case in quantitative pharmacovigilance signal metrics (e.g., PRR, ROR, BCPNN). Reflects the cases contribution to the disproportionality statistic. Null for signals detected via clinical review rather than quantitative methods.',
    `contribution_date` DATE COMMENT 'Date on which this adverse event case was formally added to the signal case series during signal evaluation. Supports audit trail and evaluation timeline reconstruction.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this safety signal record was first created in the system. Supports audit trail requirements and data lineage tracking per 21 CFR Part 11 and ALCOA+ principles.',
    `data_reviewed_summary` STRING COMMENT 'Summary of the data sources and datasets reviewed during signal evaluation, including case narratives, aggregate safety data, literature, and clinical trial data from Medidata Rave or SAS Drug Development outputs.',
    `detection_date` DATE COMMENT 'Date on which the safety signal was first identified or flagged, either by automated detection algorithms in Oracle Argus Safety or by a medical monitor during clinical review. Critical for regulatory reporting timelines.',
    `detection_method` STRING COMMENT 'Method used to detect the safety signal. Includes quantitative pharmacovigilance methods such as Proportional Reporting Ratio (PRR), Reporting Odds Ratio (ROR), Bayesian Confidence Propagation Neural Network (BCPNN), disproportionality analysis, clinical review, or literature review. [ENUM-REF-CANDIDATE: disproportionality_analysis|PRR|ROR|BCPNN|clinical_review|literature_review|spontaneous_report|data_mining — promote to reference product]',
    `dsmb_recommendation` STRING COMMENT 'Formal recommendation issued by the DSMB/DMC following their review of the safety signal. Drives sponsor and investigator actions regarding study continuation, protocol modification, or suspension.. Valid values are `continue|modify_protocol|suspend|terminate|increase_monitoring|no_action`',
    `dsmb_review_date` DATE COMMENT 'Date on which the DSMB/DMC reviewed this safety signal. Null if not yet reviewed or not referred. Used to track DSMB meeting schedules and signal review timelines.',
    `evaluation_completion_date` DATE COMMENT 'Date on which the formal evaluation of the safety signal was completed and a final disposition was reached. Null if evaluation is still in progress.',
    `evaluation_cycle_number` STRING COMMENT 'Sequential cycle number for the current evaluation of this safety signal. Supports multiple evaluation cycles as new data emerges (e.g., Cycle 1 = initial evaluation, Cycle 2 = re-evaluation after new cases). Enables tracking of iterative signal assessments.',
    `evaluation_due_date` DATE COMMENT 'Target due date for completing the signal evaluation, based on signal priority and applicable regulatory timelines (e.g., 30 days for high-priority signals per EMA GVP Module IX). Used for SLA tracking and escalation.',
    `evaluation_plan` STRING COMMENT 'Narrative description of the planned approach for evaluating the safety signal, including data sources to be reviewed, analyses to be conducted, and timelines. Documented in Oracle Argus Safety evaluation module.',
    `evaluation_start_date` DATE COMMENT 'Date on which formal evaluation of the safety signal was initiated. Used to track evaluation timelines against regulatory and internal SOP requirements.',
    `final_disposition` STRING COMMENT 'Final outcome of the signal evaluation process. Indicates whether the signal was validated as a new risk, validated as a change in known risk, refuted as not a true signal, requires further monitoring, or requires no action. Populated upon evaluation completion.. Valid values are `validated_new_risk|validated_change_in_risk|refuted|requires_further_monitoring|no_action_needed`',
    `inclusion_reason` STRING COMMENT 'Narrative or coded rationale explaining why this adverse event case was included in the signal case series. Examples: confirmed causality, meets Brighton Collaboration criteria, index case for disproportionality, regulatory authority query. Supports signal evaluation documentation requirements.',
    `is_dsmb_referred` BOOLEAN COMMENT 'Indicates whether this safety signal has been referred to the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) for independent review. True = referred; False = not referred.',
    `is_expedited_reporting_required` BOOLEAN COMMENT 'Indicates whether this safety signal triggers expedited regulatory reporting obligations (e.g., 7-day or 15-day IND safety report to FDA, or SUSAR report to EMA). True = expedited reporting required; False = routine reporting.',
    `is_index_case` BOOLEAN COMMENT 'Indicates whether this adverse event was the sentinel (first) case that triggered initial detection of the safety signal. Only one case per signal should carry this flag as true.',
    `is_susar_related` BOOLEAN COMMENT 'Indicates whether this safety signal is associated with one or more Suspected Unexpected Serious Adverse Reactions (SUSARs). True = SUSAR-related; False = not SUSAR-related. Relevant for expedited regulatory reporting obligations.',
    `meddra_pt_code` STRING COMMENT 'MedDRA Preferred Term (PT) code representing the primary adverse event term associated with the safety signal. Standardized coding per MedDRA hierarchy for regulatory submissions and signal tracking.. Valid values are `^[0-9]{8}$`',
    `meddra_soc_code` STRING COMMENT 'MedDRA System Organ Class (SOC) code for the primary adverse event term associated with the safety signal. Used for signal categorization and aggregate safety reporting.. Valid values are `^[0-9]{8}$`',
    `meddra_version` STRING COMMENT 'Version of the MedDRA dictionary used for coding the adverse event terms associated with this safety signal (e.g., 26.1). Required for regulatory submissions to ensure coding consistency.. Valid values are `^[0-9]{1,2}.[0-9]{1}$`',
    `priority` STRING COMMENT 'Priority level assigned to the safety signal based on clinical seriousness, signal strength, and potential public health impact. Drives evaluation timelines and resource allocation.. Valid values are `critical|high|medium|low`',
    `regulatory_action_recommended` STRING COMMENT 'Regulatory action recommended as a result of signal evaluation. Options include label update (update Investigator Brochure or product label), Direct Healthcare Professional Communication (DHPC), study suspension, protocol amendment, risk minimization measures, no action required, or further monitoring. [ENUM-REF-CANDIDATE: label_update|DHPC|study_suspension|protocol_amendment|risk_minimization|no_action|further_monitoring — promote to reference product]',
    `regulatory_action_status` STRING COMMENT 'Current implementation status of the recommended regulatory action. Tracks whether the recommended action (e.g., label update, protocol amendment) has been initiated, completed, or determined not required.. Valid values are `pending|in_progress|completed|not_required`',
    `regulatory_report_due_date` DATE COMMENT 'Deadline by which the regulatory safety report (e.g., IND safety report, SUSAR report) must be submitted to the relevant health authority (FDA, EMA, MHRA, PMDA, etc.) based on the signals seriousness and expectedness.',
    `signal_description` STRING COMMENT 'Detailed narrative describing the nature of the safety signal, including the observed drug-event association, population affected, and clinical context. Supports medical monitor review and regulatory reporting.',
    `signal_number` STRING COMMENT 'Human-readable, externally-known business identifier for the safety signal (e.g., SIG-2024-00123). Used in regulatory correspondence, DSMB/DMC reports, and cross-functional communications.. Valid values are `^SIG-[0-9]{4}-[0-9]{5}$`',
    `signal_status` STRING COMMENT 'Current lifecycle status of the safety signal in the evaluation workflow. Tracks progression from initial detection through evaluation to final disposition. Values: new (newly detected, not yet evaluated), under_evaluation (active evaluation in progress), validated (confirmed as a real signal), refuted (determined not to be a true signal), ongoing_monitoring (validated but under continued surveillance), closed (evaluation complete, no further action required).. Valid values are `new|under_evaluation|validated|refuted|ongoing_monitoring|closed`',
    `source_system` STRING COMMENT 'Operational system of record from which this safety signal record originated (e.g., Oracle Argus Safety signal detection module, Medidata Rave EDC, SAS Drug Development). Supports data lineage and audit trail requirements per 21 CFR Part 11.. Valid values are `Oracle_Argus_Safety|Medidata_Rave|SAS_Drug_Development|manual`',
    `strength_lower_ci` DECIMAL(18,2) COMMENT 'Lower bound of the 95% confidence interval for the signal strength metric value. A lower CI > 1 (for PRR/ROR) or > 0 (for IC) typically indicates a statistically significant signal.',
    `strength_metric_name` STRING COMMENT 'Name of the quantitative disproportionality metric used to measure signal strength (e.g., PRR - Proportional Reporting Ratio, ROR - Reporting Odds Ratio, BCPNN IC - Information Component, EBGM - Empirical Bayes Geometric Mean). Null if signal was detected by clinical review only.. Valid values are `PRR|ROR|BCPNN_ic|EBGM|chi_squared|none`',
    `strength_value` DECIMAL(18,2) COMMENT 'Numeric value of the signal strength metric (e.g., PRR = 3.45, ROR = 4.12, IC = 2.1). Used to quantify the degree of disproportionate reporting and support signal validation decisions.',
    `title` STRING COMMENT 'Concise human-readable title describing the safety signal (e.g., Potential hepatotoxicity signal with Study Drug X). Used in dashboards, DSMB/DMC agendas, and regulatory submissions.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this safety signal record was most recently modified. Supports audit trail requirements and change tracking per 21 CFR Part 11 and ALCOA+ principles.',
    CONSTRAINT pk_signal PRIMARY KEY(`signal_id`)
) COMMENT 'Master record for identified safety signals and their full evaluation lifecycle. Captures signal description, detection method (disproportionality analysis, PRR, ROR, BCPNN, clinical review, literature), detection date, data source, signal strength metrics, assigned medical monitor, evaluation plan, data reviewed, benefit-risk assessment summary, regulatory action recommended (label update, DHPC, study suspension, protocol amendment), evaluation completion date, DSMB/DMC referral flag, current status (new, under evaluation, validated, refuted, ongoing monitoring), and final disposition. Supports multiple evaluation cycles as new data emerges. Managed in Oracle Argus Safety signal detection and evaluation modules.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`signal_evaluation` (
    `signal_evaluation_id` BIGINT COMMENT 'Unique surrogate identifier for each signal evaluation record in the Databricks Silver Layer. Primary key for the signal_evaluation data product. Entity role: TRANSACTION_HEADER — captures the formal evaluation workflow lifecycle for a detected safety signal.',
    `analysis_population_id` BIGINT COMMENT 'Foreign key linking to biostatistics.analysis_population. Business justification: Signal evaluations specify which analysis population (safety population, subgroup) the signal was detected in. DSMB and regulatory signal evaluation reports require this population reference; it deter',
    `arm_id` BIGINT COMMENT 'Foreign key linking to study.arm. Business justification: Signal evaluations are conducted per treatment arm to determine if a specific intervention is causing the signal. Benefit-risk assessments and regulatory action recommendations in signal_evaluation re',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: Signal evaluations in EU trials may require CTA amendments or safety notifications under the CTA framework. A clinical research expert expects signal evaluations to reference the governing CTA.',
    `ctcae_grade_id` BIGINT COMMENT 'Foreign key linking to safety.ctcae_grade. Business justification: signal_evaluation stores ctcae_grade as a STRING (not INT like other tables), which is a non-standard representation. Adding ctcae_grade_id FK to the ctcae_grade reference table normalizes this refere',
    `dsmb_review_id` BIGINT COMMENT 'Foreign key linking to safety.dsmb_review. Business justification: Signal evaluations are often reviewed and discussed at DSMB/DMC meetings. The signal_evaluation has is_dsmb_dmc_referral and dsmb_dmc_referral_date fields indicating DSMB involvement, but no FK to the',
    `health_authority_id` BIGINT COMMENT 'Foreign key linking to regulatory.health_authority. Business justification: Signal evaluations are reported to specific health authorities. The health_authority_query_reference field on signal_evaluation implies HA interaction but no FK exists. A clinical research expert expe',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: Signal evaluations may trigger IND safety reporting or IND amendments. The IND is the regulatory framework under which signal evaluations are reported to the FDA. A clinical research expert expects si',
    `meddra_term_id` BIGINT COMMENT 'Foreign key linking to safety.meddra_term. Business justification: signal_evaluation stores MedDRA PT and SOC codes and names as strings. Adding meddra_term_id FK normalizes the reference to the authoritative MedDRA dictionary. meddra_pt_name and meddra_soc_name are ',
    `regulatory_protocol_amendment_id` BIGINT COMMENT 'Foreign key linking to regulatory.protocol_amendment. Business justification: Signal evaluations requiring protocol changes trigger protocol amendments (protocol_amendment_required flag on signal_evaluation). Linking to the resulting protocol amendment enables pharmacovigilance',
    `safety_report_submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.safety_report_submission. Business justification: Signal evaluations that identify SUSARs or require expedited reporting result in safety_report_submissions. A clinical research expert expects signal evaluations to reference the resulting safety repo',
    `sdtm_dataset_id` BIGINT COMMENT 'Foreign key linking to data.sdtm_dataset. Business justification: Signal evaluations are conducted against specific SDTM dataset versions. Regulatory signal management documentation requires traceability from the evaluation to the exact dataset used; this supports r',
    `signal_id` BIGINT COMMENT 'Reference to the parent safety signal record that triggered this evaluation. A single signal may have multiple evaluation cycles as new data emerges.',
    `statistical_endpoint_id` BIGINT COMMENT 'Foreign key linking to biostatistics.statistical_endpoint. Business justification: Signal evaluations determine whether a safety signal impacts a primary or secondary statistical endpoint, potentially triggering protocol amendments or stopping rules. This link is required for benefi',
    `study_id` BIGINT COMMENT 'Reference to the clinical study associated with this signal evaluation. Links the evaluation to the specific trial protocol under which the signal was detected.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: Signal evaluations resulting in regulatory action generate formal submissions. Linking signal_evaluation to its submission replaces the denormalized expedited_report_submitted_date and enables signal-',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: Signal evaluation reports are formal GVP Module IX documents filed in the TMF. Each completed signal evaluation cycle produces a report that must be traceable in the TMF for regulatory inspections and',
    `treatment_arm_id` BIGINT COMMENT 'Foreign key linking to randomization.treatment_arm. Business justification: Signal evaluations assess whether a safety signal is arm-specific, which is a core regulatory requirement for signal management (ICH E2E). signal_evaluation has investigational_product_name as a plain',
    `argus_signal_evaluation_number` STRING COMMENT 'Externally-known business identifier for this signal evaluation as assigned by Oracle Argus Safety. Used for cross-system traceability and regulatory correspondence. Serves as the BUSINESS_IDENTIFIER for this TRANSACTION_HEADER.',
    `benefit_risk_assessment_summary` STRING COMMENT 'Narrative summary of the benefit-risk assessment conducted during this evaluation cycle, documenting the clinical judgment on the balance between therapeutic benefit and identified safety risk.',
    `benefit_risk_conclusion` STRING COMMENT 'Formal conclusion of the benefit-risk assessment for this evaluation cycle. Drives downstream regulatory action decisions.. Valid values are `favorable|unfavorable|inconclusive|requires_further_evaluation`',
    `case_count_reviewed` STRING COMMENT 'Total number of adverse event cases reviewed during this signal evaluation cycle. Provides a quantitative measure of the evidence base examined.',
    `causality_assessment` STRING COMMENT 'Assessment of the causal relationship between the investigational product and the safety signal, using WHO-UMC or investigator causality criteria.. Valid values are `certain|probable|possible|unlikely|unassessable|not_related`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this signal evaluation record was first created in the system. RECORD_AUDIT_CREATED for TRANSACTION_HEADER role. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `data_sources_reviewed` STRING COMMENT 'Description of the data sources reviewed during this evaluation, such as clinical trial databases, spontaneous report databases (FAERS, EudraVigilance), published literature, and DSMB/DMC reports.',
    `dsmb_dmc_recommendation` STRING COMMENT 'Formal recommendation issued by the DSMB or DMC following their independent review of the referred signal evaluation. Populated only when a DSMB/DMC review has been completed.. Valid values are `continue|modify_protocol|suspend|terminate|no_recommendation`',
    `dsmb_dmc_referral_date` DATE COMMENT 'Date on which the signal evaluation was formally referred to the DSMB or DMC for independent safety review. Populated only when is_dsmb_dmc_referral is True.',
    `evaluation_completion_date` DATE COMMENT 'Date on which the formal signal evaluation was completed and conclusions were finalized. Marks the end of the evaluation lifecycle for this cycle.',
    `evaluation_cycle_number` STRING COMMENT 'Sequential cycle number for this evaluation of the signal (e.g., 1 for initial evaluation, 2 for re-evaluation after new data). Supports tracking of iterative evaluation rounds for the same signal.',
    `evaluation_initiated_date` DATE COMMENT 'The date on which the formal signal evaluation process was initiated. Serves as the principal BUSINESS_EVENT_TIMESTAMP for this transaction, marking the start of the regulatory evaluation clock.',
    `evaluation_outcome` STRING COMMENT 'Final outcome determination of the signal evaluation cycle. Indicates whether the signal was confirmed as a new safety finding, refuted by the evidence, or requires ongoing monitoring.. Valid values are `signal_confirmed|signal_refuted|signal_ongoing|new_signal_identified|no_action_required`',
    `evaluation_plan_description` STRING COMMENT 'Narrative description of the evaluation plan, including the scope of data to be reviewed, analytical approach, and objectives for this evaluation cycle.',
    `evaluation_status` STRING COMMENT 'Current lifecycle state of the signal evaluation workflow. Tracks progression from initiation through completion. LIFECYCLE_STATUS for TRANSACTION_HEADER role.. Valid values are `initiated|in_progress|pending_review|completed|closed|superseded`',
    `expedited_report_due_date` DATE COMMENT 'Regulatory deadline by which the expedited safety report (e.g., SUSAR) must be submitted to the relevant authority. Calculated from the awareness date per ICH E2A timelines (7 or 15 calendar days).',
    `expedited_reporting_required` BOOLEAN COMMENT 'Indicates whether this signal evaluation triggers an expedited regulatory reporting obligation (e.g., SUSAR 7-day or 15-day report). True = expedited reporting required.',
    `health_authority_query_reference` STRING COMMENT 'Reference number assigned by a regulatory authority (FDA, EMA, MHRA, etc.) for any formal query or request for information related to this signal evaluation. Enables traceability of regulatory correspondence.',
    `investigational_product_name` STRING COMMENT 'Name of the investigational medicinal product (IMP) or drug substance associated with the safety signal under evaluation.',
    `is_current_version` BOOLEAN COMMENT 'Indicates whether this record represents the current active version of the signal evaluation. True = current version; False = superseded version. Supports slowly changing dimension (SCD) pattern in the Silver Layer.',
    `is_dsmb_dmc_referral` BOOLEAN COMMENT 'Indicates whether this signal evaluation has been referred to the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) for independent review. True = referred; False = not referred.',
    `is_susar` BOOLEAN COMMENT 'Indicates whether the safety signal under evaluation has been classified as a Suspected Unexpected Serious Adverse Reaction (SUSAR), triggering specific expedited reporting obligations under ICH E2A.',
    `meddra_pt_code` STRING COMMENT 'MedDRA Preferred Term code representing the primary adverse event or medical concept under evaluation. Used for standardized coding and regulatory reporting alignment.. Valid values are `^[0-9]{8}$`',
    `meddra_soc_code` STRING COMMENT 'MedDRA System Organ Class code for the primary adverse event under evaluation. Supports aggregate safety reporting by organ system.. Valid values are `^[0-9]{8}$`',
    `meddra_version` STRING COMMENT 'Version of the MedDRA dictionary used for coding the signal evaluation (e.g., 26.0). Ensures reproducibility and regulatory traceability of coding decisions.. Valid values are `^[0-9]{1,2}.[0-9]{1}$`',
    `protocol_amendment_required` BOOLEAN COMMENT 'Indicates whether this signal evaluation has resulted in a recommendation to amend the study protocol (e.g., dose modification, additional safety monitoring, exclusion criteria update).',
    `regulatory_action_justification` STRING COMMENT 'Narrative justification for the recommended regulatory action, documenting the clinical and scientific rationale supporting the recommendation.',
    `regulatory_action_recommended` STRING COMMENT 'Formal regulatory action recommended as an outcome of this signal evaluation. Options include label update, Direct Healthcare Professional Communication (DHPC), study suspension, protocol amendment, Risk Management Plan (RMP) update, or urgent safety measure. [ENUM-REF-CANDIDATE: no_action|label_update|dhpc|study_suspension|protocol_amendment|rmp_update|urgent_safety_measure|additional_pharmacovigilance — promote to reference product]',
    `regulatory_authority_notified` STRING COMMENT 'Identifies the primary regulatory authority notified as part of this signal evaluation outcome. For multi-authority notifications, use multiple and document details in the regulatory action justification. [ENUM-REF-CANDIDATE: FDA|EMA|MHRA|PMDA|TGA|Health_Canada|multiple|none — 8 candidates stripped; promote to reference product]',
    `risk_minimization_measure` STRING COMMENT 'Risk minimization measure recommended or implemented as a result of this signal evaluation. Supports Risk Management Plan (RMP) updates and regulatory commitments.. Valid values are `routine_pharmacovigilance|additional_monitoring|rmp_update|educational_material|restricted_access|none`',
    `signal_detection_method` STRING COMMENT 'Statistical or clinical methodology used to detect the safety signal prior to this evaluation. Examples include disproportionality analysis (PRR, ROR), data mining algorithms, or clinical case series review.. Valid values are `disproportionality_analysis|clinical_review|data_mining|literature_review|regulatory_request|dsmb_dmc_referral`',
    `signal_source` STRING COMMENT 'Origin of the safety signal that triggered this evaluation. Identifies whether the signal arose from spontaneous adverse event reports, clinical trial data, published literature, a regulatory authority communication, or DSMB/DMC review. [ENUM-REF-CANDIDATE: spontaneous_reports|clinical_trial_data|literature|regulatory_authority|dsmb_dmc|eudravigilance|faers|internal_review — promote to reference product]',
    `source_system` STRING COMMENT 'Operational system of record from which this signal evaluation record originated. Primarily Oracle Argus Safety for adverse event signal management and regulatory case submission.. Valid values are `Oracle_Argus_Safety|manual|other`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this signal evaluation record was last modified. RECORD_AUDIT_UPDATED for TRANSACTION_HEADER role. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `version` STRING COMMENT 'Version number of this evaluation record, incremented each time the evaluation is updated or revised. Supports audit trail and version control per ALCOA+ principles.',
    CONSTRAINT pk_signal_evaluation PRIMARY KEY(`signal_evaluation_id`)
) COMMENT 'Transactional record capturing the formal evaluation workflow for a safety signal, including evaluation plan, data reviewed, benefit-risk assessment, regulatory action recommended (label update, DHPC, study suspension, protocol amendment), evaluation completion date, and DSMB/DMC referral flag. Each signal may have multiple evaluation cycles as new data emerges.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`dsmb_review` (
    `dsmb_review_id` BIGINT COMMENT 'Unique surrogate identifier for each DSMB/DMC review record in the safety governance system. Primary key for the dsmb_review data product.',
    `arm_id` BIGINT COMMENT 'Foreign key linking to study.arm. Business justification: DSMB reviews unblinded safety data by treatment arm — the arm under review is a fundamental operational attribute. Stopping rule evaluations and dose modification recommendations require identifying w',
    `blinding_config_id` BIGINT COMMENT 'Foreign key linking to randomization.blinding_config. Business justification: DSMB reviews operate under a specific blinding configuration defining the committees unblinded access level. Audit trails for GCP compliance require documenting which blinding_config governed each DS',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: DSMB reviews in EU trials operate under the CTA framework. DSMB findings may require CTA amendments or urgent safety measures. A clinical research expert expects DSMB reviews to reference the governin',
    `database_lock_event_id` BIGINT COMMENT 'Foreign key linking to biostatistics.database_lock_event. Business justification: DSMB data packages are prepared from a specific database lock/data cut. Traceability from DSMB review to the formal database_lock_event is required for audit trail and regulatory inspection; dsmb_revi',
    `epoch_id` BIGINT COMMENT 'Foreign key linking to study.epoch. Business justification: DSMB reviews are scheduled at specific study epochs (end of treatment, interim analysis points). Linking dsmb_review to epoch enables tracking of which epochs data was reviewed and supports study_mil',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: DSMB reviews may result in IND safety reporting requirements or IND amendments. The IND governs whether DSMB findings require FDA notification. A clinical research expert expects DSMB reviews to refer',
    `interim_analysis_id` BIGINT COMMENT 'Reference to the formal interim analysis record associated with this DSMB/DMC review, if applicable. Links safety governance to the statistical interim analysis conducted per the Statistical Analysis Plan (SAP).',
    `monitoring_plan_id` BIGINT COMMENT 'Foreign key linking to monitoring.monitoring_plan. Business justification: DSMB reviewers require the monitoring plan to assess data quality, SDV coverage, and monitoring approach when evaluating unblinded safety data. The DSMB charter typically references the monitoring pla',
    `tmf_document_id` BIGINT COMMENT 'Document identifier for the official DSMB/DMC meeting minutes stored in the electronic Trial Master File (eTMF) system (Veeva Vault). Provides traceability to the formal meeting record. Classified confidential as minutes contain unblinded safety deliberations.',
    `protocol_id` BIGINT COMMENT 'Foreign key linking to study.protocol. Business justification: DSMB charter and stopping rules are protocol-version-specific. The protocol version in effect at time of DSMB review determines the stopping criteria being evaluated. Regulatory submissions of DSMB re',
    `rand_list_id` BIGINT COMMENT 'Foreign key linking to randomization.rand_list. Business justification: DSMB unblinded safety reviews are conducted against a specific randomization list version. The unblinded statistician must reference the exact rand_list used during the review period to validate subje',
    `rand_scheme_id` BIGINT COMMENT 'Foreign key linking to randomization.rand_scheme. Business justification: DSMB reviews are conducted against a specific randomization scheme version governing blinding level, stratification, and allocation. The DSMB charter and data package are scheme-version-specific. dsmb',
    `reconciliation_id` BIGINT COMMENT 'Foreign key linking to data.reconciliation. Business justification: DSMB data packages require formal data reconciliation sign-off before unblinded data is presented. Linking the DSMB review to the reconciliation record documents the data quality status at the time of',
    `regulatory_binder_id` BIGINT COMMENT 'Foreign key linking to document.regulatory_binder. Business justification: DSMB review reports and recommendations are submitted to regulatory authorities and must be filed in regulatory binders. The existing submission_id links to the regulatory domain but not directly to t',
    `regulatory_protocol_amendment_id` BIGINT COMMENT 'Foreign key linking to regulatory.protocol_amendment. Business justification: DSMB reviews that identify safety issues trigger protocol amendments (protocol_amendment_required flag on dsmb_review). Linking to the resulting protocol amendment enables safety governance traceabili',
    `review_committee_id` BIGINT COMMENT 'Reference to the safety oversight committee (DSMB, DMC, IDMC, or internal SRC) that conducted this review. Links to the committee master record.',
    `sap_id` BIGINT COMMENT 'Foreign key linking to biostatistics.sap. Business justification: DSMB reviews are conducted per the SAP and statistical charter version in effect at the time of review. The unblinded statistician presents data per SAP specifications; regulatory submissions require ',
    `sdtm_dataset_id` BIGINT COMMENT 'Foreign key linking to data.sdtm_dataset. Business justification: DSMB reviews are conducted using unblinded SDTM datasets provided in the data package. Linking the DSMB review to the specific SDTM dataset version used is required for audit trails, reproducibility o',
    `signal_id` BIGINT COMMENT 'Foreign key linking to safety.safety_signal. Business justification: dsmb_review has safety_signal_identified (BOOLEAN) and safety_signal_description (STRING) but no FK to the safety_signal record. A DSMB review may be triggered by or identify a specific safety signal.',
    `statistical_endpoint_id` BIGINT COMMENT 'Foreign key linking to biostatistics.statistical_endpoint. Business justification: DSMB charters define stopping rules based on primary statistical endpoints. Each DSMB review formally assesses whether efficacy or safety stopping boundaries have been crossed; linking to the statisti',
    `study_id` BIGINT COMMENT 'Reference to the clinical study for which this DSMB/DMC review was conducted. Links the safety oversight record to the parent study master.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: DSMB reviews requiring regulatory notification generate formal submissions. Linking dsmb_review to its regulatory submission enables tracking of sponsor regulatory responses to DSMB outcomes, supporti',
    `argus_safety_case_ref` STRING COMMENT 'Reference identifier linking this DSMB/DMC review to related safety cases or aggregate safety reports in Oracle Argus Safety. Enables cross-referencing between safety governance decisions and individual case safety reports.',
    `charter_version` STRING COMMENT 'Version identifier of the DSMB/DMC charter document in effect at the time of this review (e.g., v1.0, v2.1). Ensures traceability to the governing charter under which the review was conducted.. Valid values are `^vd+.d+$`',
    `closed_session_held` BOOLEAN COMMENT 'Indicates whether a closed (confidential, unblinded) session was held during the DSMB/DMC meeting, attended only by committee members and the unblinded statistician (True = closed session held; False = no closed session).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this DSMB/DMC review record was first created in the system. Supports audit trail requirements under 21 CFR Part 11 and ALCOA+ data integrity principles.',
    `data_cutoff_date` DATE COMMENT 'The date through which clinical data was included in the unblinded safety data package reviewed by the DSMB/DMC. Defines the temporal scope of the safety data under review.',
    `data_package_version` STRING COMMENT 'Version identifier of the unblinded safety data package provided to the DSMB/DMC for this review. Ensures traceability between the committees recommendation and the exact data snapshot reviewed.',
    `implementation_date` DATE COMMENT 'Date on which the sponsor implemented the DSMB/DMC recommendation (e.g., date study was suspended, protocol amendment was issued, or continuation was confirmed). Used for regulatory timeline compliance tracking.',
    `is_independent` BOOLEAN COMMENT 'Indicates whether the committee is fully independent of the sponsor and investigator team (True = independent; False = internal/non-independent). Independence is a key regulatory requirement for unblinded safety reviews.',
    `meeting_date` DATE COMMENT 'Calendar date on which the DSMB/DMC review meeting was held. This is the principal business event date for the review record and is used for regulatory timeline tracking.',
    `meeting_number` STRING COMMENT 'Sequential ordinal number of this DSMB/DMC meeting within the study (e.g., 1 = first meeting, 2 = second meeting). Used to track the progression of safety oversight across the study lifecycle.',
    `meeting_type` STRING COMMENT 'Classification of the DSMB/DMC meeting format and trigger. Scheduled = pre-planned per charter; Ad hoc = convened outside regular schedule; Emergency = triggered by urgent safety signal; Teleconference = remote meeting; Written review = asynchronous document review without live meeting.. Valid values are `scheduled|ad_hoc|emergency|teleconference|written_review`',
    `members_present_count` STRING COMMENT 'Number of DSMB/DMC committee members who attended and participated in this review meeting. Used to verify quorum compliance and document meeting validity.',
    `next_review_date` DATE COMMENT 'Date of the next scheduled DSMB/DMC review meeting as recommended by the committee or defined in the charter. Used for proactive scheduling and safety oversight continuity planning.',
    `open_session_held` BOOLEAN COMMENT 'Indicates whether an open (non-confidential) session was held during the DSMB/DMC meeting, typically attended by the sponsor and investigators (True = open session held; False = closed session only). Standard DSMB meetings include both open and closed sessions.',
    `protocol_amendment_required` BOOLEAN COMMENT 'Indicates whether the DSMB/DMC recommendation requires a protocol amendment to be submitted to the IRB/IEC and regulatory authorities (True = amendment required; False = no amendment required). Triggers the protocol amendment workflow.',
    `quorum_achieved` BOOLEAN COMMENT 'Indicates whether the required quorum of DSMB/DMC members was present for the meeting to be valid per the committee charter (True = quorum met; False = quorum not met). Meetings without quorum may require rescheduling or written ratification.',
    `recommendation` STRING COMMENT 'The formal recommendation issued by the DSMB/DMC following the review. Continue = proceed without changes; Continue with modification = proceed with protocol or safety monitoring amendments; Suspend = temporary halt pending further review; Terminate = permanent study discontinuation; Pause enrollment = halt new enrollment while ongoing subjects continue. [ENUM-REF-CANDIDATE: continue|continue_with_modification|suspend|terminate|pause_enrollment|other — promote to reference product]. Valid values are `continue|continue_with_modification|suspend|terminate|pause_enrollment|other`',
    `recommendation_rationale` STRING COMMENT 'Narrative explanation provided by the DSMB/DMC justifying the formal recommendation. Documents the safety findings, benefit-risk assessment, and reasoning that led to the committees decision.',
    `regulatory_notification_date` DATE COMMENT 'Date on which the regulatory authority was notified of the DSMB/DMC recommendation or safety findings. Populated only when regulatory_notification_required is True. Used for compliance with expedited reporting timelines.',
    `regulatory_notification_due_date` DATE COMMENT 'Deadline by which the regulatory authority must be notified per applicable regulations (e.g., 7-day or 15-day reporting window). Enables proactive compliance monitoring and escalation.',
    `regulatory_notification_required` BOOLEAN COMMENT 'Indicates whether the DSMB/DMC recommendation or safety findings from this review require expedited regulatory notification to health authorities (True = notification required; False = no notification required).',
    `review_status` STRING COMMENT 'Current lifecycle status of the DSMB/DMC review record. Scheduled = meeting planned but not yet held; In progress = meeting underway or deliberations ongoing; Completed = recommendation issued and documented; Cancelled = meeting cancelled; Postponed = meeting rescheduled.. Valid values are `scheduled|in_progress|completed|cancelled|postponed`',
    `safety_signal_identified` BOOLEAN COMMENT 'Indicates whether the DSMB/DMC identified a new or emerging safety signal during this review that requires further investigation or monitoring (True = signal identified; False = no new signal). Triggers downstream signal management workflow in Oracle Argus Safety.',
    `source_system` STRING COMMENT 'Operational system of record from which this DSMB/DMC review record originated. Supports data lineage tracking in the Databricks Silver Layer lakehouse. Primary source is Oracle Argus Safety for safety governance records.. Valid values are `Oracle_Argus_Safety|Oracle_Siebel_CTMS|Veeva_Vault|Manual|Other`',
    `sponsor_response` STRING COMMENT 'The sponsors formal response to the DSMB/DMC recommendation. Accepted = sponsor will implement as recommended; Accepted with modification = sponsor accepts intent but modifies implementation; Rejected = sponsor disagrees and provides counter-rationale; Under review = sponsor is evaluating; Pending = response not yet provided.. Valid values are `accepted|accepted_with_modification|rejected|under_review|pending`',
    `sponsor_response_rationale` STRING COMMENT 'Narrative explanation of the sponsors response to the DSMB/DMC recommendation, particularly required when the sponsor rejects or modifies the recommendation. Documents the sponsors benefit-risk reasoning.',
    `stopping_rule_description` STRING COMMENT 'Description of the specific pre-specified stopping rule that was triggered, if applicable (e.g., Futility boundary crossed at IA2, Excess SAE rate in treatment arm exceeds 15%). Populated only when stopping_rule_triggered is True.',
    `stopping_rule_triggered` BOOLEAN COMMENT 'Indicates whether a pre-specified stopping rule defined in the DSMB charter or Statistical Analysis Plan (SAP) was triggered at this review (True = stopping rule met; False = no stopping rule triggered). Critical for regulatory audit trail.',
    `study_phase_reviewed` STRING COMMENT 'Clinical development phase of the study at the time of the DSMB/DMC review. Determines the regulatory framework and risk thresholds applicable to the safety assessment.. Valid values are `Phase_I|Phase_II|Phase_III|Phase_IV|Phase_I_II|Phase_II_III`',
    `subjects_enrolled_count` STRING COMMENT 'Total number of subjects enrolled in the study at the time of the DSMB/DMC data cutoff. Provides context for the safety data volume reviewed and is a key metric in the committees benefit-risk assessment.',
    `subjects_exposed_count` STRING COMMENT 'Number of subjects who received at least one dose of investigational product at the time of the data cutoff. Used for exposure-adjusted safety rate calculations in the DSMB/DMC review.',
    `unblinded_statistician_present` BOOLEAN COMMENT 'Indicates whether the independent unblinded statistician was present at the DSMB/DMC meeting to present the unblinded safety data package (True = present; False = not present). Required for valid closed-session deliberations.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this DSMB/DMC review record. Required for audit trail compliance under 21 CFR Part 11 and ALCOA+ data integrity principles.',
    CONSTRAINT pk_dsmb_review PRIMARY KEY(`dsmb_review_id`)
) COMMENT 'Master record for Data Safety Monitoring Board (DSMB) / Data Monitoring Committee (DMC) safety governance, covering both committee definition and individual review meetings. Captures committee name, type (DSMB, DMC, IDMC, internal SRC), charter version, member roster, independence status, meeting date, meeting type (scheduled, ad hoc, emergency), study phase reviewed, unblinded data package version, interim analysis reference, formal recommendations issued (continue, modify, suspend, terminate), recommendation rationale, sponsor response, implementation date, and regulatory notification requirements. This is the SSOT for safety oversight committee governance and their formal outputs.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`dsmb_recommendation` (
    `dsmb_recommendation_id` BIGINT COMMENT 'Unique surrogate identifier for each formal DSMB/DMC recommendation record in the safety domain. Entity role: TRANSACTION_HEADER — represents a discrete formal recommendation event issued by the DSMB/DMC following a safety review meeting.',
    `treatment_arm_id` BIGINT COMMENT 'Foreign key linking to randomization.treatment_arm. Business justification: DSMB stopping rules and arm-suspension recommendations target specific treatment arms. affected_treatment_arms on dsmb_recommendation is a plain text denormalization of treatment_arm. Operational impl',
    `capa_id` BIGINT COMMENT 'Identifier of the Corrective and Preventive Action (CAPA) record created in MasterControl in response to this DSMB/DMC recommendation. Links the safety recommendation to the quality management system for formal remediation tracking.',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: DSMB recommendations in EU trials may require CTA amendments or urgent safety measures under the CTA framework. A clinical research expert expects DSMB recommendations to reference the governing CTA.',
    `dsmb_review_id` BIGINT COMMENT 'Reference to the parent DSMB/DMC safety review meeting that generated this recommendation. A single review meeting may produce one or more recommendations.',
    `epoch_id` BIGINT COMMENT 'Foreign key linking to study.epoch. Business justification: DSMB recommendations often apply to specific epochs — e.g., stop the treatment epoch, extend follow-up epoch, or modify dosing in the next epoch. Epoch-level recommendations drive protocol amendments ',
    `health_authority_id` BIGINT COMMENT 'Foreign key linking to regulatory.health_authority. Business justification: DSMB recommendations requiring regulatory notification must reference the specific health authority to be notified. The dsmb_recommendation has regulatory_notification_required and regulatory_agencies',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: DSMB recommendations may require IND amendments or expedited safety reports to the FDA. The IND is the regulatory vehicle for implementing DSMB recommendations in US trials. A clinical research expert',
    `interim_analysis_id` BIGINT COMMENT 'Foreign key linking to biostatistics.interim_analysis. Business justification: Each DSMB recommendation is issued in response to a specific interim analysis. Regulatory submissions and TMF require traceability from recommendation to the triggering interim analysis; this link ena',
    `regulatory_protocol_amendment_id` BIGINT COMMENT 'Foreign key linking to regulatory.protocol_amendment. Business justification: DSMB recommendations frequently trigger protocol amendments (protocol_amendment_required flag exists on dsmb_recommendation). Linking to the resulting protocol amendment enables safety governance trac',
    `sap_id` BIGINT COMMENT 'Foreign key linking to biostatistics.sap. Business justification: DSMB recommendations for sample size re-estimation, stopping rule changes, or additional analyses require SAP amendments. Tracking which SAP version a recommendation targets is required for sponsor re',
    `signal_evaluation_id` BIGINT COMMENT 'Foreign key linking to safety.signal_evaluation. Business justification: DSMB recommendations are often issued in response to specific signal evaluations presented at the DSMB meeting. The dsmb_recommendation has signal_id → signal but no FK to the specific signal_evaluati',
    `signal_id` BIGINT COMMENT 'Reference to the specific safety signal or aggregate safety finding in Oracle Argus Safety that prompted or informed this DSMB/DMC recommendation. Nullable when the recommendation arises from routine scheduled review rather than a specific signal.',
    `study_id` BIGINT COMMENT 'Reference to the clinical study for which this DSMB/DMC recommendation was issued. Links the recommendation to the study protocol and sponsor context.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: DSMB recommendations requiring regulatory notification generate formal regulatory submissions. Linking the recommendation to its submission enables tracking of sponsor regulatory responses to DSMB dec',
    `tmf_document_id` BIGINT COMMENT 'Document identifier in Veeva Vault eTMF for the official DSMB/DMC recommendation letter or minutes filed in the Trial Master File. Ensures regulatory-compliant document traceability per ICH E6(R2) Section 8.',
    `affected_subject_population` STRING COMMENT 'Description of the subject population subgroup to which this recommendation applies (e.g., all enrolled subjects, subjects in a specific age cohort, subjects with a particular comorbidity). Supports targeted safety actions.',
    `argus_safety_case_number` STRING COMMENT 'Case number assigned in Oracle Argus Safety to the safety case or aggregate safety report associated with this DSMB/DMC recommendation. Enables traceability between the recommendation and the underlying pharmacovigilance case management record.',
    `benefit_risk_summary` STRING COMMENT 'Concise summary of the DSMB/DMC benefit-risk assessment that underpins the recommendation, capturing the committees evaluation of the investigational products benefit profile relative to observed safety risks at the time of review.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this DSMB recommendation record was first captured in the data platform. Supports ALCOA+ data integrity requirements and audit trail compliance.',
    `dissenting_opinion` STRING COMMENT 'Narrative capturing any dissenting opinion(s) from DSMB/DMC members who did not agree with the majority recommendation. Documented for regulatory transparency and governance purposes when vote_outcome is split or majority.',
    `follow_up_review_date` DATE COMMENT 'Target date for the follow-up DSMB/DMC review meeting required to assess the outcome of actions taken in response to this recommendation. Populated when follow_up_review_required is True.',
    `follow_up_review_required` BOOLEAN COMMENT 'Indicates whether this recommendation requires a follow-up DSMB/DMC review meeting to assess implementation effectiveness or monitor evolving safety data. Drives scheduling of unscheduled interim reviews.',
    `implementation_date` DATE COMMENT 'Date on which the sponsor implemented the actions required by the DSMB/DMC recommendation (e.g., protocol amendment effective date, dose modification start date, study suspension date). Critical for regulatory compliance tracking.',
    `implementation_deadline` DATE COMMENT 'Regulatory or charter-mandated deadline by which the sponsor must implement the DSMB/DMC recommendation. Supports compliance monitoring and escalation workflows.',
    `informed_consent_update_required` BOOLEAN COMMENT 'Indicates whether this DSMB/DMC recommendation necessitates an update to the Informed Consent Form (ICF) to reflect new safety information. Triggers re-consent workflow in Clinpal eConsent system.',
    `irb_iec_notification_date` DATE COMMENT 'Date on which the IRB/IEC was formally notified of this DSMB/DMC recommendation. Required for audit trail and compliance verification against ICH E6(R2) and applicable regulations.',
    `irb_iec_notification_required` BOOLEAN COMMENT 'Indicates whether this DSMB/DMC recommendation requires notification to the Institutional Review Board (IRB) or Independent Ethics Committee (IEC) overseeing the study. Required for significant safety findings and protocol changes.',
    `is_current_version` BOOLEAN COMMENT 'Boolean flag indicating whether this record represents the current active version of the recommendation. Set to False for superseded or amended versions retained for audit trail purposes.',
    `issue_date` DATE COMMENT 'Calendar date on which the DSMB/DMC formally issued this recommendation to the sponsor following the safety review meeting. This is the principal real-world business event date for the recommendation lifecycle.',
    `protocol_amendment_required` BOOLEAN COMMENT 'Indicates whether this DSMB/DMC recommendation requires a formal protocol amendment to be submitted to regulatory authorities and IRB/IEC for approval before implementation.',
    `rationale` STRING COMMENT 'Detailed narrative explanation of the scientific, clinical, and safety evidence basis for the DSMB/DMC recommendation. Includes reference to interim efficacy data, safety data, benefit-risk assessment, and any stopping rules triggered. Required for regulatory submissions and CSR.',
    `recommendation_number` STRING COMMENT 'Externally-known alphanumeric identifier assigned to this recommendation, typically formatted as a sequential reference within the study (e.g., REC-2024-001). Used for regulatory correspondence, sponsor communications, and TMF filing.',
    `recommendation_status` STRING COMMENT 'Current lifecycle state of the DSMB/DMC recommendation from initial issuance through sponsor acceptance or rejection and final closure. Drives workflow routing in Oracle Argus Safety and Oracle Siebel CTMS. [ENUM-REF-CANDIDATE: draft|issued|under_review|accepted|rejected|superseded|closed — 7 candidates stripped; promote to reference product]',
    `recommendation_type` STRING COMMENT 'Formal classification of the DSMB/DMC recommendation issued following the safety review. Drives sponsor response obligations and regulatory notification requirements. [ENUM-REF-CANDIDATE: continue_unchanged|protocol_amendment_required|dose_modification|study_suspension|early_termination|other — promote to reference product]. Valid values are `continue_unchanged|protocol_amendment_required|dose_modification|study_suspension|early_termination|other`',
    `recommendation_version` STRING COMMENT 'Version number of this recommendation record, incremented when the recommendation is amended or superseded. Supports version control and audit trail requirements under 21 CFR Part 11 and ALCOA+ principles.',
    `regulatory_agencies_notified` STRING COMMENT 'Comma-separated list of health authority agencies notified of this recommendation (e.g., FDA, EMA, MHRA, PMDA, TGA, Health Canada). Supports multi-jurisdictional regulatory compliance tracking.',
    `regulatory_notification_date` DATE COMMENT 'Actual date on which the sponsor submitted the required regulatory notification to health authorities regarding this DSMB/DMC recommendation. Used to verify compliance with expedited reporting timelines.',
    `regulatory_notification_deadline` DATE COMMENT 'Regulatory deadline by which the sponsor must notify health authorities of this DSMB/DMC recommendation and any resulting study actions. Typically 7 or 15 calendar days depending on jurisdiction and recommendation type.',
    `regulatory_notification_required` BOOLEAN COMMENT 'Indicates whether this DSMB/DMC recommendation triggers a mandatory regulatory notification obligation to health authorities (e.g., FDA, EMA, MHRA). True for recommendations involving study suspension, early termination, or significant safety findings.',
    `review_type` STRING COMMENT 'Classification of the DSMB/DMC review that generated this recommendation, distinguishing between planned interim analyses, unscheduled safety reviews triggered by emerging signals, annual reviews, and final study reviews.. Valid values are `scheduled_interim|unscheduled_interim|annual|final|ad_hoc`',
    `source_system` STRING COMMENT 'Name of the operational system of record from which this DSMB recommendation record was sourced or ingested into the Silver Layer lakehouse. Supports data lineage and reconciliation.. Valid values are `Oracle Argus Safety|Oracle Siebel CTMS|Veeva Vault|Manual Entry`',
    `sponsor_response` STRING COMMENT 'Formal response of the study sponsor to the DSMB/DMC recommendation, indicating whether the recommendation has been accepted, rejected, or partially accepted. Drives implementation and regulatory notification workflows.. Valid values are `accepted|rejected|partially_accepted|under_review|pending`',
    `sponsor_response_date` DATE COMMENT 'Date on which the sponsor formally communicated their response (acceptance, rejection, or partial acceptance) to the DSMB/DMC recommendation. Used to calculate response timeliness against regulatory and charter obligations.',
    `sponsor_response_rationale` STRING COMMENT 'Narrative explanation provided by the sponsor for their response to the DSMB/DMC recommendation, particularly required when the recommendation is rejected or only partially accepted. Documented in the TMF.',
    `stopping_rule_description` STRING COMMENT 'Description of the specific pre-specified stopping rule that was triggered, including the boundary type (efficacy, futility, safety), the statistical threshold, and the observed test statistic or safety metric that crossed the boundary.',
    `stopping_rule_triggered` BOOLEAN COMMENT 'Indicates whether a pre-specified stopping rule defined in the Statistical Analysis Plan (SAP) or DSMB charter was formally triggered as the basis for this recommendation. True when a boundary (efficacy, futility, or safety) was crossed.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to this DSMB recommendation record. Required for change tracking, audit trail, and data lineage in the Silver Layer lakehouse.',
    `vote_outcome` STRING COMMENT 'Outcome of the DSMB/DMC committee vote that produced this recommendation, indicating whether the decision was unanimous, by majority, or resulted in a split vote. Relevant for regulatory transparency and committee governance documentation.. Valid values are `unanimous|majority|split|no_vote_required`',
    CONSTRAINT pk_dsmb_recommendation PRIMARY KEY(`dsmb_recommendation_id`)
) COMMENT 'Transactional record for formal DSMB/DMC recommendations issued following a safety review meeting. Captures recommendation type (continue unchanged, protocol amendment required, dose modification, study suspension, early termination), rationale, sponsor response, implementation date, and regulatory notification requirement. Each DSMB review may produce one or more recommendations.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`reporting_obligation` (
    `reporting_obligation_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory reporting obligation record in the safety_reporting_obligation reference master.',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: EU safety reporting obligations are tied to specific CTAs under EudraCT/CTIS. Linking to clinical_trial_authorization replaces denormalized eudract_number and ctis_number and enables CTA-level safety ',
    `compliance_sop_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_sop. Business justification: Each regulatory reporting obligation (7-day, 15-day SUSAR, DSUR) is governed by a specific compliance SOP defining the process. reporting_obligation has document_sop_id pointing to document domain but',
    `health_authority_id` BIGINT COMMENT 'Foreign key linking to regulatory.health_authority. Business justification: Safety reporting obligations are defined per health authority (FDA 7/15-day rules, EMA rules). Linking to health_authority normalizes the agency reference, replaces denormalized agency_name, and enabl',
    `imp_master_id` BIGINT COMMENT 'Foreign key linking to supply.imp_master. Business justification: Safety reporting obligations are defined per IMP per regulatory authority (IND, IMPD, CTA). safety_reporting_obligation.investigational_product_name is denormalized; FK to imp_master enables automated',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: Safety reporting obligations are tied to specific IND applications (IND number is on the obligation). Linking to ind_application replaces the denormalized ind_number and enables IND-level safety repor',
    `investigational_product_id` BIGINT COMMENT 'Foreign key linking to study.investigational_product. Business justification: Reporting obligations are IP-specific at the study level — different IPs in a combination study may have different reporting requirements. study.investigational_product provides the study-specific IP ',
    `protocol_id` BIGINT COMMENT 'Foreign key linking to study.protocol. Business justification: Safety reporting obligations are defined at the protocol level — the protocol version determines applicable ICH E2A/E2B rules, reporting timelines, and expectedness criteria. Regulatory operations tea',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: Each reporting obligation is anchored to a Reference Safety Information (RSI) document (e.g., IB, SmPC) filed in the TMF. The role prefix reference_safety distinguishes this from generic TMF links. ',
    `study_id` BIGINT COMMENT 'Reference to the clinical study for which this reporting obligation applies. Enables study-specific obligation configuration and deadline tracking in Oracle Argus Safety.',
    `superseded_by_obligation_reporting_obligation_id` BIGINT COMMENT 'Reference to the newer safety_reporting_obligation record that supersedes this one when regulatory requirements are updated. Enables traceability of obligation version history and ensures Oracle Argus Safety applies the current rule.',
    `agency_code` STRING COMMENT 'Code identifying the regulatory agency that is the recipient of the safety report (e.g., FDA, EMA, MHRA, PMDA, TGA, HEALTH_CANADA). Determines submission routing in Oracle Argus Safety. [ENUM-REF-CANDIDATE: FDA|EMA|MHRA|PMDA|TGA|HEALTH_CANADA|ANVISA|CDSCO|SFDA|COFEPRIS — promote to reference product]',
    `applicable_regulation` STRING COMMENT 'The specific regulatory citation governing this reporting obligation (e.g., 21 CFR 312.32, EU CTR Art. 42, ICH E2A, ICH E2F, ISO 14155 Clause 7.10). Used for regulatory correspondence, audit trails, and compliance documentation in Veeva Vault.',
    `approved_date` DATE COMMENT 'Date on which this reporting obligation configuration was formally approved by the responsible regulatory affairs or pharmacovigilance authority. Supports 21 CFR Part 11 electronic records compliance and SOP-controlled change management.',
    `argus_report_type_code` STRING COMMENT 'Oracle Argus Safety system report type code (e.g., EXP-7, EXP-15, DSUR-ANNUAL) that maps this obligation to the Argus Safety case classification and output configuration. Used for automated case routing and report generation.',
    `argus_workflow_template` STRING COMMENT 'Name or identifier of the Oracle Argus Safety workflow template configured for this reporting obligation. Maps the obligation to the automated case processing, routing, and deadline calculation workflow in Argus Safety.',
    `causality_scope` STRING COMMENT 'Defines whether this obligation applies to events assessed as related to the investigational product, unrelated, or all events regardless of causality. Drives Oracle Argus Safety auto-routing logic for expedited reports.. Valid values are `RELATED|UNRELATED|ALL`',
    `clock_day_type` STRING COMMENT 'Specifies whether the reporting clock counts calendar days or business days. Most regulatory agencies (FDA, EMA) use calendar days for expedited safety reports per ICH E2A.. Valid values are `CALENDAR|BUSINESS`',
    `clock_start_event` STRING COMMENT 'Defines the business event that starts the regulatory reporting clock (e.g., AWARENESS_DATE — day sponsor becomes aware of the event; RECEIPT_DATE — day report is received from site). Critical for automated deadline calculation in Oracle Argus Safety per ICH E2A Day 0 rules.. Valid values are `AWARENESS_DATE|RECEIPT_DATE|ONSET_DATE|STUDY_START_DATE|CALENDAR_YEAR_END`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the jurisdiction in which this reporting obligation applies (e.g., USA, GBR, DEU, JPN). Drives country-specific regulatory deadline rules in Oracle Argus Safety.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this reporting obligation record was first created in the system. Supports audit trail requirements under 21 CFR Part 11 and ALCOA+ data integrity principles.',
    `dsmb_notification_required` BOOLEAN COMMENT 'Indicates whether the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) must be notified in addition to the regulatory agency when this obligation is triggered. Drives parallel notification workflows in Oracle Argus Safety.',
    `effective_end_date` DATE COMMENT 'Date on which this reporting obligation ceases to be effective. Null for open-ended obligations. Used to manage regulatory transitions and superseded obligation versions in Oracle Argus Safety configuration.',
    `effective_start_date` DATE COMMENT 'Date from which this reporting obligation becomes effective and applicable to new safety events. Used to manage regulatory changes (e.g., transition from EudraCT to CTIS under EU CTR 536/2014) and version-controlled obligation records.',
    `escalation_alert_days` STRING COMMENT 'Number of days before the regulatory deadline at which an escalation alert is triggered in Oracle Argus Safety to notify the safety team of an approaching submission deadline. Enables proactive compliance management.',
    `event_type` STRING COMMENT 'Classification of the safety event category that triggers this reporting obligation (e.g., SUSAR_FATAL, SUSAR_NON_FATAL, SAE, IND_SAFETY_REPORT, DSUR). Drives the applicable reporting clock and submission format in Oracle Argus Safety. [ENUM-REF-CANDIDATE: SUSAR_FATAL|SUSAR_NON_FATAL|SAE|AE|IND_SAFETY_REPORT|DSUR|PSUR|CIOMS_LINE_LISTING|OTHER — promote to reference product]',
    `expectedness_scope` STRING COMMENT 'Defines whether this obligation applies to unexpected adverse reactions (not listed in the Reference Safety Information), expected reactions, or all events. Unexpected serious adverse reactions (SUSARs) trigger expedited reporting under ICH E2A.. Valid values are `UNEXPECTED|EXPECTED|ALL`',
    `fatality_scope` STRING COMMENT 'Specifies whether this obligation applies specifically to fatal events (7-day clock), non-fatal events (15-day clock), or all events regardless of outcome. Fatal SUSARs require 7-day expedited reporting under ICH E2A and 21 CFR 312.32.. Valid values are `FATAL|NON_FATAL|ALL`',
    `follow_up_clock_days` STRING COMMENT 'Number of calendar days within which a follow-up report must be submitted after new significant information becomes available following the initial expedited report. Typically 15 days per ICH E2A for follow-up SUSARs.',
    `follow_up_report_required` BOOLEAN COMMENT 'Indicates whether a follow-up report must be submitted after the initial expedited report when additional information becomes available. Follow-up reports are required under ICH E2A when the initial report was incomplete.',
    `grace_period_hours` STRING COMMENT 'Number of hours of grace period allowed beyond the regulatory deadline before a compliance breach is flagged in Oracle Argus Safety. Accounts for weekends, public holidays, and system downtime. Typically 0 for strict regulatory deadlines.',
    `investigator_notification_required` BOOLEAN COMMENT 'Indicates whether all Principal Investigators (PIs) participating in the study must be notified of the safety finding when this obligation is triggered. Drives investigator notification letter generation in Oracle Argus Safety.',
    `irb_iec_notification_required` BOOLEAN COMMENT 'Indicates whether the Institutional Review Board (IRB) or Independent Ethics Committee (IEC) must be notified when this reporting obligation is triggered. Drives parallel IRB/IEC notification workflows in Oracle Argus Safety.',
    `obligation_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this reporting obligation rule (e.g., SUSAR-FATAL-7D-FDA, SAE-15D-EMA). Used as the business key in Oracle Argus Safety deadline configuration and compliance dashboards.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `obligation_name` STRING COMMENT 'Human-readable name describing the reporting obligation (e.g., SUSAR Fatal 7-Day Expedited Report to FDA, Annual Development Safety Update Report to EMA). Used in compliance monitoring dashboards and regulatory correspondence.',
    `obligation_status` STRING COMMENT 'Current lifecycle status of this reporting obligation record (ACTIVE — currently enforced; INACTIVE — no longer applicable; SUPERSEDED — replaced by a newer version; DRAFT — under review). Controls whether Oracle Argus Safety applies this obligation to new cases.. Valid values are `ACTIVE|INACTIVE|SUPERSEDED|DRAFT`',
    `periodic_report_frequency` STRING COMMENT 'Frequency at which periodic safety reports (e.g., DSUR, PSUR) must be submitted under this obligation. Applicable only when reporting_category is PERIODIC or ANNUAL. Drives scheduled report generation in Oracle Argus Safety.. Valid values are `ANNUAL|SEMI_ANNUAL|QUARTERLY|NOT_APPLICABLE`',
    `regulatory_basis_description` STRING COMMENT 'Narrative description of the regulatory basis and rationale for this reporting obligation, including relevant guideline sections, agency guidance documents, and any country-specific deviations from ICH standards. Supports regulatory audit and inspection readiness.',
    `reporting_category` STRING COMMENT 'Indicates whether this obligation requires expedited (immediate) reporting or periodic/annual reporting. Expedited applies to SUSARs and fatal SAEs; periodic applies to DSURs and PSURs. Drives workflow prioritization in Oracle Argus Safety.. Valid values are `EXPEDITED|PERIODIC|ANNUAL`',
    `reporting_clock_days` STRING COMMENT 'Number of calendar days from the clock start event within which the safety report must be submitted to the regulatory agency (e.g., 7 for fatal SUSARs, 15 for non-fatal SUSARs and SAEs, 30 for IND annual reports). Drives automated deadline calculation in Oracle Argus Safety.',
    `seriousness_scope` STRING COMMENT 'Defines whether this obligation applies to serious adverse events (SAEs), non-serious adverse events, or all events. Serious events meeting ICH E2A criteria trigger expedited reporting obligations.. Valid values are `SERIOUS|NON_SERIOUS|ALL`',
    `sponsor_protocol_number` STRING COMMENT 'Sponsor-assigned protocol number for the clinical study associated with this reporting obligation. Used to cross-reference obligations to the study protocol in Oracle Argus Safety and Veeva Vault eTMF.',
    `submission_format` STRING COMMENT 'Required electronic or paper format for the safety report submission (e.g., E2B_R3 for ICH-compliant electronic submissions via EudraVigilance/FDA FAERS, MEDWATCH_3500A for FDA paper/electronic, CIOMS_I for international expedited reports). Drives Oracle Argus Safety output configuration. [ENUM-REF-CANDIDATE: E2B_R3|E2B_R2|MEDWATCH_3500A|CIOMS_I|DSUR|PSUR|NARRATIVE|CTD_MODULE_5|OTHER — promote to reference product]',
    `submission_gateway` STRING COMMENT 'Electronic gateway or portal through which the safety report is transmitted to the regulatory agency (e.g., EUDRAVIGILANCE for EMA, FDA_FAERS for FDA). Drives Oracle Argus Safety transmission routing configuration. [ENUM-REF-CANDIDATE: EUDRAVIGILANCE|FDA_FAERS|MHRA_YELLOW_CARD|PMDA_GATEWAY|TGA_DATABASE|HEALTH_CANADA_MHPD|OTHER — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this reporting obligation record was last modified. Supports audit trail requirements under 21 CFR Part 11 and ALCOA+ data integrity principles for regulatory-grade data management.',
    `version_number` STRING COMMENT 'Sequential version number of this reporting obligation record, incremented when regulatory requirements change (e.g., new ICH guideline, updated agency regulation). Supports version-controlled obligation management and audit trail in Veeva Vault.',
    CONSTRAINT pk_reporting_obligation PRIMARY KEY(`reporting_obligation_id`)
) COMMENT 'Reference master defining regulatory reporting timelines and obligations for each study-country-agency combination. Captures event type (SUSAR fatal, SUSAR non-fatal, SAE, annual DSUR, IND safety report), reporting clock duration (7-day, 15-day, 30-day, annual), applicable regulation (21 CFR 312.32, EU CTR Art. 42, ICH E2A), agency recipient, submission format (E2B R3, MedWatch 3500A, CIOMS I), and whether expedited or periodic reporting applies. Drives automated deadline calculation in Oracle Argus Safety and enables compliance monitoring dashboards.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`expedited_report_deadline` (
    `expedited_report_deadline_id` BIGINT COMMENT 'Unique surrogate identifier for each expedited safety report deadline tracking record in the Silver Layer lakehouse.',
    `adverse_event_id` BIGINT COMMENT 'Reference to the parent adverse event or serious adverse event record for which this expedited report deadline is being tracked.',
    `arm_id` BIGINT COMMENT 'Foreign key linking to study.arm. Business justification: Expedited safety reports (7/15-day) submitted to health authorities must identify the treatment arm. Regulatory operations teams track arm-level expedited report compliance; arm attribution is require',
    `capa_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_capa. Business justification: Missed expedited reporting deadlines are GCP deviations that mandatorily trigger CAPAs in pharmacovigilance quality systems. Linking the deadline record to the resulting CAPA enables root cause tracki',
    `causality_assessment_id` BIGINT COMMENT 'Foreign key linking to safety.causality_assessment. Business justification: The causality assessment determines whether expedited reporting is required (expedited_report_required flag on causality_assessment). The expedited_report_deadline has a causality_assessment denormali',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: EU expedited report deadlines are tracked per CTA under EudraCT/CTIS. Linking to clinical_trial_authorization replaces the denormalized eudract_number and enables CTA-level expedited reporting deadlin',
    `dispensing_record_id` BIGINT COMMENT 'Foreign key linking to supply.dispensing_record. Business justification: Expedited reporting clock calculation requires the dispensing date as the product exposure reference point. The dispensing_record provides the authoritative dispensing timestamp needed to validate rep',
    `enrollment_id` BIGINT COMMENT 'Foreign key linking to subject.enrollment. Business justification: Expedited reporting clock-start and applicable timelines depend on the subjects enrollment context (IMP, arm, protocol version) to determine which reporting obligations apply. Pharmacovigilance opera',
    `health_authority_id` BIGINT COMMENT 'Foreign key linking to regulatory.health_authority. Business justification: Expedited report deadlines are defined per regulatory agency (FDA 7-day, EMA 15-day). Linking to health_authority normalizes the agency reference and enables deadline tracking by regulatory framework,',
    `icsr_id` BIGINT COMMENT 'Foreign key linking to safety.icsr. Business justification: Each expedited report deadline record tracks the submission deadline for a specific ICSR. expedited_report_deadline has icsr_number as a STRING reference which should be normalized to a proper FK. Add',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: Expedited report deadlines are tracked per IND application per FDA requirements. Linking to ind_application replaces the denormalized ind_number and enables IND-level expedited reporting deadline comp',
    `protocol_id` BIGINT COMMENT 'Foreign key linking to study.protocol. Business justification: Expedited reporting deadlines are determined by protocol-defined obligations and the protocol version in effect at AE onset. The protocol version determines expectedness (listed vs. unlisted) which dr',
    `reporting_obligation_id` BIGINT COMMENT 'Foreign key linking to safety.safety_reporting_obligation. Business justification: Each expedited report deadline is calculated based on a specific regulatory reporting obligation (e.g., 7-day or 15-day rule for a specific agency). safety_reporting_obligation defines the clock_start',
    `safety_report_submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.safety_report_submission. Business justification: The expedited_report_deadline tracks whether the safety_report_submission was filed on time. This is the core compliance link between deadline management and actual submission. A clinical research exp',
    `serious_adverse_event_id` BIGINT COMMENT 'Foreign key linking to safety.serious_adverse_event. Business justification: Expedited report deadlines are calculated for SAEs that meet expedited reporting criteria. The expedited_report_deadline has adverse_event_id but not serious_adverse_event_id. A direct FK to serious_a',
    `study_id` BIGINT COMMENT 'Reference to the clinical study under which the adverse event and associated expedited report were generated.',
    `subject_visit_data_id` BIGINT COMMENT 'Foreign key linking to data.subject_visit_data. Business justification: Expedited reporting deadlines are triggered by data captured in subject visit eCRF records (e.g., SAE onset date). Data managers and safety teams need to trace the triggering visit data record for dea',
    `susar_id` BIGINT COMMENT 'Foreign key linking to safety.susar. Business justification: SUSARs have strict 7-day (fatal/life-threatening) and 15-day expedited reporting deadlines under ICH E2A and EU CTR. The expedited_report_deadline table tracks these deadlines but has no direct FK to ',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: Expedited safety reports submitted to health authorities must be filed in the TMF as essential documents. Linking each deadline record to its filed TMF document enables inspection-ready tracking of su',
    `trial_subject_id` BIGINT COMMENT 'Reference to the clinical trial subject (patient) who experienced the adverse event requiring expedited reporting.',
    `applicable_deadline_date` DATE COMMENT 'The operative deadline date for this specific expedited report submission, reflecting the applicable_deadline_days (7 or 15) from the awareness_date. This is the primary compliance target date for monitoring and alerting.',
    `applicable_deadline_days` STRING COMMENT 'The number of calendar days within which the expedited report must be submitted to the applicable regulatory agency (typically 7 or 15 days). Determined by the seriousness, expectedness, and causality of the adverse event per ICH E2A.',
    `argus_case_number` STRING COMMENT 'The unique case identifier assigned by Oracle Argus Safety for the Individual Case Safety Report (ICSR) associated with this deadline record. Used to cross-reference the source safety system.',
    `argus_workflow_status` STRING COMMENT 'The current workflow processing status of the ICSR case within Oracle Argus Safety, reflecting the internal case processing lifecycle from initial data entry through medical review, QC, approval, and submission.. Valid values are `open|medical_review|qc_review|approved|submitted|closed`',
    `awareness_date` DATE COMMENT 'The date on which the sponsor or CRO first became aware of the adverse event meeting expedited reporting criteria. This is the regulatory clock start date (Day 0) from which all reporting deadlines are calculated, per ICH E2A.',
    `causality_assessment` STRING COMMENT 'The investigators or sponsors assessment of the causal relationship between the investigational product and the adverse event. Causality is a key determinant of SUSAR classification and expedited reporting obligations.. Valid values are `related|possibly_related|unlikely_related|unrelated|not_assessable`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp at which this expedited report deadline tracking record was first created in the system, supporting audit trail requirements under 21 CFR Part 11 and ALCOA+ principles.',
    `days_overdue` STRING COMMENT 'Number of calendar days by which the submission exceeded the applicable regulatory deadline. Positive value indicates late submission; zero or null indicates on-time or not yet due. Used for CAPA tracking and regulatory risk assessment.',
    `days_to_submission` STRING COMMENT 'The number of calendar days elapsed between the awareness_date (clock start) and the actual submission_date. Populated only after submission. Used for compliance KPI reporting and trend analysis against ICH E2A timelines.',
    `deadline_15_day` DATE COMMENT 'Calculated deadline date for 15-day expedited reporting, applicable to non-fatal/non-life-threatening unexpected SUSARs and other serious unexpected adverse reactions. Computed as awareness_date + 15 calendar days per ICH E2A.',
    `deadline_7_day` DATE COMMENT 'Calculated deadline date for 7-day expedited reporting, applicable to fatal or life-threatening unexpected SUSARs. Computed as awareness_date + 7 calendar days per ICH E2A and FDA 21 CFR Part 312.32.',
    `deadline_status` STRING COMMENT 'Current workflow status of the expedited report deadline. Pending = report not yet submitted and deadline not passed; Submitted_on_time = submitted within required days; Submitted_late = submitted after deadline; Overdue = deadline passed without submission; Waived = regulatory waiver granted; Not_applicable = reporting exemption applies.. Valid values are `pending|submitted_on_time|submitted_late|overdue|waived|not_applicable`',
    `delay_reason_code` STRING COMMENT 'Coded reason explaining why the expedited report was submitted after the applicable regulatory deadline. Required for CAPA documentation and regulatory inspection readiness. [ENUM-REF-CANDIDATE: incomplete_clinical_info|pending_causality_assessment|medical_review_delay|translation_required|system_outage|sponsor_approval_delay|other — promote to reference product]',
    `delay_reason_description` STRING COMMENT 'Free-text narrative describing the specific circumstances that caused the expedited report to be submitted after the regulatory deadline. Supports CAPA documentation and regulatory inspection responses.',
    `dsmb_notification_date` DATE COMMENT 'The date on which the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) was formally notified of this expedited safety report.',
    `dsmb_notified` BOOLEAN COMMENT 'Indicates whether the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) was notified of this expedited safety report. Required for studies with an active DSMB/DMC per the study protocol.',
    `follow_up_due_date` DATE COMMENT 'The target date by which a follow-up expedited safety report must be submitted to the regulatory agency with updated case information. Applicable when follow_up_required is True.',
    `follow_up_required` BOOLEAN COMMENT 'Indicates whether a follow-up expedited safety report is required to provide additional or updated information to the regulatory agency after the initial submission, per ICH E2A guidance.',
    `investigator_notification_date` DATE COMMENT 'The date on which the Principal Investigator (PI) was notified of the SUSAR or expedited safety report submission, as required by ICH E2A and GCP guidelines. Supports site-level compliance tracking.',
    `irb_iec_notification_date` DATE COMMENT 'The date on which the Institutional Review Board (IRB) or Independent Ethics Committee (IEC) was notified of the SUSAR or expedited safety report, as required by GCP and applicable regulations.',
    `is_fatal_or_life_threatening` BOOLEAN COMMENT 'Indicates whether the adverse event is classified as fatal or life-threatening, which triggers the 7-day expedited reporting requirement rather than the standard 15-day timeline per ICH E2A.',
    `is_on_time` BOOLEAN COMMENT 'Indicates whether the expedited safety report was submitted on or before the applicable regulatory deadline. True = submitted within the required timeframe; False = submitted late or not yet submitted past deadline. Core compliance KPI.',
    `is_unexpected` BOOLEAN COMMENT 'Indicates whether the adverse event is unexpected (not consistent with the Investigator Brochure or current labeling), which is a key criterion for SUSAR classification and expedited reporting obligations.',
    `regulatory_agency` STRING COMMENT 'The regulatory authority to which the expedited safety report must be submitted (e.g., FDA, EMA, MHRA, PMDA, TGA, Health Canada). Determines the applicable reporting timeline and format requirements. [ENUM-REF-CANDIDATE: FDA|EMA|MHRA|PMDA|TGA|Health_Canada|ANVISA|Other — promote to reference product]',
    `report_category` STRING COMMENT 'Indicates whether this deadline record pertains to an initial expedited report submission, a follow-up report with updated information, or a final report closing the case.. Valid values are `initial|follow_up|final`',
    `report_type` STRING COMMENT 'Classification of the expedited safety report type. SAE = Serious Adverse Event report; SUSAR = Suspected Unexpected Serious Adverse Reaction; USADE = Unexpected Serious Adverse Device Effect; IND_Safety = IND Safety Report; BLA_Safety = Biologics License Application Safety Report.. Valid values are `SAE|SUSAR|USADE|IND_Safety|BLA_Safety`',
    `reporting_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the jurisdiction in which the expedited report must be filed. Drives country-specific regulatory timeline requirements.. Valid values are `^[A-Z]{3}$`',
    `sponsor_notification_date` DATE COMMENT 'The date on which the sponsor was formally notified of the adverse event by the investigator or CRO. May differ from awareness_date if the CRO received information before the sponsor. Relevant for sponsor-level clock start determination.',
    `submission_date` DATE COMMENT 'The actual date on which the expedited safety report was submitted to the regulatory agency. Null if the report has not yet been submitted. Used to calculate days-to-submission and determine on-time compliance.',
    `submission_method` STRING COMMENT 'The electronic or paper-based method used to transmit the expedited safety report to the regulatory agency (e.g., eCTD via FDA ESG, E2B(R3) via EMA EVWEB, MedWatch 3500A, paper submission).. Valid values are `eCTD|E2B_R3|MedWatch|EVWEB|paper|gateway`',
    `submission_reference_number` STRING COMMENT 'The acknowledgement or tracking number returned by the regulatory agency upon receipt of the expedited safety report submission (e.g., FDA ESG acknowledgement number, EMA EVWEB submission ID). Confirms successful receipt.',
    `submission_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the expedited safety report was electronically transmitted to the regulatory agency, including timezone offset. Supports 21 CFR Part 11 audit trail requirements.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp at which this expedited report deadline tracking record was most recently modified, supporting audit trail requirements under 21 CFR Part 11 and ALCOA+ principles.',
    `waiver_granted` BOOLEAN COMMENT 'Indicates whether a formal regulatory waiver or exemption has been granted for this expedited report, allowing submission outside the standard 7- or 15-day timeline. When True, waiver_reference must be populated.',
    `waiver_reference` STRING COMMENT 'The reference number or description of the regulatory waiver or exemption granted for this expedited report submission. Populated only when waiver_granted is True.',
    CONSTRAINT pk_expedited_report_deadline PRIMARY KEY(`expedited_report_deadline_id`)
) COMMENT 'Transactional record tracking the calculated and actual submission deadlines for each expedited safety report (ICSR/SUSAR). Captures clock start date (date of first awareness), 7-day and 15-day deadline dates, actual submission date, days-to-submission, on-time flag, reason for delay if late, and regulatory agency. Enables compliance monitoring against ICH E2A and regional reporting requirements.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`dsur` (
    `dsur_id` BIGINT COMMENT 'Unique surrogate identifier for the Development Safety Update Report record in the lakehouse silver layer. Primary key for this entity.',
    `analysis_population_id` BIGINT COMMENT 'Foreign key linking to biostatistics.analysis_population. Business justification: DSUR cumulative subject exposure counts and SAE incidence rates are reported per SAP-defined analysis population (typically the safety population). Regulatory DSUR templates require population-stratif',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: DSURs in EU trials are filed under specific CTAs per EMA requirements. Linking dsur to clinical_trial_authorization replaces the denormalized cta_number and enables CTA-level DSUR compliance tracking ',
    `database_lock_event_id` BIGINT COMMENT 'Foreign key linking to biostatistics.database_lock_event. Business justification: DSUR data lock date must be traceable to the formal database lock event for regulatory audit trail. ICH E2F requires DSURs to specify the data lock point; linking to database_lock_event provides the f',
    `dsmb_review_id` BIGINT COMMENT 'Foreign key linking to safety.dsmb_review. Business justification: A DSUR (Development Safety Update Report) references the DSMB review conducted during the reporting period. dsur has dsmb_review_conducted (BOOLEAN) and dsmb_recommendation (STRING) but no FK to the d',
    `health_authority_id` BIGINT COMMENT 'Foreign key linking to regulatory.health_authority. Business justification: DSURs are submitted to specific primary health authorities. Linking to health_authority normalizes the primary_health_authority field and enables DSUR submission tracking by authority, supporting annu',
    `imp_master_id` BIGINT COMMENT 'Foreign key linking to supply.imp_master. Business justification: DSUR is fundamentally organized around the investigational product per ICH E2F. dsur.investigational_product_name and investigational_product_code are denormalized; FK to imp_master enables automated ',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: DSURs are filed under specific IND applications as part of IND annual reporting requirements. Linking dsur to ind_application replaces the denormalized ind_number and enables IND-level DSUR compliance',
    `interim_analysis_id` BIGINT COMMENT 'Foreign key linking to biostatistics.interim_analysis. Business justification: A DSUR reporting period may coincide with or incorporate an interim analysis data cut. Subject exposure counts and SAE summaries in the DSUR must reconcile with the interim analysis dataset. Linking d',
    `investigational_product_id` BIGINT COMMENT 'Foreign key linking to study.investigational_product. Business justification: DSURs are filed per investigational product per study per ICH E2F. The study-level IP record contains the IND/IMPD reference, development phase, and formulation details required for DSUR content. Dist',
    `monitoring_plan_id` BIGINT COMMENT 'Foreign key linking to monitoring.monitoring_plan. Business justification: DSURs (Development Safety Update Reports) must include a summary of monitoring activities and approach during the reporting period per ICH E2F. The DSUR references the monitoring plan to document the ',
    `protocol_id` BIGINT COMMENT 'Foreign key linking to study.protocol. Business justification: DSURs reference the protocol version(s) in effect during the reporting period per ICH E2F Section 6. Protocol amendments during the DSUR period must be documented; linking dsur to protocol enables tra',
    `reconciliation_id` BIGINT COMMENT 'Foreign key linking to data.reconciliation. Business justification: DSURs require formal data reconciliation of SAE counts and subject exposure figures before submission. The reconciliation record documents the data quality sign-off underpinning the DSUR; this link is',
    `regulatory_binder_id` BIGINT COMMENT 'Foreign key linking to document.regulatory_binder. Business justification: DSURs are submitted to health authorities and included in regulatory binders (IND annual reports, CTA annual safety reports). Regulatory affairs teams need to link each DSUR record to its submission b',
    `regulatory_protocol_amendment_id` BIGINT COMMENT 'Foreign key linking to regulatory.regulatory_protocol_amendment. Business justification: DSURs must document protocol amendments made during the reporting period. The DSUR references the regulatory_protocol_amendment to report safety-related protocol changes to health authorities. A clini',
    `reporting_obligation_id` BIGINT COMMENT 'Foreign key linking to safety.reporting_obligation. Business justification: DSURs are submitted to fulfill specific regulatory reporting obligations (ICH E2F, EU CTD Module 1.8.3). The reporting_obligation table defines the regulatory basis, submission frequency, and health a',
    `safety_report_submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.safety_report_submission. Business justification: DSURs are periodic safety reports filed as regulatory safety report submissions. Linking the internal DSUR record to its regulatory submission record enables submission status tracking, due date compl',
    `sap_id` BIGINT COMMENT 'Foreign key linking to biostatistics.sap. Business justification: The DSUR is a periodic regulatory safety report whose content — analysis populations, data cut alignment, subject exposure counts — must be consistent with the SAP. ICH E2F guidance requires DSUR to a',
    `sdtm_dataset_id` BIGINT COMMENT 'Foreign key linking to data.sdtm_dataset. Business justification: DSURs are compiled from SDTM datasets (AE, exposure domains). ICH E2F requires traceability from the DSUR to the source data; this link enables data managers and safety teams to identify the exact SDT',
    `signal_evaluation_id` BIGINT COMMENT 'Foreign key linking to safety.signal_evaluation. Business justification: DSURs include a mandatory section on safety signals identified and evaluated during the reporting period (ICH E2F Section 9). The dsur has new_safety_signal_identified boolean but no FK to the specifi',
    `study_id` BIGINT COMMENT 'Foreign key linking to study.study_study. Business justification: DSUR (Development Safety Update Report) is a mandatory annual periodic safety report filed per study per IND/CTA. Every DSUR must reference the study it covers — this is a fundamental ICH E2F regulato',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: DSURs are filed as formal regulatory submissions (eCTD sequences). Linking the DSUR to its regulatory submission record enables dossier traceability, submission timeline tracking, and agency receipt c',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: DSURs (Development Safety Update Reports) are periodic safety reports required by ICH E2F and are essential TMF documents. The link enables TMF completeness tracking and inspection readiness verificat',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time at which this DSUR was formally approved by the sponsors qualified medical officer or pharmacovigilance responsible person, as recorded in the document management system.',
    `argus_periodic_report_reference` STRING COMMENT 'The internal report identifier assigned by Oracle Argus Safety periodic reporting module, used to trace this DSUR back to its source system record.',
    `benefit_risk_conclusion` STRING COMMENT 'The sponsors overall benefit-risk conclusion for the investigational product based on the cumulative safety data reviewed in this DSUR, as required by ICH E2F.. Valid values are `favorable|unfavorable|inconclusive|under_review`',
    `benefit_risk_summary` STRING COMMENT 'Narrative text summarizing the sponsors benefit-risk assessment for the reporting period, including key safety findings, emerging signals, and overall conclusions as documented in the DSUR.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this DSUR record was first created in the system, providing the audit trail creation anchor per ALCOA+ data integrity principles.',
    `cumulative_sae_count` STRING COMMENT 'Total number of serious adverse events (SAEs) reported for the investigational product from program inception through the end of the reporting period, as captured in Oracle Argus Safety.',
    `cumulative_subject_exposure_count` STRING COMMENT 'Total number of subjects exposed to the investigational product from the inception of the development program through the end of the reporting period, representing the cumulative safety exposure denominator.',
    `cumulative_subject_exposure_days` BIGINT COMMENT 'Total patient-days of exposure to the investigational product accumulated across all studies from program inception through the reporting period end date, used as the denominator for incidence rate calculations.',
    `cumulative_susar_count` STRING COMMENT 'Total number of SUSARs (Suspected Unexpected Serious Adverse Reactions) reported from program inception through the reporting period end date, a key regulatory safety metric.',
    `data_lock_date` DATE COMMENT 'The database lock date on which safety data was frozen for inclusion in this DSUR. No new safety data is incorporated after this date for the current reporting period.',
    `development_phase` STRING COMMENT 'The clinical development phase of the investigational product at the time of this DSUR (e.g., Phase I, Phase II, Phase III), which contextualizes the safety data and benefit-risk assessment.. Valid values are `Phase I|Phase II|Phase III|Phase IV|Phase I/II|Phase II/III`',
    `dibd` DATE COMMENT 'The Development International Birth Date — the date of first approval of a Clinical Trial Application (CTA) or equivalent in any country, used as the anchor date for annual DSUR reporting cycles.',
    `dsmb_review_conducted` BOOLEAN COMMENT 'Indicates whether a Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) review was conducted during the reporting period, with findings incorporated into this DSUR.',
    `fatal_sae_count` STRING COMMENT 'Number of serious adverse events with a fatal outcome reported during the reporting period, a critical safety metric for benefit-risk assessment and DSMB/DMC review.',
    `health_authority_acknowledgement_date` DATE COMMENT 'The date on which the health authority formally acknowledged receipt of the DSUR submission, used for regulatory compliance tracking and audit trail purposes.',
    `health_authority_query_received` BOOLEAN COMMENT 'Indicates whether the health authority issued a query or request for additional information in response to this DSUR submission, triggering a response workflow.',
    `medical_reviewer` STRING COMMENT 'Name or identifier of the qualified medical officer or pharmacovigilance physician who performed the medical review and sign-off of this DSUR prior to submission.',
    `new_safety_signal_identified` BOOLEAN COMMENT 'Indicates whether a new safety signal for the investigational product was identified during the reporting period, triggering additional signal management activities and potential regulatory notifications.',
    `ongoing_study_count` STRING COMMENT 'Number of clinical studies with the investigational product that were ongoing during the reporting period, providing context for the scope of the safety data.',
    `period_sae_count` STRING COMMENT 'Number of serious adverse events (SAEs) reported during the current annual reporting period, used to assess period-over-period safety trends.',
    `period_subject_exposure_count` STRING COMMENT 'Number of subjects exposed to the investigational product during the current annual reporting period only, used to assess period-specific safety signal rates.',
    `period_susar_count` STRING COMMENT 'Number of SUSARs reported during the current annual reporting period, used for expedited reporting compliance monitoring and signal detection.',
    `reference_safety_document_type` STRING COMMENT 'Type of reference safety information document used to assess expectedness of adverse reactions in this DSUR (e.g., IB = Investigators Brochure, CCSI = Company Core Safety Information, SmPC = Summary of Product Characteristics, USPI = US Prescribing Information, RSI = Reference Safety Information).. Valid values are `IB|CCSI|SmPC|USPI|RSI`',
    `reference_safety_document_version` STRING COMMENT 'Version number or edition of the reference safety document (e.g., Investigators Brochure edition) used as the basis for expectedness assessment in this DSUR.',
    `regulatory_action_taken` STRING COMMENT 'Significant regulatory or safety action taken during the reporting period as a result of safety findings (e.g., protocol amendment, Investigators Brochure update, study suspension). [ENUM-REF-CANDIDATE: none|protocol_amendment|ibr_update|study_suspension|study_termination|rmp_update|label_update|dhcp_letter — promote to reference product]. Valid values are `none|protocol_amendment|ibr_update|study_suspension|study_termination|rmp_update`',
    `report_number` STRING COMMENT 'Externally-known sequential report number assigned to this DSUR (e.g., DSUR-2024-001), used for regulatory tracking and cross-referencing across submissions.',
    `report_status` STRING COMMENT 'Current lifecycle status of the DSUR document, tracking its progression from authoring through regulatory acceptance. [ENUM-REF-CANDIDATE: draft|under_review|approved|submitted|accepted|rejected|withdrawn — promote to reference product]',
    `report_version` STRING COMMENT 'Version number of the DSUR document (e.g., 1.0, 2.0), incremented upon amendments or corrections to a previously submitted report.. Valid values are `^[0-9]+.[0-9]+$`',
    `reporting_period_end_date` DATE COMMENT 'The last date of the annual reporting period covered by this DSUR, marking the data cut-off for safety data included in the report.',
    `reporting_period_start_date` DATE COMMENT 'The first date of the annual reporting period covered by this DSUR, typically the Development International Birth Date (DIBD) anniversary.',
    `submission_date` DATE COMMENT 'The actual date on which this DSUR was submitted to the primary health authority, used for regulatory compliance tracking and on-time submission KPI monitoring.',
    `submission_due_date` DATE COMMENT 'The regulatory deadline by which this DSUR must be submitted to health authorities, typically 60 days after the reporting period end date per ICH E2F.',
    `submission_format` STRING COMMENT 'The electronic or paper format used for the DSUR submission to health authorities (e.g., eCTD = Electronic Common Technical Document, NeeS = Non-eCTD Electronic Submission).. Valid values are `eCTD|NeeS|paper|eCTD_v4`',
    `therapeutic_area` STRING COMMENT 'The clinical therapeutic area or disease indication for which the investigational product is being developed (e.g., Oncology, Cardiology, Neurology), used for safety signal contextualization.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this DSUR record was last modified in the system, supporting audit trail and data lineage tracking per ALCOA+ principles.',
    CONSTRAINT pk_dsur PRIMARY KEY(`dsur_id`)
) COMMENT 'Development Safety Update Report (DSUR) — the annual periodic safety report submitted to health authorities summarizing cumulative safety data for an investigational product across all ongoing studies. Captures reporting period, data lock date, cumulative subject exposure, SAE line listing summary, benefit-risk conclusion, and submission dates per agency. Sourced from Oracle Argus Safety periodic reporting module.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`ctcae_grade` (
    `ctcae_grade_id` BIGINT COMMENT 'Unique surrogate identifier for each CTCAE grade definition record in the reference table. This is the primary key for the ctcae_grade product. [_canonical_skip_reason: Entity role is REFERENCE_LOOKUP — a controlled NCI-published code list of severity grades; per-role minimum categories are exempt.]',
    `meddra_term_id` BIGINT COMMENT 'Foreign key linking to safety.meddra_term. Business justification: ctcae_grade stores meddra_pt_code, meddra_pt_name, meddra_soc_code, meddra_version as strings representing the MedDRA mapping for each CTCAE grade. Adding meddra_term_id FK to the meddra_term referenc',
    `ae_term` STRING COMMENT 'The official CTCAE adverse event term name as published by NCI (e.g., Atrial fibrillation, Nausea, Peripheral neuropathy). This is the standardized clinical term used to classify and report adverse events across all clinical trials. Corresponds to the AETERM or AEDECOD field in CDISC SDTM AE domain and is the primary human-readable label for this grading record.',
    `applicable_population` STRING COMMENT 'Specifies the patient population for which this CTCAE grade definition is applicable (e.g., All, Pediatric, Adult, Oncology). Some CTCAE terms and grade criteria differ by population (e.g., pediatric-specific grading criteria). Used to filter applicable grade definitions when assigning severity in studies with specific population constraints.. Valid values are `Pediatric|Adult|Geriatric|All|Oncology|Non-Oncology`',
    `cdisc_codelist_code` STRING COMMENT 'The CDISC controlled terminology codelist code associated with this CTCAE grade entry (e.g., the AETOXGR codelist code). Enables direct mapping to CDISC SDTM submission datasets and ADaM analysis datasets produced in SAS Drug Development. Required for eCTD regulatory submissions to FDA, EMA, and PMDA.. Valid values are `^Cd{4,7}$`',
    `change_summary` STRING COMMENT 'A brief description of what changed in this grade definition relative to the prior CTCAE version (e.g., Grade 3 criteria updated to include specific lab threshold, New term added in v5.0, Grade description clarified). Supports data managers and regulatory affairs teams in assessing the impact of CTCAE version upgrades on ongoing studies and in preparing regulatory submission change justifications.',
    `clinical_criteria` STRING COMMENT 'Supplementary clinical criteria, laboratory thresholds, or objective measurement parameters that define the boundary conditions for assigning this specific grade to the AE term (e.g., specific lab value ranges, vital sign thresholds, functional impairment descriptors). Distinct from the grade_description in that it captures the measurable/objective criteria rather than the narrative description. Used by clinical staff for precise grade assignment and by biostatisticians for consistency validation.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this CTCAE grade reference record was first loaded into the data lakehouse Silver layer. Supports audit trail requirements under 21 CFR Part 11, ALCOA+ principles, and GDPR Article 5 data integrity obligations. Used by data management teams to track when new CTCAE version data was ingested.',
    `ctcae_code` STRING COMMENT 'Official NCI-assigned alphanumeric code uniquely identifying the CTCAE adverse event term within a given version. Used as the primary business identifier for cross-system referencing and CDISC SDTM mapping (AETOXGR domain). Enables unambiguous linkage between AE records and the reference grading criteria.. Valid values are `^[A-Z0-9_]{3,30}$`',
    `ctcae_version` STRING COMMENT 'Version number of the CTCAE publication from which this grade definition originates (e.g., v5.0, v4.03). Critical for ensuring AE severity grading is applied against the correct version mandated by the study protocol. New CTCAE versions are released by the National Cancer Institute (NCI) and may alter grade descriptions or add/remove terms.. Valid values are `^v?d+.d+(.d+)?$`',
    `effective_end_date` DATE COMMENT 'The date on which this CTCAE grade definition was superseded, retired, or replaced by a newer version (nullable for currently active records). Used in conjunction with effective_start_date to implement bi-temporal versioning of the reference table, ensuring that AE records can always be validated against the grade criteria that were in effect at the time of the adverse event.',
    `effective_start_date` DATE COMMENT 'The date from which this CTCAE grade definition became effective and available for use in clinical trial AE grading (typically the official NCI publication date of the CTCAE version). Used to determine which version of a grade definition was applicable at the time of an AE occurrence, supporting retrospective audit and regulatory inspection readiness.',
    `grade` STRING COMMENT 'Numeric severity grade (1 through 5) as defined by CTCAE. Grade 1 = Mild; Grade 2 = Moderate; Grade 3 = Severe; Grade 4 = Life-threatening or disabling; Grade 5 = Death related to AE. This is the core grading dimension of the reference table and is used to populate the AETOXGR field in CDISC SDTM submissions and to trigger SAE/SUSAR reporting workflows in Oracle Argus Safety.',
    `grade_description` STRING COMMENT 'Full verbatim clinical description of the severity grade for the specific AE term as published in the CTCAE by NCI (e.g., for Nausea Grade 2: Moderate nausea; oral intake decreased without significant weight loss, dehydration or malnutrition). This is the authoritative clinical criteria text used by investigators and CRAs to assign the correct grade during AE assessment. Stored verbatim to preserve regulatory integrity.',
    `grade_label` STRING COMMENT 'Standardized textual label corresponding to the numeric CTCAE grade (e.g., Mild for Grade 1, Moderate for Grade 2, Severe for Grade 3, Life-Threatening for Grade 4, Death for Grade 5). Provides a human-readable severity descriptor for use in clinical reports, DSMB/DMC safety narratives, and regulatory submissions without requiring a lookup of the numeric grade.. Valid values are `Mild|Moderate|Severe|Life-Threatening|Death`',
    `grading_notes` STRING COMMENT 'Additional clinical notes, caveats, or guidance provided by NCI for applying this specific grade to the AE term (e.g., Also consider Anemia, See also Cardiac disorders: Left ventricular systolic dysfunction). Captures the Also consider and Navigational Note annotations present in the CTCAE publication that guide investigators in differential grading decisions.',
    `is_active` BOOLEAN COMMENT 'Indicates whether this CTCAE grade definition record is currently active and available for use in new AE grading assignments. Set to False when a term or grade is retired, superseded by a newer CTCAE version, or deprecated. Enables version-controlled filtering so that active studies use only current, approved grading criteria while historical records remain accessible for audit.',
    `is_oncology_specific` BOOLEAN COMMENT 'Indicates whether this CTCAE adverse event term and grade definition is specific to oncology/cancer treatment contexts. CTCAE was originally developed for oncology trials; some terms are exclusively relevant to chemotherapy, radiation, or immunotherapy adverse effects. Used to filter applicable grading criteria for oncology versus non-oncology study protocols.',
    `is_serious_by_grade` BOOLEAN COMMENT 'Indicates whether this CTCAE grade level is inherently classified as a Serious Adverse Event (SAE) based on regulatory definitions (typically Grade 3 and above may trigger SAE criteria, Grade 4–5 are always serious). Used to automate SAE flagging logic in Oracle Argus Safety and EDC systems (Medidata Rave) when a grade is recorded, supporting expedited reporting timelines under ICH E2A and FDA 21 CFR 312.32.',
    `meddra_pt_code` STRING COMMENT 'The MedDRA Preferred Term (PT) code that most closely corresponds to this CTCAE adverse event term, enabling cross-coding between CTCAE and MedDRA terminologies. Used for regulatory submissions (IND, NDA, BLA, MAA) that require MedDRA coding, and for signal detection in Oracle Argus Safety. Alignment maintained per current MedDRA version used in the study.. Valid values are `^d{8}$`',
    `meddra_soc_code` STRING COMMENT 'The MedDRA System Organ Class (SOC) numeric code corresponding to the primary SOC classification of this CTCAE terms MedDRA PT cross-reference. Enables integrated safety tabulations that span both CTCAE-graded AE data and MedDRA-coded data in regulatory submissions and DSMB/DMC reports.. Valid values are `^d{8}$`',
    `meddra_version` STRING COMMENT 'Version of the MedDRA dictionary used for the cross-reference mapping between this CTCAE term and its corresponding MedDRA PT/SOC codes (e.g., 26.0, 25.1). MedDRA is updated biannually; version tracking ensures regulatory submissions reference the correct dictionary version as required by FDA, EMA, and PMDA.. Valid values are `^d{2}.d{1}$`',
    `nci_concept_code` STRING COMMENT 'The NCI Thesaurus (NCIt) concept identifier (e.g., C54767) for this CTCAE adverse event term. Provides a stable, version-independent identifier from the NCI controlled vocabulary that persists across CTCAE versions. Used for ontology-based data integration, CDISC terminology alignment, and cross-study analytics in SAS Drug Development and AI/ML safety signal detection pipelines.. Valid values are `^Cd{4,7}$`',
    `nci_publication_date` DATE COMMENT 'The official publication date of the CTCAE version from which this grade definition originates, as released by the National Cancer Institute (NCI) Cancer Therapy Evaluation Program (CTEP). Provides the authoritative reference date for regulatory submissions and audit trails, distinct from the effective_start_date which may reflect internal adoption timing.',
    `prior_version_code` STRING COMMENT 'The CTCAE term code from the immediately preceding CTCAE version that this record supersedes or corresponds to, enabling version-to-version lineage tracking. Used by data managers and biostatisticians to reconcile AE grading data collected under different CTCAE versions within the same study or across studies in integrated safety analyses.. Valid values are `^[A-Z0-9_]{3,30}$`',
    `reporting_timeline_days` STRING COMMENT 'The maximum number of calendar days within which an AE at this grade must be reported to regulatory authorities upon sponsor awareness (e.g., 7 days for fatal/life-threatening unexpected SUSARs, 15 days for other serious unexpected reactions, null for non-expedited grades). Drives automated due-date calculation in Oracle Argus Safety and regulatory_report_due_date population on the adverse_event product.',
    `requires_expedited_reporting` BOOLEAN COMMENT 'Indicates whether an AE recorded at this CTCAE grade level triggers mandatory expedited regulatory reporting obligations (e.g., 7-day or 15-day IND safety reports to FDA, EMA, PMDA). Derived from regulatory guidance but stored as a reference attribute to drive automated reporting workflow triggers in Oracle Argus Safety and CTMS. Supports compliance with FDA 21 CFR 312.32, EMA GVP Module VI, and ICH E2A timelines.',
    `sdtm_domain` STRING COMMENT 'The two-letter CDISC SDTM domain code to which this CTCAE grade reference applies (e.g., AE for Adverse Events domain). Supports SDTM dataset construction in SAS Drug Development and ensures correct domain-level mapping during regulatory submission preparation.. Valid values are `^[A-Z]{2}$`',
    `sdtm_variable` STRING COMMENT 'The CDISC SDTM variable name to which this CTCAE grade value maps in regulatory submission datasets (e.g., AETOXGR for the AE domain toxicity grade). Used by SAS Drug Development programmers and CDISC data managers to ensure correct SDTM dataset population and FDA/EMA submission compliance.. Valid values are `^[A-Z]{2,8}$`',
    `soc_code` STRING COMMENT 'NCI-assigned code for the System Organ Class (SOC) category within the CTCAE hierarchy. Enables programmatic grouping and filtering of adverse event terms by organ system for safety tabulations, DSMB/DMC reports, and regulatory submissions. Distinct from MedDRA SOC codes but may be cross-referenced.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `soc_name` STRING COMMENT 'The System Organ Class (SOC) category name as defined in the CTCAE, representing the highest-level anatomical or physiological grouping of adverse event terms (e.g., Cardiac disorders, Gastrointestinal disorders, Nervous system disorders). Aligns with MedDRA SOC hierarchy for cross-coding purposes. Used for safety signal detection and aggregate reporting by organ system.',
    `source_document_reference` STRING COMMENT 'Reference to the specific section, page, or table in the official NCI CTCAE publication document from which this grade definition was extracted (e.g., CTCAE v5.0, Section 2, Table: Cardiac Disorders, p.12). Supports regulatory inspection readiness and audit trail requirements by providing a direct link to the authoritative source document stored in Veeva Vault eTMF.',
    `source_system` STRING COMMENT 'The operational system or authoritative source from which this CTCAE grade reference record was loaded (e.g., Oracle Argus Safety where CTCAE codes are maintained, SAS Drug Development for CDISC-aligned reference data, NCI CTCAE for direct NCI publication ingestion). Supports data lineage tracking and Silver layer provenance requirements.. Valid values are `Oracle Argus Safety|SAS Drug Development|NCI CTCAE|Manual`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent update to this CTCAE grade reference record in the data lakehouse Silver layer. Tracks corrections, enrichments, or metadata updates applied after initial load. Required for audit trail completeness under 21 CFR Part 11 and ALCOA+ principles.',
    `veeva_document_reference` STRING COMMENT 'The document identifier in Veeva Vault eTMF for the official NCI CTCAE source document associated with this version. Enables direct navigation from the reference record to the controlled source document in the electronic Trial Master File, supporting audit trail completeness and regulatory inspection readiness per 21 CFR Part 11 and EU CTR 536/2014.',
    CONSTRAINT pk_ctcae_grade PRIMARY KEY(`ctcae_grade_id`)
) COMMENT 'Reference table for CTCAE (Common Terminology Criteria for Adverse Events) severity grading definitions. Captures CTCAE version, SOC category, adverse event term, grade (1–5), grade description, and clinical criteria. Used to standardize severity grading across all AE records. Infrequently updated when new CTCAE versions are released by NCI.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`meddra_term` (
    `meddra_term_id` BIGINT COMMENT 'Unique surrogate identifier for each MedDRA term record in the lakehouse silver layer. Primary key. [REFERENCE_LOOKUP role — _canonical_skip_reason: This entity is a standardized regulatory reference code list (MedDRA hierarchy) maintained by MSSO/ICH; per-role minimums for REFERENCE_LOOKUP are exempt.]',
    `argus_dict_reference` STRING COMMENT 'The internal dictionary record identifier assigned by Oracle Argus Safety when this MedDRA term is loaded into the Argus dictionary module. Enables direct cross-reference between the lakehouse silver layer and the Oracle Argus Safety system of record for adverse event coding reconciliation and audit.',
    `change_type` STRING COMMENT 'Describes the nature of the change applied to this term in the current MedDRA version: new (first introduced), modified (name or hierarchy changed), retired (removed from active use), split (one term divided into multiple), merged (multiple terms combined), or reinstated (previously retired term reactivated). Critical for managing dictionary upgrade impacts in Oracle Argus Safety.. Valid values are `new|modified|retired|split|merged|reinstated`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this MedDRA term record was first created in the lakehouse silver layer. Supports data lineage, audit trail requirements under 21 CFR Part 11, and ALCOA+ data integrity principles for the clinical data management platform.',
    `ctcae_grade_mapping` STRING COMMENT 'The CTCAE v5.0 term name that corresponds to this MedDRA PT, where a direct mapping exists. Enables cross-referencing between MedDRA coding and CTCAE severity grading used in oncology and other therapeutic area studies. Null where no CTCAE mapping exists for this term.',
    `effective_date` DATE COMMENT 'The date from which this MedDRA term is officially effective and available for use in adverse event coding and regulatory submissions, corresponding to the MSSO release date of the version in which it was introduced. Supports version-gating logic in Oracle Argus Safety and study-level coding version controls.',
    `hierarchy_level` STRING COMMENT 'The level within the five-tier MedDRA hierarchy to which this term belongs: LLT (Lowest Level Term), PT (Preferred Term), HLT (High Level Term), HLGT (High Level Group Term), or SOC (System Organ Class). Determines how the term is used in adverse event coding, CTCAE mapping, and regulatory aggregate reporting.. Valid values are `LLT|PT|HLT|HLGT|SOC`',
    `hlgt_code` STRING COMMENT 'The 8-digit MedDRA code for the High Level Group Term (HLGT) in the primary SOC path for this term. Populated for LLT, PT, HLT, and HLGT level terms to support aggregate safety analysis and regulatory tabulations at the HLGT level.. Valid values are `^[0-9]{8}$`',
    `hlgt_name` STRING COMMENT 'The official MedDRA name of the High Level Group Term (HLGT) in the primary SOC path. Denormalized for direct use in safety tabulations and signal detection analytics without requiring a hierarchy traversal.',
    `hlt_code` STRING COMMENT 'The 8-digit MedDRA code for the High Level Term (HLT) in the primary SOC path for this term. Populated for LLT, PT, and HLT level terms to support aggregate safety analysis at the HLT level in regulatory submissions and DSMB/DMC reports.. Valid values are `^[0-9]{8}$`',
    `hlt_name` STRING COMMENT 'The official MedDRA name of the High Level Term (HLT) in the primary SOC path. Denormalized for direct use in safety tabulations and signal detection analytics.',
    `introduced_version` STRING COMMENT 'The MedDRA version in which this term was first introduced into the dictionary. Supports historical analysis of term availability across study timelines and ensures correct version-gating when coding adverse events from legacy studies.. Valid values are `^[0-9]{1,2}.[0-9]$`',
    `is_llt_current` BOOLEAN COMMENT 'Applicable to LLT-level terms only. Indicates whether the LLT is a current LLT (true) — meaning it maps to a PT with the same name — or a non-current LLT (false) that maps to a PT with a different name. Current LLTs are preferred for new coding; non-current LLTs are retained for historical traceability per MSSO policy.',
    `is_primary_soc` BOOLEAN COMMENT 'Indicates whether this terms association to a System Organ Class (SOC) is the primary (true) or secondary (false) SOC linkage. MedDRA allows a PT to be linked to multiple SOCs; the primary SOC is used for regulatory aggregate safety tabulations, DSMB/DMC safety reviews, and CTCAE-aligned reporting.',
    `language_code` STRING COMMENT 'ISO 639-1/639-2 language code for the language of this term record (e.g., en for English, ja for Japanese, de for German). MedDRA is published in multiple languages; this field supports multi-language implementations required for submissions to PMDA (Japanese), EMA (EU languages), and Health Canada (French/English).. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `llt_code` STRING COMMENT 'The 8-digit MedDRA code for the Lowest Level Term (LLT). For LLT-level records this equals term_code. For higher-level terms this field is null. LLTs capture verbatim-level medical concepts and are the entry point for verbatim-to-MedDRA coding in Oracle Argus Safety and EDC systems.. Valid values are `^[0-9]{8}$`',
    `llt_name` STRING COMMENT 'The official MedDRA name of the Lowest Level Term (LLT). For LLT-level records this equals term_name. Null for higher-level terms. Used in verbatim coding workflows and auto-coding dictionaries in Oracle Argus Safety.',
    `load_date` DATE COMMENT 'The date on which this MedDRA term record was loaded into the lakehouse silver layer from the MSSO distribution files. Used to track the effective date of each biannual dictionary update and to support audit trails required under 21 CFR Part 11 and ALCOA+ data integrity principles.',
    `meddra_version` STRING COMMENT 'The biannual MedDRA release version in which this term was introduced or last updated (e.g., 27.0, 26.1). Critical for regulatory submissions requiring version-specific coding, database lock (DBL) documentation, and CDISC SDTM dataset compliance. MedDRA releases occur twice yearly (March and September).. Valid values are `^[0-9]{1,2}.[0-9]$`',
    `pt_code` STRING COMMENT 'The 8-digit MedDRA code for the Preferred Term (PT) to which this term maps. For PT-level records this equals term_code. For LLT-level records this is the parent PT code. Used as the primary coding level in Oracle Argus Safety adverse event records, CDISC SDTM (AEDECOD), and regulatory case submissions (ICH E2B).. Valid values are `^[0-9]{8}$`',
    `pt_name` STRING COMMENT 'The official MedDRA name of the Preferred Term (PT) to which this term maps. Denormalized for direct use in adverse event coding displays, safety narratives, CDISC SDTM datasets, and regulatory submissions without requiring a hierarchy join.',
    `rave_dict_entry_reference` STRING COMMENT 'The dictionary entry identifier assigned by Medidata Rave EDC when this MedDRA term is configured in the Rave coding dictionary for eCRF verbatim-to-MedDRA auto-coding. Supports reconciliation between EDC-coded adverse events and the master MedDRA reference in the lakehouse.',
    `replacement_term_code` STRING COMMENT 'The 8-digit MedDRA code of the term that replaces this term when it has been retired, split, or merged. Null for active terms and retired terms with no direct replacement. Supports automated re-coding workflows in Oracle Argus Safety during biannual MedDRA version upgrades.. Valid values are `^[0-9]{8}$`',
    `retired_version` STRING COMMENT 'The MedDRA version in which this term was retired, if applicable. Null for active terms. Used to enforce coding rules in Oracle Argus Safety and to flag terms that should not be applied to new adverse event records after the specified version.. Valid values are `^[0-9]{1,2}.[0-9]$`',
    `retirement_date` DATE COMMENT 'The date on which this MedDRA term was officially retired by MSSO, corresponding to the release date of the version in which it was retired. Null for active terms. Used to enforce coding restrictions in Oracle Argus Safety and to flag terms in legacy study datasets.',
    `smq_membership` STRING COMMENT 'Pipe-delimited list of Standardised MedDRA Query (SMQ) names to which this PT belongs. SMQs are validated, topic-focused groupings of MedDRA terms used for signal detection, aggregate safety analysis, and regulatory queries (e.g., Anaphylactic reaction, Drug-induced liver injury). Populated for PT-level terms only.',
    `smq_scope` STRING COMMENT 'Indicates whether this terms SMQ membership is classified as broad (higher sensitivity, more inclusive) or narrow (higher specificity, more restrictive) within the associated SMQ. Used to configure signal detection algorithms in Oracle Argus Safety and to define the scope of safety queries in regulatory submissions.. Valid values are `broad|narrow`',
    `soc_abbreviation` STRING COMMENT 'The standardized two-to-four letter abbreviation for the System Organ Class (SOC) as defined by MSSO (e.g., CARD for Cardiac disorders, NERV for Nervous system disorders). Used in safety tabulation headers, DSMB/DMC slide decks, and abbreviated regulatory reports.',
    `soc_code` STRING COMMENT 'The 8-digit MedDRA code for the System Organ Class (SOC) to which this term is linked (primary or secondary). Populated for all hierarchy levels to enable direct SOC-level filtering in safety tabulations, signal detection, and regulatory submissions without requiring a hierarchy traversal join.. Valid values are `^[0-9]{8}$`',
    `soc_name` STRING COMMENT 'The official MedDRA name of the System Organ Class (SOC) associated with this term. Denormalized for direct use in safety tabulations, DSMB/DMC reports, and CDISC SDTM datasets (AEBODSYS variable) without requiring a hierarchy join.',
    `source_file_name` STRING COMMENT 'The name of the MSSO-distributed MedDRA ASCII flat file from which this term record was loaded (e.g., llt.asc, pt.asc, hlt.asc, hlgt.asc, soc.asc). Supports data lineage traceability and ETL audit for the biannual MedDRA dictionary update process in the Databricks lakehouse.',
    `term_code` STRING COMMENT 'The official 8-digit numeric MedDRA term code assigned by the Maintenance and Support Services Organization (MSSO) uniquely identifying this term within the MedDRA hierarchy. Used as the primary lookup key in Oracle Argus Safety for adverse event coding and regulatory submissions.. Valid values are `^[0-9]{8}$`',
    `term_name` STRING COMMENT 'The official MedDRA term label as published by MSSO for this term code. Represents the standardized medical concept name used in adverse event coding, regulatory submissions (IND, NDA, BLA, MAA), and safety signal detection across all five hierarchy levels.',
    `term_status` STRING COMMENT 'Indicates whether the MedDRA term is currently active and available for coding or has been retired in a subsequent MedDRA version release. Retired terms are retained for historical traceability of previously coded adverse events but must not be used for new coding in Oracle Argus Safety.. Valid values are `active|retired`',
    `term_type` STRING COMMENT 'Classifies the term as standard (fully endorsed MedDRA term) or non-standard (a term that has been superseded, split, or merged and retained for backward compatibility). Drives coding validation rules in Oracle Argus Safety and Medidata Rave auto-coding configurations.. Valid values are `standard|non-standard`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this MedDRA term record was last updated in the lakehouse silver layer, typically triggered by a biannual MedDRA version release load. Supports change tracking, audit trail requirements under 21 CFR Part 11, and ALCOA+ data integrity principles.',
    `who_art_mapping` STRING COMMENT 'The corresponding WHO Adverse Reaction Terminology (WHO-ART) preferred term code or name for this MedDRA term, where a legacy mapping exists. Supports legacy study migration and cross-dictionary reconciliation for studies coded under WHO-ART prior to MedDRA adoption.',
    CONSTRAINT pk_meddra_term PRIMARY KEY(`meddra_term_id`)
) COMMENT 'Reference master for the MedDRA (Medical Dictionary for Regulatory Activities) terminology hierarchy, storing all active terms across all five levels: LLT (Lowest Level Term), PT (Preferred Term), HLT (High Level Term), HLGT (High Level Group Term), and SOC (System Organ Class). Captures term code, term name, level, primary SOC flag, MedDRA version, and active/retired status. Updated with each biannual MedDRA release.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`review_committee` (
    `review_committee_id` BIGINT COMMENT 'Unique surrogate identifier for the safety review committee record in the lakehouse silver layer. Primary key for this entity.',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: Review committees in EU trials operate under the CTA framework. The CTA governs the committees mandate and reporting obligations in EU member states. A clinical research expert expects review committ',
    `health_authority_id` BIGINT COMMENT 'Foreign key linking to regulatory.health_authority. Business justification: Safety review committees (DSMBs) report to specific regulatory authorities per their charter. Linking to health_authority normalizes the regulatory_authority_notified field and enables governance trac',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: DSMBs/review committees are constituted under the IND protocol. The IND references the DSMB charter and governs the committees regulatory reporting obligations. A clinical research expert expects rev',
    `study_id` BIGINT COMMENT 'Foreign key linking to study.study_study. Business justification: DSMB/DMC review committees are established per study — the committee charter, membership, and meeting schedule are study-specific. Linking review_committee to study_study enables study-level committee',
    `tmf_document_id` BIGINT COMMENT 'Reference identifier of the charter document as stored in Veeva Vault eTMF. Enables direct retrieval of the governing charter for audit and regulatory inspection purposes.',
    `argus_committee_reference` STRING COMMENT 'Reference identifier for this committee as configured in Oracle Argus Safety for routing SAE/SUSAR reports and safety data packages to the committee. Enables traceability between safety case management and committee oversight.',
    `charter_approval_date` DATE COMMENT 'Date on which the current version of the committee charter was formally approved by the sponsor or designated authority. Establishes the effective date of the committees operating mandate.',
    `charter_expiry_date` DATE COMMENT 'Date on which the current charter version expires and requires renewal or amendment. Null if the charter is open-ended and tied to study completion. Used for compliance tracking in MasterControl.',
    `charter_title` STRING COMMENT 'Official title of the committees governing charter document as stored in Veeva Vault eTMF. The charter defines the committees mandate, operating procedures, decision-making authority, and confidentiality obligations.',
    `charter_version` STRING COMMENT 'Version number of the currently approved committee charter document (e.g., v1.0, v2.1). Tracks charter amendments over the committee lifecycle. Linked to the document in Veeva Vault eTMF.. Valid values are `^v?[0-9]+.[0-9]+(.[0-9]+)?$`',
    `closed_session_required` BOOLEAN COMMENT 'Indicates whether the committee charter mandates a closed/executive session restricted to independent committee members and the unblinded statistician, excluding sponsor representatives. Required for independent DMC/DSMB per FDA guidance.',
    `committee_code` STRING COMMENT 'Short alphanumeric business identifier for the committee used in Oracle Siebel CTMS and Oracle Argus Safety for cross-system referencing and reporting (e.g., DMC-2024-001, SRC-ONCOLOGY-01).. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `committee_name` STRING COMMENT 'Official full name of the safety review committee as defined in its charter (e.g., Study XYZ Data Monitoring Committee, Global Safety Review Committee). Used as the primary human-readable identifier across CTMS and safety systems.',
    `committee_status` STRING COMMENT 'Current lifecycle status of the committee. active = operational and conducting reviews; inactive = temporarily not meeting; dissolved = formally disbanded at study close-out; suspended = operations halted pending investigation; pending_charter = established but charter not yet approved.. Valid values are `active|inactive|dissolved|suspended|pending_charter`',
    `committee_type` STRING COMMENT 'Classification of the committee by its regulatory and operational role. SRC = internal Safety Review Committee; DSMB = Data Safety Monitoring Board; DMC = Data Monitoring Committee; IDMC = Independent Data Monitoring Committee; ISMC = Independent Safety Monitoring Committee. Drives applicable regulatory obligations and independence requirements.. Valid values are `SRC|DSMB|DMC|IDMC|ISMC`',
    `confidentiality_agreement_required` BOOLEAN COMMENT 'Indicates whether all committee members are required to execute a confidentiality agreement prior to receiving unblinded study data. Mandatory for independent committees with unblinded access per GCP and sponsor SOPs.',
    `conflict_of_interest_policy` STRING COMMENT 'Identifies the conflict-of-interest (COI) policy framework governing committee member disclosures and recusal procedures. sponsor_policy = governed by sponsors COI SOP; charter_defined = COI rules embedded in the committee charter; external_standard = governed by an external professional body standard.. Valid values are `sponsor_policy|charter_defined|none|external_standard`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this committee record was first created in the lakehouse silver layer. Supports ALCOA+ data integrity principles and audit trail requirements under 21 CFR Part 11 and ICH E6(R2).',
    `ctms_committee_reference` STRING COMMENT 'Identifier for this committee record in Oracle Siebel CTMS, used for meeting scheduling, site notification workflows, and cross-system reconciliation between the CTMS and the lakehouse.',
    `dissolution_date` DATE COMMENT 'Date on which the committee was formally dissolved, typically at study close-out or database lock (DBL). Null if the committee is still active. Required for TMF completeness at study archival.',
    `establishment_date` DATE COMMENT 'Date on which the committee was formally established and constituted by the sponsor. Marks the start of the committees operational lifecycle and is recorded in the Trial Master File (TMF).',
    `governing_regulation` STRING COMMENT 'Primary regulatory framework or guideline under which the committee operates (e.g., 21 CFR Part 312, EU CTR 536/2014, ICH E6(R2), ISO 14155). Determines reporting obligations and procedural requirements. [ENUM-REF-CANDIDATE: 21_CFR_312|EU_CTR_536_2014|ICH_E6R2|ISO_14155|PMDA_GCP|TGA_GCP — promote to reference product]',
    `independent_statistician_assigned` BOOLEAN COMMENT 'Indicates whether an independent (unblinded) statistician has been formally assigned to support the committee with unblinded data analysis. Required for DSMB/DMC operations per ICH E9(R1) and FDA guidance.',
    `is_independent` BOOLEAN COMMENT 'Indicates whether the committee operates independently from the sponsor and investigators (True) or is an internal sponsor committee (False). Independence is a regulatory requirement for DMC/DSMB/IDMC roles per ICH E6(R2) and FDA guidance.',
    `last_meeting_date` DATE COMMENT 'Date of the most recently completed committee meeting. Used for monitoring meeting cadence compliance against the charter-defined frequency and for DSMB/DMC oversight tracking in Oracle Siebel CTMS.',
    `meeting_frequency` STRING COMMENT 'Scheduled frequency at which the committee convenes for safety reviews as defined in the charter. per_protocol indicates frequency is defined by study protocol milestones (e.g., after every N subjects enrolled). Drives meeting scheduling in Oracle Siebel CTMS.. Valid values are `ad_hoc|monthly|quarterly|semi_annual|annual|per_protocol`',
    `meeting_minutes_required` BOOLEAN COMMENT 'Indicates whether formal written minutes are required for each committee meeting per the charter. Minutes are a GCP requirement for DMC/DSMB meetings and must be archived in the eTMF.',
    `next_meeting_date` DATE COMMENT 'Date of the next scheduled committee meeting as planned in Oracle Siebel CTMS. Used for advance preparation of safety data packages and member notification workflows.',
    `open_session_required` BOOLEAN COMMENT 'Indicates whether the committee charter mandates an open session (attended by sponsor representatives) in addition to the closed/executive session (independent members only). Standard DMC practice per FDA guidance.',
    `outstanding_recommendations_count` STRING COMMENT 'Number of committee recommendations that have been issued but not yet formally resolved or closed by the sponsor. A non-zero value triggers escalation workflows in Oracle Siebel CTMS and MasterControl CAPA tracking.',
    `primary_therapeutic_area` STRING COMMENT 'The primary therapeutic area or disease indication for which the committee provides safety oversight (e.g., Oncology, Cardiovascular, Neurology). Used for committee expertise matching and portfolio-level safety analytics.',
    `quorum_requirement` STRING COMMENT 'Minimum number of committee members required to be present for a meeting to be valid and for decisions to be binding, as specified in the charter. Enforced during meeting scheduling and minutes review.',
    `regulatory_authority_notified` BOOLEAN COMMENT 'Indicates whether the relevant regulatory authority (e.g., FDA, EMA) has been formally notified of the committees establishment and composition, as required for certain study types and jurisdictions.',
    `reporting_authority` STRING COMMENT 'Name or role of the organizational body or individual to whom the committee formally reports its recommendations (e.g., Sponsor Medical Officer, Executive Steering Committee, IRB/IEC). Defines the escalation path for safety recommendations.',
    `safety_data_package_frequency` STRING COMMENT 'Frequency at which the unblinded safety data package is prepared and distributed to committee members prior to meetings. Governs data preparation schedules in SAS Drug Development and Oracle Argus Safety.. Valid values are `per_meeting|monthly|quarterly|ad_hoc|per_protocol`',
    `sponsor_liaison_name` STRING COMMENT 'Full name of the sponsors designated liaison or medical monitor who serves as the primary point of contact between the sponsor organization and the committee. This individual typically attends open sessions but is excluded from closed sessions.',
    `statistical_charter_included` BOOLEAN COMMENT 'Indicates whether the committee charter includes a statistical analysis plan (SAP) or statistical charter defining interim analysis rules, stopping boundaries (e.g., OBrien-Fleming, Lan-DeMets), and alpha-spending functions. Critical for DSMB/DMC oversight of adaptive trials.',
    `stopping_rules_defined` BOOLEAN COMMENT 'Indicates whether the charter defines pre-specified stopping rules for efficacy, futility, or safety that the committee is empowered to invoke. Presence of stopping rules is a key regulatory expectation for DSMB/DMC charters.',
    `tmf_section_reference` STRING COMMENT 'Reference to the TMF section or zone in Veeva Vault eTMF where committee-related documents (charter, member CVs, meeting minutes, recommendations) are filed. Aligns with the DIA Reference Model for TMF structure.',
    `total_meetings_held` STRING COMMENT 'Cumulative count of formal committee meetings held since the committees establishment. Used for lifecycle tracking, regulatory inspection readiness, and TMF completeness verification.',
    `unblinded_access` BOOLEAN COMMENT 'Indicates whether the committee has access to unblinded (treatment-arm-identified) safety and efficacy data during its reviews. Unblinded access is standard for independent DMC/DSMB; internal SRCs may operate on blinded data. Governs data preparation workflows in SAS Drug Development.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this committee record in the lakehouse silver layer. Required for change tracking, data lineage, and audit trail compliance under 21 CFR Part 11.',
    CONSTRAINT pk_review_committee PRIMARY KEY(`review_committee_id`)
) COMMENT 'Master record for internal sponsor Safety Review Committees (SRCs) and external Data Monitoring Committees (DMCs) overseeing study safety. Captures committee name, type (internal SRC, DSMB, DMC, IDMC), charter version, meeting frequency, member roster, independence status, and associated studies. Distinct from the dsmb_review entity which captures individual meeting records.';

CREATE OR REPLACE TABLE `clinical_trials_ecm`.`safety`.`communication` (
    `communication_id` BIGINT COMMENT 'Unique surrogate identifier for each formal safety communication record in the Databricks Silver Layer. Primary key for this entity.',
    `blinding_config_id` BIGINT COMMENT 'Foreign key linking to randomization.blinding_config. Business justification: Urgent safety measures and safety communications frequently trigger blinding modifications or reference the current blinding configuration (e.g., requiring blind break, updating unblinding procedures)',
    `clinical_trial_authorization_id` BIGINT COMMENT 'Foreign key linking to regulatory.clinical_trial_authorization. Business justification: Safety communications in EU trials (urgent safety measures) must be filed under the CTA. The CTA governs the notification requirements for urgent safety measures. A clinical research expert expects sa',
    `dsmb_recommendation_id` BIGINT COMMENT 'Foreign key linking to safety.dsmb_recommendation. Business justification: Safety communications are frequently issued to implement DSMB/DMC recommendations (e.g., protocol amendments, dose modifications, study suspension). The safety_communication has dsmb_dmc_notification_',
    `ethics_submission_id` BIGINT COMMENT 'Foreign key linking to compliance.ethics_submission. Business justification: Urgent safety measures and safety communications require formal ethics committee submissions per ICH E6 R2. safety_communication has irb_iec_approval_id but no FK to the ethics_submission record docum',
    `health_authority_id` BIGINT COMMENT 'Foreign key linking to regulatory.health_authority. Business justification: Safety communications are sent to specific regulatory authorities. Linking to health_authority normalizes the regulatory_authority_code field and enables tracking of safety communications by authority',
    `icsr_id` BIGINT COMMENT 'Foreign key linking to safety.icsr. Business justification: Safety communications are often issued in conjunction with ICSR submissions to notify investigators, IRBs, and health authorities. The safety_communication has susar_id → susar but no direct FK to the',
    `imp_master_id` BIGINT COMMENT 'Foreign key linking to supply.imp_master. Business justification: Safety communications (urgent safety measures, IB amendments, SUSAR notifications) are issued for specific IMPs. safety_communication.investigational_product_name is denormalized; FK to imp_master ena',
    `ind_application_id` BIGINT COMMENT 'Foreign key linking to regulatory.ind_application. Business justification: Safety communications (urgent safety measures, investigator notifications) are reported to the FDA under the IND. A clinical research expert expects safety communications to reference the governing IN',
    `investigational_site_id` BIGINT COMMENT 'Foreign key linking to site.investigational_site. Business justification: Safety communications (Dear Investigator Letters, urgent safety measures) are sent directly to investigational sites. GCP (ICH E6 4.11) requires site-level acknowledgement tracking. safety_communicati',
    `irb_iec_approval_id` BIGINT COMMENT 'Reference to the IRB/IEC approval record associated with the site receiving this communication. Used to track whether the ethics committee has been formally notified and to link acknowledgement back to the approval record.',
    `manufacture_batch_id` BIGINT COMMENT 'Foreign key linking to supply.manufacture_batch. Business justification: Urgent safety measures and Dear Investigator/Investigator letters triggered by batch-specific quality issues must reference the specific batch to enable targeted site-level holds or recalls. safety_co',
    `meddra_term_id` BIGINT COMMENT 'Foreign key linking to safety.meddra_term. Business justification: safety_communication stores meddra_pt_code, meddra_pt_name, meddra_soc_name as strings. Adding meddra_term_id FK normalizes the reference to the authoritative MedDRA dictionary. meddra_pt_name and med',
    `parent_communication_safety_communication_id` BIGINT COMMENT 'Reference to the original (initial) safety communication record when this record is a follow-up communication. Null for initial communications. Enables reconstruction of the full communication chain for a given safety event.',
    `principal_investigator_id` BIGINT COMMENT 'Foreign key linking to site.principal_investigator. Business justification: Safety communications (urgent safety measures, Dear Investigator Letters) are addressed and sent directly to the principal investigator. GCP requires PI acknowledgement tracking per communication. saf',
    `regulatory_protocol_amendment_id` BIGINT COMMENT 'Foreign key linking to regulatory.protocol_amendment. Business justification: Safety communications (urgent safety measures) frequently trigger protocol amendments (protocol_amendment_required flag on safety_communication). Linking to the resulting protocol amendment enables ur',
    `reporting_obligation_id` BIGINT COMMENT 'Foreign key linking to safety.reporting_obligation. Business justification: Safety communications are issued to fulfill specific regulatory reporting obligations (e.g., investigator notifications required under 21 CFR 312.32, IRB/IEC notifications). The reporting_obligation t',
    `signal_evaluation_id` BIGINT COMMENT 'Reference to the safety signal evaluation record that triggered this communication, where applicable. Null if triggered by a SUSAR or DSMB/DMC recommendation.',
    `site_file_id` BIGINT COMMENT 'Foreign key linking to document.site_file. Business justification: Safety communications (urgent safety measures, safety letters, investigator notifications) must be filed in site files per ICH E6 GCP. Linking safety_communication to site_file enables site-level fili',
    `study_id` BIGINT COMMENT 'Reference to the clinical study for which this safety communication was issued. Links the communication to the relevant protocol and investigational product context.',
    `study_site_id` BIGINT COMMENT 'Reference to the investigational site (Principal Investigator site) that is the primary recipient of this safety communication, where the communication is site-specific. Null for communications addressed to health authorities or broad HCP audiences.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: Urgent safety communications (Dear Investigator Letters, urgent safety measures) require regulatory submission. Linking safety_communication to its submission replaces the denormalized regulatory_subm',
    `susar_id` BIGINT COMMENT 'Reference to the SUSAR record that triggered this safety communication, where applicable. Null if the communication was triggered by a safety signal, DSMB/DMC recommendation, or other source.',
    `tmf_document_id` BIGINT COMMENT 'Foreign key linking to document.tmf_document. Business justification: Safety communications (urgent safety measures, investigator notifications for SUSARs) are essential TMF documents per ICH E6(R2) Section 8. TMF managers must file each safety communication and link it',
    `treatment_arm_id` BIGINT COMMENT 'Foreign key linking to randomization.treatment_arm. Business justification: Urgent safety measures and investigator safety communications are frequently arm-specific (e.g., dose reduction for active arm only). safety_communication has no FK to treatment_arm. Regulatory agenci',
    `acknowledgement_received_date` DATE COMMENT 'Date on which formal acknowledgement of receipt was received from the primary recipient. Null if acknowledgement has not yet been received or is not required. Used for compliance tracking and site monitoring follow-up.',
    `acknowledgement_required` BOOLEAN COMMENT 'Indicates whether formal written acknowledgement from the recipient (investigator, IRB/IEC, or health authority) is required for this safety communication. Drives acknowledgement tracking and overdue escalation workflows.',
    `acknowledgement_status` STRING COMMENT 'Current status of the acknowledgement tracking for this safety communication. PENDING: acknowledgement required but not yet received; RECEIVED: acknowledgement confirmed; OVERDUE: acknowledgement deadline passed without receipt; NOT_REQUIRED: no acknowledgement required for this communication type.. Valid values are `PENDING|RECEIVED|OVERDUE|NOT_REQUIRED`',
    `approval_date` DATE COMMENT 'Date on which the safety communication was formally approved by the authorized signatory for issuance. Distinct from issue_date; approval may precede issuance by hours or days in multi-step workflows.',
    `argus_communication_number` STRING COMMENT 'Externally-known unique reference number assigned by Oracle Argus Safety to this safety communication record. Used for cross-system traceability and regulatory audit trails.',
    `communication_status` STRING COMMENT 'Current lifecycle state of the safety communication record within the Oracle Argus Safety and Veeva Vault workflow. DRAFT: in preparation; PENDING_APPROVAL: awaiting sponsor/medical review sign-off; APPROVED: cleared for distribution; ISSUED: formally distributed to recipients; SUPERSEDED: replaced by a follow-up communication; WITHDRAWN: retracted prior to or after issuance.. Valid values are `DRAFT|PENDING_APPROVAL|APPROVED|ISSUED|SUPERSEDED|WITHDRAWN`',
    `communication_type` STRING COMMENT 'Classification of the formal safety communication. SUSAR_NOTIFICATION: expedited SUSAR report to investigators/IRBs; URGENT_SAFETY_MEASURE: immediate action to protect subjects; DHPC: Dear Healthcare Professional Communication; SAFETY_LETTER: general safety update letter; DSMB_RECOMMENDATION: communication of Data Safety Monitoring Board/Data Monitoring Committee recommendation; PROTOCOL_DEVIATION_ALERT: safety-relevant protocol deviation notice. [ENUM-REF-CANDIDATE: SUSAR_NOTIFICATION|URGENT_SAFETY_MEASURE|DHPC|SAFETY_LETTER|DSMB_RECOMMENDATION|PROTOCOL_DEVIATION_ALERT — promote to reference product]. Valid values are `SUSAR_NOTIFICATION|URGENT_SAFETY_MEASURE|DHPC|SAFETY_LETTER|DSMB_RECOMMENDATION|PROTOCOL_DEVIATION_ALERT`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this safety communication record was first created in Oracle Argus Safety or Veeva Vault. Supports ALCOA+ data integrity requirements and audit trail compliance.',
    `distribution_method` STRING COMMENT 'The channel or mechanism used to distribute this safety communication to recipients. eCTD_PORTAL: submitted via electronic Common Technical Document gateway; EMAIL: direct email distribution; POSTAL: physical mail; FAX: facsimile; CTMS_PORTAL: distributed via Oracle Siebel CTMS investigator portal; HAND_DELIVERY: in-person delivery at site.. Valid values are `ECTD_PORTAL|EMAIL|POSTAL|FAX|CTMS_PORTAL|HAND_DELIVERY`',
    `dsmb_dmc_notification_date` DATE COMMENT 'Date on which the DSMB/DMC was formally notified of the safety event. Null if dsmb_dmc_notified is False. Used for DSMB/DMC meeting preparation and safety oversight audit trails.',
    `dsmb_dmc_notified` BOOLEAN COMMENT 'Indicates whether the Data Safety Monitoring Board (DSMB) or Data Monitoring Committee (DMC) was formally notified of the safety event underlying this communication. Supports DSMB/DMC oversight tracking.',
    `follow_up_number` STRING COMMENT 'Sequential follow-up number for this communication, where 0 or null indicates the initial communication and integers ≥1 indicate subsequent follow-up communications providing updated safety information on the same triggering event.',
    `icf_update_required` BOOLEAN COMMENT 'Indicates whether this safety communication requires an update to the Informed Consent Form (ICF) to reflect new safety information. When True, re-consenting of enrolled subjects may be required per IRB/IEC direction.',
    `is_expedited_report` BOOLEAN COMMENT 'Indicates whether this safety communication constitutes an expedited regulatory report (7-day or 15-day) as defined by ICH E2A and applicable regional regulations. True = expedited report required and submitted; False = routine or non-expedited communication.',
    `issue_date` DATE COMMENT 'The calendar date on which the safety communication was formally issued and distributed to recipients. This is the principal real-world event date used for regulatory reporting clock calculations and compliance tracking.',
    `meddra_pt_code` STRING COMMENT 'MedDRA Preferred Term code for the primary adverse event or safety finding that is the subject of this communication. Enables standardized cross-study and cross-product safety signal analysis.',
    `meddra_version` STRING COMMENT 'Version of the MedDRA dictionary used for coding the safety finding in this communication. Required for regulatory submissions to ensure consistent terminology versioning.',
    `narrative` STRING COMMENT 'Full narrative text body of the safety communication, describing the safety finding, its clinical significance, recommended actions for investigators, and any required subject management steps. Sourced from Oracle Argus Safety case narrative or Veeva Vault document content.',
    `protocol_amendment_required` BOOLEAN COMMENT 'Indicates whether this safety communication necessitates a formal protocol amendment. When True, a protocol amendment workflow must be initiated in Oracle Clinical One or Veeva Vault to update the study protocol.',
    `recipient_type` STRING COMMENT 'Category of the primary recipient(s) of this safety communication. INVESTIGATOR: Principal Investigator at a clinical site; IRB_IEC: Institutional Review Board or Independent Ethics Committee; HEALTH_AUTHORITY: regulatory agency (FDA, EMA, PMDA, etc.); SPONSOR: pharmaceutical/biotech sponsor organization; DSMB_DMC: Data Safety Monitoring Board or Data Monitoring Committee; HEALTHCARE_PROFESSIONAL: broader HCP audience for DHPCs.. Valid values are `INVESTIGATOR|IRB_IEC|HEALTH_AUTHORITY|SPONSOR|DSMB_DMC|HEALTHCARE_PROFESSIONAL`',
    `recommended_action` STRING COMMENT 'Specific action(s) recommended to the recipient as a result of this safety communication, such as enhanced subject monitoring, protocol amendment implementation, informed consent update, or study suspension. Derived from the safety assessment and sponsor medical review.',
    `regulatory_deadline_date` DATE COMMENT 'The calculated deadline date by which this safety communication must be submitted to the relevant health authority, based on the reporting clock start date and applicable regulatory timeline (7-day for fatal/life-threatening SUSAR; 15-day for other serious unexpected reactions).',
    `reporting_clock_start_date` DATE COMMENT 'The date on which the regulatory reporting clock was initiated for this safety communication, typically the sponsors date of first awareness of the triggering safety event. Determines the 7-day or 15-day expedited reporting deadline.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this safety communication record was sourced for the Silver Layer. ARGUS_SAFETY: Oracle Argus Safety (primary pharmacovigilance system); VEEVA_VAULT: Veeva Vault eTMF/regulatory module; SIEBEL_CTMS: Oracle Siebel CTMS; MANUAL: manually entered record.. Valid values are `ARGUS_SAFETY|VEEVA_VAULT|SIEBEL_CTMS|MANUAL`',
    `study_suspension_required` BOOLEAN COMMENT 'Indicates whether this safety communication is associated with a full or partial suspension of the clinical study or specific study arms. When True, study suspension actions must be tracked in Oracle Siebel CTMS.',
    `subject_line` STRING COMMENT 'The formal subject or title of the safety communication document as it appears in the issued letter or notification. Used for document identification, TMF filing, and recipient reference.',
    `trigger_event_type` STRING COMMENT 'The category of safety event or business process that initiated this communication. Distinguishes whether the communication was driven by a SUSAR, a detected safety signal, a DSMB/DMC review outcome, a health authority request, a protocol amendment, or a risk minimization measure.. Valid values are `SUSAR|SAFETY_SIGNAL|DSMB_DMC_REVIEW|REGULATORY_REQUEST|PROTOCOL_AMENDMENT|RISK_MINIMIZATION`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this safety communication record. Supports audit trail requirements and change tracking per ALCOA+ principles.',
    `urgent_safety_measure_flag` BOOLEAN COMMENT 'Indicates whether this communication constitutes or accompanies an Urgent Safety Measure (USM) as defined under EU CTR 536/2014, requiring immediate protective action for trial subjects prior to formal protocol amendment approval.',
    `veeva_vault_document_reference` STRING COMMENT 'Document identifier in Veeva Vault (eTMF/regulatory submissions module) where the finalized safety communication document is archived. Enables direct retrieval from the electronic Trial Master File.',
    CONSTRAINT pk_communication PRIMARY KEY(`communication_id`)
) COMMENT 'Transactional record for formal safety communications issued to investigators, IRBs/IECs, and health authorities, including urgent safety measures, Dear Healthcare Professional Communications (DHPCs), and safety letters. Captures communication type, trigger event (SUSAR, signal, DSMB recommendation), recipient type, issue date, distribution method, and acknowledgement tracking. Sourced from Oracle Argus Safety and Veeva Vault.';

